window.ASBAB_NUZUL_CACHE["3"] = {"asbab_nuzul":{"12":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: لَمَّا أَصَابَ رَسُولُ اللهِ ﷺ قُرَيْشاً يَوْمَ بَدْرٍ وَقَدِمَ الْمَدِينَةَ جَمَعَ الْيَهُودَ فِي سُوقِ بَنِي قَيْنقَاع، فَقَالَ: « يَا مَعْشَرَ يَهُودَ، أَسْلِمُوا قَبْلَ أَنْ يُصِيبَكُمْ مِثْلُ مَا أَصَابَ قُرَيْشاً » قَالُوا: يَا مُحَمَّدُ، لَا يَغُرَّنَّكَ مِنْ نَفْسِكَ أَنَّكَ قَتَلْتَ نَفَراً مِنْ قُرَيْشٍ، كَانُوا أَغْمَاراً لَا يَعْرِفُونَ الْقِتَالَ، إِنَّكَ لَوْ قَاتَلْتَنَا لَعَرَفَتْ أَنَّا نَحْنُ النَّاسُ، وَأَنَّكَ لَمْ تَلْقَ مِثْلَنَا. فَأَنْزَلَ اللهُ عز و جل فِي ذَلِكَ { قُل لِّلَّذِينَ كَفَرُوا۟ سَتُغْلَبُونَ } إِلَى قَوْلِهِ: { فِئَةٌ تُقَـٰتِلُ فِى سَبِيلِ ٱللَّهِ } بِبَدْرٍ { وَأُخْرَىٰ كَافِرَةٌ }.","id":""},{"ar":"عن عاصم بن عمر بن قتادة رحمهم الله تعالى: أن رسول الله ﷺ لما أصاب من أهل بدر ما أصاب، ورجع إلى المدينة، جمع اليهود في سوق بني قينقاع، وقال: « يا معشر يهود، أسلموا قبل أن يصيبكم الله بما أصاب قريشاً »، فقالوا: يا محمد لا يغرنك من نفسك أن قتلت نفراً من قريش كانوا أغماراً لا يعرفون القتال، إنك والله لو قاتلتنا العرفت أنا نحن الناس وإنك لم تلق مثلنا، فأنزل الله في ذلك من قولهم { قُل لِّلَّذِينَ كَفَرُوا۟ سَتُغْلَبُونَ وَتُحْشَرُونَ إِلَىٰ جَهَنَّمَ ۚ وَبِئْسَ ٱلْمِهَادُ ﴿١٢﴾ } الي قوله { لَعِبْرَةً لِّأُو۟لِى ٱلْأَبْصَـٰرِ }.","id":""}],"23":[{"ar":"عن ابن عباس رضي الله عنهما قال: دخل رسول الله بيت المدراس على جماعة من يهود فدعاهم إلى الله، فقال له نعيم بن عمرو والحارث بن زيد: على أي دين أنت يا محمد؟ فقال: « على ملة إبراهيم ودينه »، فقالا: فإن إبراهيم كان يهودياً. فقال لهما رسول الله ﷺ: « فهلموا إلى التوراة فهي بيننا وبينكم »، فأبوا عليه، فأنزل الله عز و جل { أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًا مِّنَ ٱلْكِتَـٰبِ يُدْعَوْنَ إِلَىٰ كِتَـٰبِ ٱللَّهِ لِيَحْكُمَ بَيْنَهُمْ ثُمَّ يَتَوَلَّىٰ فَرِيقٌ مِّنْهُمْ وَهُم مُّعْرِضُونَ ﴿٢٣﴾... } إلى قوله:{... مَّا كَانُوا۟ يَفْتَرُونَ }.","id":""}],"28":[{"ar":"عن ابن عباس رضي الله عنهما قال: كان الحجّاج بن عمرو حليف كعب بن الأشرف، وابن أبي الحقيق، وقيس بن زيد، قد بطنوا بنفر من الأنصار ليفتنوهم عن دينهم، فقال رفاعة بن المنذر بن زبير، وعبد الله بن جبير، وسعد بن خيثمة لأولئك النفر: اجتنبوا هؤلاء اليهود، واحذروا لزومهم ومباطنتهم لا يفتنوكم عن دينكم، فأبى أولئك النفر إلا مباطنتهم ولزومهم، فأنزل الله عز جل { لَّا يَتَّخِذِ ٱلْمُؤْمِنُونَ ٱلْكَـٰفِرِينَ أَوْلِيَآءَ مِن دُونِ ٱلْمُؤْمِنِينَ ۖ }.","id":""}],"61":[{"ar":"عن جابر رضي الله عنه قال: قدم وفد أهل نجران على النبي ﷺ العاقب والسيد، فدعاهما إلى الإسلام، فقالا: أسلمنا قبلك، قال: « كذبتما، إن شئت أخبرتكما بما يمنعكما من الإسلام؟ » فقالا: هات أنبئنا، فقال: « حب الصليب، وشرب الخمر، وأكل لحم الخنزير »، فدعاهما إلى الملاعنة، فوعداه على أن يغادياه بالغداة، فغدا رسول الله، فأخذ بيد علي وفاطمة والحسن والحسين، ثم أرسل إليهما فأبيا أن يجيبا، فأقرا له بالخراج، فقال النبي ﷺ: « والذي بعثني بالحق لو فعلا لمطر الوادي ناراً ». قال جابر: فنزلت فيهم هذه الآية: { فَقُلْ تَعَالَوْا۟ نَدْعُ أَبْنَآءَنَا وَأَبْنَآءَكُمْ وَنِسَآءَنَا وَنِسَآءَكُمْ وَأَنفُسَنَا وَأَنفُسَكُمْ }.","id":""}],"72":[{"ar":"عن ابن عباس رضي الله عنهما في قوله: { وَقَالَت طَّآئِفَةٌ مِّنْ أَهْلِ ٱلْكِتَـٰبِ ءَامِنُوا۟ بِٱلَّذِىٓ أُنزِلَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَجْهَ ٱلنَّهَارِ } الآية: وذلك أن طائفة من اليهود قالوا: إذا لقيتم أصحاب محمد ﷺ أول النهار فآمنوا، وإذا كان آخره فصلوا صلاتكم، لعلهم يقولون هؤلاء أهل الكتاب وهم أعلم منا، لعلهم ينقلبون عن دينهم، ولا تؤمنوا إلا لمن تبع دينكم.","id":""}],"77":[{"ar":"عَنْ أَبِي وَائِلٍ رحمه الله قَالَ: قَالَ عَبْدُ اللَّهِ رضي الله عنه: مَنْ حَلَفَ عَلَى يَمِينِ يَسْتَحِقُّ بِهَا مَالاً، وَهُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْه غَضْبَانُ، فَأَنْزَلَ اللَّهُ تَصْدِيقَ { إِنَّ ٱلَّذِينَ يَشْتَرُونَ بِعَهْدِ ٱللَّهِ وَأَيْمَـٰنِهِمْ ثَمَنًا قَلِيلًا } فَقَرَأَ إِلَى { عَذَابٌ أَلِيمٌ }، ثُمَّ إِنَّ الْأَشْعَثَ بْنَ قَيْسٍ رضي الله عنه خَرَجَ إِلَيْنَا فَقَال: مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ؟ قَالَ: فَحَدَّثْنَاهُ، قَالَ: فَقَالَ: صَدَقَ، لَفِيَّ وَاللهِ، أُنْزِلَتْ، كَانَتْ بَيْنِي وَبَيْنَ رَجُلٍ خُصُومَةٌ فِي بِئْرٍ فَاخْتَصَمْنَا إِلَى رَسُولِ اللهِ ﷺ، فَقَالَ رَسُولُ اللهِ: « شَاهَدَاكَ أَوْ يَمِينُهُ ». قُلْتُ: إِنَّهُ إِذَاً يَحْلِفُ وَلَا يُبَالِي، فَقَالَ رَسُولُ اللهِ ﷺ: « مَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالاً، وَهُوَ فِيهَا فَاجِرٌ لَقِيَ اللهُ وَهُوَ عَلَيْهِ غَضْبَانُ »، فَأَنْزَلَ اللهُ تَصْدِيقَ ذَلِكَ، ثُمَّ اقْتَرَأَ هَذِهِ الْآيَةَ { إِنَّ ٱلَّذِينَ يَشْتَرُونَ بِعَهْدِ ٱللَّهِ وَأَيْمَـٰنِهِمْ ثَمَنًا قَلِيلًا } إِلَى { وَلَهُمْ عَذَابٌ أَلِيمٌ }.","id":""},{"ar":"وهناك سبب آخر للنزول: فقد جاء عن عبد الله بن أبي أوفى رضي الله تعالى عنه أن رجلاً أقام سلعة وهو في السوق، فحلف بالله لقد أعطي بها ما لم يعط ليوقع فيها رجلاً من المسلمين، فنزلت { إِنَّ ٱلَّذِينَ يَشْتَرُونَ بِعَهْدِ ٱللَّهِ وَأَيْمَـٰنِهِمْ ثَمَنًا قَلِيلًا }.","id":""}],"86":[{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: كَانَ رَجُلٌ مِنْ الْأَنْصَارِ أَسْلَمَ ثُمَّ ارْتَدَّ وَلَحِقَ بِالشَّرْكِ، ثُمَّ تَنَدَّمَ فَأَرْسَلَ إِلَى قَوْمِهِ: سَلُوا لِي رَسُولَ اللهِ ﷺ هَلْ لِي\nمِنْ تَوْبَةٍ؟ فَجَاءَ قَوْمُهُ إِلَى رَسُولِ اللهِ ﷺ فَقَالُوا: إِنَّ فُلاناً قَدْ نَدِمَ، وَإِنَّهُ أَمَرَنَا أَنْ نَسْأَلَكَ هَلْ لَهُ مِنْ تَوْبَةٍ؟ فَنَزَلَتْ { كَيْفَ يَهْدِى ٱللَّهُ قَوْمًا كَفَرُوا۟ بَعْدَ إِيمَـٰنِهِمْ } إِلَى قَوْلِهِ { غَفُورٌ رَّحِيمٌ } فَأَرْسَلَ إِلَيْهِ، فَأَسْلَمَ.","id":""}],"101":[{"ar":"عن ابن عباس رضي الله عنهما قال: كانت الأوس والخزرج في الجاهلية بينهم شر، فبينما هم يوماً جلوس، ذكروا ما بينهم حتى غضبوا، فقام بعضهم إلى بعض بالسلاح ؛ فنزلت { وَكَيْفَ تَكْفُرُونَ وَأَنتُمْ تُتْلَىٰ عَلَيْكُمْ ءَايَـٰتُ ٱللَّهِ وَفِيكُمْ رَسُولُهُۥ ۗ  } الآية كلها، والآيتان بعدها إلى { وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ إِذْ كُنتُمْ أَعْدَآءً فَأَلَّفَ بَيْنَ قُلُوبِكُمْ }.","id":""},{"ar":"عن مجاهد رحمه الله في قوله: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ } قال: كان جماع قبائل الأنصار بطنين الأوس والخزرج، وكان بينهما في الجاهلية حرب ودماء وشنآن، حتى مَنَّ الله عليهم بالإسلام وبالنبي ﷺ فأطفأ الله الحرب التي كانت بينهم وألف بينهم بالإسلام.\nقال: فبينا رجل من الأوس، ورجل من الخزرج قاعدان يتحدثان، ومعهما يهودي جالس، فلم يزل يذكرهما أيامهما، والعداوة التي كانت بينهم حتى استبَّا ثم اقتتلا.\nقال: فنادى هذا قومه، وهذا قومه، فخرجوا بالسلاح، وصف بعضهم لبعض، قال: ورسول الله ﷺ شاهد يومئذٍ بالمدينة، فجاء رسول الله ﷺ فلم يزل يمشي بينهم إلى هؤلاء، وإلى هؤلاء ليسكنهم، حتى رجعوا ووضعوا السلاح، فأنزل الله عز و جل القرآن في ذلك { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ } الي قوله { عَذَابٌ عَظِيمٌ }.","id":""}],"102":[{"ar":"عن ابن عباس رضي الله عنهما قال: كانت الأوس والخزرج في الجاهلية بينهم شر، فبينما هم يوماً جلوس، ذكروا ما بينهم حتى غضبوا، فقام بعضهم إلى بعض بالسلاح ؛ فنزلت { وَكَيْفَ تَكْفُرُونَ وَأَنتُمْ تُتْلَىٰ عَلَيْكُمْ ءَايَـٰتُ ٱللَّهِ وَفِيكُمْ رَسُولُهُۥ ۗ  } الآية كلها، والآيتان بعدها إلى { وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ إِذْ كُنتُمْ أَعْدَآءً فَأَلَّفَ بَيْنَ قُلُوبِكُمْ }.","id":""},{"ar":"عن مجاهد رحمه الله في قوله: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ } قال: كان جماع قبائل الأنصار بطنين الأوس والخزرج، وكان بينهما في الجاهلية حرب ودماء وشنآن، حتى مَنَّ الله عليهم بالإسلام وبالنبي ﷺ فأطفأ الله الحرب التي كانت بينهم وألف بينهم بالإسلام.\nقال: فبينا رجل من الأوس، ورجل من الخزرج قاعدان يتحدثان، ومعهما يهودي جالس، فلم يزل يذكرهما أيامهما، والعداوة التي كانت بينهم حتى استبَّا ثم اقتتلا.\nقال: فنادى هذا قومه، وهذا قومه، فخرجوا بالسلاح، وصف بعضهم لبعض، قال: ورسول الله ﷺ شاهد يومئذٍ بالمدينة، فجاء رسول الله ﷺ فلم يزل يمشي بينهم إلى هؤلاء، وإلى هؤلاء ليسكنهم، حتى رجعوا ووضعوا السلاح، فأنزل الله عز و جل القرآن في ذلك { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ } الي قوله { عَذَابٌ عَظِيمٌ }.","id":""}],"103":[{"ar":"عن ابن عباس رضي الله عنهما قال: كانت الأوس والخزرج في الجاهلية بينهم شر، فبينما هم يوماً جلوس، ذكروا ما بينهم حتى غضبوا، فقام بعضهم إلى بعض بالسلاح ؛ فنزلت { وَكَيْفَ تَكْفُرُونَ وَأَنتُمْ تُتْلَىٰ عَلَيْكُمْ ءَايَـٰتُ ٱللَّهِ وَفِيكُمْ رَسُولُهُۥ ۗ  } الآية كلها، والآيتان بعدها إلى { وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ إِذْ كُنتُمْ أَعْدَآءً فَأَلَّفَ بَيْنَ قُلُوبِكُمْ }.","id":""},{"ar":"عن مجاهد رحمه الله في قوله: { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ } قال: كان جماع قبائل الأنصار بطنين الأوس والخزرج، وكان بينهما في الجاهلية حرب ودماء وشنآن، حتى مَنَّ الله عليهم بالإسلام وبالنبي ﷺ فأطفأ الله الحرب التي كانت بينهم وألف بينهم بالإسلام.\nقال: فبينا رجل من الأوس، ورجل من الخزرج قاعدان يتحدثان، ومعهما يهودي جالس، فلم يزل يذكرهما أيامهما، والعداوة التي كانت بينهم حتى استبَّا ثم اقتتلا.\nقال: فنادى هذا قومه، وهذا قومه، فخرجوا بالسلاح، وصف بعضهم لبعض، قال: ورسول الله ﷺ شاهد يومئذٍ بالمدينة، فجاء رسول الله ﷺ فلم يزل يمشي بينهم إلى هؤلاء، وإلى هؤلاء ليسكنهم، حتى رجعوا ووضعوا السلاح، فأنزل الله عز و جل القرآن في ذلك { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ } الي قوله { عَذَابٌ عَظِيمٌ }.","id":""}],"113":[{"ar":"عن ابن عباس رضي الله عنهما قال: لما أسلم عبد الله بن سلام، وثعلبة بن سعية، وأسيد بن سعية، وأسد بن عبيد، ومن أسلم من يهود معهم فآمنوا\nوصدقوا ورغبوا في الإسلام، ورسخوا فيه.\nقالت أحبار يهود وأهل الكفر منهم: ما آمن بمحمد ولا تبعه إلا أشرارنا، ولو كانوا من خيارنا ما تركوا دين آبائهم وذهبوا إلى غيره، فأنزل الله عز و جل في ذلك من قولهم { لَيْسُوا۟ سَوَآءً ۗ مِّنْ أَهْلِ ٱلْكِتَـٰبِ أُمَّةٌ قَآئِمَةٌ يَتْلُونَ ءَايَـٰتِ ٱللَّهِ } إلى قوله: { وَأُو۟لَـٰٓئِكَ مِنَ ٱلصَّـٰلِحِينَ }.","id":""}],"114":[{"ar":"عن ابن عباس رضي الله عنهما قال: لما أسلم عبد الله بن سلام، وثعلبة بن سعية، وأسيد بن سعية، وأسد بن عبيد، ومن أسلم من يهود معهم فآمنوا\nوصدقوا ورغبوا في الإسلام، ورسخوا فيه.\nقالت أحبار يهود وأهل الكفر منهم: ما آمن بمحمد ولا تبعه إلا أشرارنا، ولو كانوا من خيارنا ما تركوا دين آبائهم وذهبوا إلى غيره، فأنزل الله عز و جل في ذلك من قولهم { لَيْسُوا۟ سَوَآءً ۗ مِّنْ أَهْلِ ٱلْكِتَـٰبِ أُمَّةٌ قَآئِمَةٌ يَتْلُونَ ءَايَـٰتِ ٱللَّهِ } إلى قوله: { وَأُو۟لَـٰٓئِكَ مِنَ ٱلصَّـٰلِحِينَ }.","id":""}],"115":[{"ar":"عن ابن عباس رضي الله عنهما قال: لما أسلم عبد الله بن سلام، وثعلبة بن سعية، وأسيد بن سعية، وأسد بن عبيد، ومن أسلم من يهود معهم فآمنوا\nوصدقوا ورغبوا في الإسلام، ورسخوا فيه.\nقالت أحبار يهود وأهل الكفر منهم: ما آمن بمحمد ولا تبعه إلا أشرارنا، ولو كانوا من خيارنا ما تركوا دين آبائهم وذهبوا إلى غيره، فأنزل الله عز و جل في ذلك من قولهم { لَيْسُوا۟ سَوَآءً ۗ مِّنْ أَهْلِ ٱلْكِتَـٰبِ أُمَّةٌ قَآئِمَةٌ يَتْلُونَ ءَايَـٰتِ ٱللَّهِ } إلى قوله: { وَأُو۟لَـٰٓئِكَ مِنَ ٱلصَّـٰلِحِينَ }.","id":""}],"118":[{"ar":"عن ابن عباس رضي الله عنهما قال: كان رجال من المسلمين يواصلون رجالاً من اليهود لما كان بينهم من الجوار والحلف في الجاهلية، فأنزل الله عز و جل فيهم، فنهاهم عن مباطنتهم؛ تخوف الفتنة عليهم منهم، { يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ بِطَانَةً مِّن دُونِكُمْ } إلى قوله: { وَتُؤْمِنُونَ بِٱلْكِتَـٰبِ كُلِّهِۦ }.","id":""}],"122":[{"ar":"عن جَابِرِ بْنِ عَبْدِ اللهِ رضي الله عنهما يَقُولُ: فِينَا نَزَلَتْ: { إِذْ هَمَّت طَّآئِفَتَانِ مِنكُمْ أَن تَفْشَلَا وَٱللَّهُ وَلِيُّهُمَا ۗ  }، قَالَ: نَحْنُ الطَّائِفَتَانِ: بَنُو حَارِثَةَ وَبَنُو سَلِمَةَ، وَمَا نُحِبُّ - وَقَالَ سُفْيَانُ مَرَّةً: وَمَا يَسُرُّنِي - أَنَّها لَمْ تُنْزَلْ؛ لِقَولِ اللهِ: { وَٱللَّهُ وَلِيُّهُمَا ۗ }.","id":""}],"128":[{"ar":"عَنْ أَنَسِ رضي الله عنه أَنَّ رَسُولَ اللهِ ﷺ كُسِرَتْ رَبَاعِيَتُهُ يَوْمَ أُحُدٍ، وَشُجَّ\nفِي رَأْسِهِ، فَجَعَلَ يَسْلُتُ الدَّمَ عَنْهُ، وَيَقُولُ: « كَيْفَ يُفْلِحُ قَوْمٌ شَجُّوا نَبِيَّهُمْ\nوَكَسَرُوا رَبَاعِيَتَهُ، وَهُوَ يَدْعُوهُمْ إِلَى اللهِ » فَأَنْزَلَ اللهُ قَالَ: { لَيْسَ لَكَ مِنَ ٱلْأَمْرِ شَىْءٌ } و اللفظ لمسلم.","id":""}],"152":[{"ar":"عَنِ ابْنِ مَسْعُودٍ رضي الله عنه: أَنَّ النِّسَاءَ كُنَّ يَوْمَ أُحُدٍ خَلْفَ الْمُسْلِمِينَ، يُجْهِزْنَ عَلَى جَرْحَى الْمُشْرِكِينَ، فَلَوْ حَلَفْتُ يَوْمَئِذٍ رَجَوْتُ أَنْ أَبَرَّ، إِنَّهُ لَيْسَ\nأَحَدٌ مِنَّا يُرِيدُ الدُّنْيَا، حَتَّى أَنْزَلَ اللهُ عز و جل: { مِنكُم مَّن يُرِيدُ ٱلدُّنْيَا وَمِنكُم مَّن يُرِيدُ ٱلْـَٔاخِرَةَ ۚ ثُمَّ صَرَفَكُمْ عَنْهُمْ لِيَبْتَلِيَكُمْ ۖ  } فَلَمَّا خَالَفَ أَصْحَابُ النَّبِيِّ ﷺ، وَعَصَوْا مَا أُمِرُوا بِهِ، أُفْرِدَ رَسُولُ اللهِ ﷺ فِي تِسْعَةٍ، سَبْعَةٍ مِنْ الْأَنْصَارِ، وَرَجُلَيْنِ مِنْ قُرَيْشٍ، وَهُوَ عَاشِرُهُمْ....","id":""},{"ar":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما أَنَّهُ قَالَ: مَا نَصَرَ الله�� تَبَارَكَ وَتَعَالَى فِي مَوْطِنٍ، كَمَا نَصَرَ يَوْمَ أُحد، قَالَ: فَأَنْكَرْنَا ذَلِكَ، فَقَالَ ابْنُ عَبَّاسٍ: بَيْنِي وَبَيْنَ\nمَنْ أَنْكَرَ ذَلِكَ!!! كتابُ اللهِ تَبَارَكَ وَتَعَالَى، إِنَّ اللَّه عز و جل يَقُولُ فِي يَوْمِ أُحُد: { وَلَقَدْ صَدَقَكُمُ ٱللَّهُ وَعْدَهُۥٓ إِذْ تَحُسُّونَهُم بِإِذْنِهِۦ ۖ  }.\n\nيَقُولُ ابْنُ عَبَّاسِ: وَالحَسُّ: الْقَتْلُ { حَتَّىٰٓ إِذَا فَشِلْتُمْ } إِلَى قَوْلِهِ: { وَلَقَدْ عَفَا عَنكُمْ ۗ وَٱللَّهُ ذُو فَضْلٍ عَلَى ٱلْمُؤْمِنِينَ } وَإِنَّمَا عَلَى بِهَذَا الرُّمَاةَ، وَذَلِكَ أَنَّ النَّبِيَّ ﷺ أَقَامَهُمْ فِي مَوْضِعٍ، ثم قال: « احمُوا ظُهُورَنَا، فَإِنْ رَأَيْتُمُونَا نُقْتَلُ، فَلَا تَنْصُرُونَا، وَإِنْ رَأَيْتُمُونَا قَدْ غَنِمْنَا، فَلَا تَشْرِكُونَا ».\n\nفَلَمَّا غَنِمَ النَّبِيُّ ﷺ، وَأَبَاحُوا عَسْكَرَ المُشْرِكِينَ، أَكبَّ الرُّمَاةُ جَميعاً، فَدَخَلُوا فِي العَسْكَرِ يَنْهَبُونَ، وَقَدِ الْتَقَتْ صُفُوفُ أَصْحَابِ رَسُولِ اللهِ ﷺ، فَهُمْ هَكَذَا، وَشَبَّكَ بَيْنَ أَصَابِع يَدَيْهِ، وَالْتَبَسُوا، فَلَمَّا أَخَلَّ الرُمَاةُ تِلكَ الخَلَّةَ، الَّتِي كَانُوا فِيهَا، دَخَلَتِ الخَيْلُ مِنْ ذَلِكَ المَوْضِعِ عَلَى أَصْحَابِ النَّبِيِّ ﷺ فَضَرَبَ بَعْضُهُمْ بَعْضاً، وَالْتَبَسُوا، وَقُتِلَ مِنَ الْمُسْلِمِينَ نَاسٌ كَثِيرٌ....","id":""},{"ar":"عَنِ الْبَرَاءِ بْنِ عَازِبٍ رضي الله عنهما قَالَ: جَعَلَ رَسُولُ اللهِ ﷺ عَلَى الرُّمَاةِ - وَكَانُوا خَمْسِينَ رَجُلاً - عَبْدَ اللهِ بْنَ جُبَيْرٍ يَوْمَ أُحُدٍ، وَقَالَ: « إِنْ رَأَيْتُمُ الْعَدُوَّ وَرَأَيْتُمُ الطَّيْرَ تَخْطَفْنَا فَلَا تَبْرَحُوا »، فَلَمَّا رَأَوْا الْغَنَائِمَ قَالُوا: عَلَيْكُمْ الْغَنَائِمَ، فَقَالَ عَبْدُ اللَّهِ: أَلَمْ يَقُلْ رَسُولُ اللهِ ﷺ: لَا تَبْرَحُوا؟!، قَالَ غَيْرُهُ: فَنَزَلَتْ { وَعَصَيْتُم مِّنۢ بَعْدِ مَآ أَرَىٰكُم مَّا تُحِبُّونَ ۚ }، يَقُولُ: عَصَيْتُمُ الرَّسُولَ مِنْ بَعْدِ مَا أَرَاكُمْ الْغَنَائِمَ، وَهَزِيمَةَ الْعَدُو.","id":""}],"154":[{"ar":"عن عبد الله بن الزبير رضي الله عنهما قال: قال الزبير رضي الله عنه: لقد رأيتني مع رسول الله ﷺ حين اشتد الخوف علينا، أرسل الله علينا النوم، فما منا من رجل إلا ذقنه في صدره، قال: فوالله إني لأسمع قول معتب بن قشير ما أسمعه إلا كالحلم يقول: { لَوْ كَانَ لَنَا مِنَ ٱلْأَمْرِ شَىْءٌ مَّا قُتِلْنَا هَـٰهُنَا ۗ } لقول معتب.","id":""}],"169":[{"ar":"عن جَابِرِ بْنِ عَبْدِ اللهِ رضي الله عنهما قَالَ: لَقِيَنِي رَسُولُ اللهِ ﷺ فَقَالَ لِي: « يَا جَابِرُ: مَا لِي أَرَاكَ مُنْكَسِراً » قُلْتُ: يَا رَسُولَ اللهِ، اسْتُشْهِدَ أَبِي، قُتِلَ يَوْمَ أُحُدٍ وَتَرَكَ عِيَالاً وَدَيْنَا.\nقَالَ: « أَفَلَا أُبَشِّرُكَ بِمَا لَقِيَ اللهُ بِهِ أَبَاكَ »، قَالَ: قُلْتُ: بَلَى يَا رَسُولَ اللهِ.\nقَالَ: « مَا كَلَّمَ اللَّهُ أَحَداً قَطُّ إِلَّا مِنْ وَرَاءِ حِجَابٍ، وَأَحْيَا أَبَاكَ فَكَلَّمَهُ كِفَاحاً، فَقَالَ: يَا عَبْدِي، تَمَنَّ عَلَيَّ أُعْطِكَ. قَالَ: يَا رَبِّ تُحْييني فَأُقْتَلَ فِيكَ ثَانِيَةً، قَالَ الرَّبُّ عز و جل: إِنَّهُ قَدْ سَبَقَ مِنِّي أَنَّهُمْ إِلَيْهَا لَا يُرْجَعُونَ » \nقَالَ: وَأُنْزِلَتْ هَذِهِ الْآيَةُ { وَلَا تَحْسَبَنَّ ٱلَّذِينَ قُتِلُوا۟ فِى سَبِيلِ ٱللَّهِ أَمْوَٰتَۢا ۚ }.","id":""},{"ar":"عَن ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: قَالَ رَسُولُ اللهِ ﷺ: « لَمَّا أُصِيبَ\nإِخْوَانُكُمْ بِأَحَدٍ جَعَلَ اللهُ عز و جل أَرْوَاحَهُمْ فِي أَجْوَافِ طَيْرِ خُضْرٍ، تَرِدُ أَنْهَارَ الْجَنَّةِ تَأْكُلُ مِنْ ثِمَارِهَا، وَتَأْوِي إِلَى قَنَادِيلَ مِنْ ذَهَبٍ فِي ظِلِّ الْعَرْشِ، فَلَمَّا وَجَدُوا طِيبَ مَشْرَبِهِمْ وَمَأْكَلِهِمْ وَحُسْنَ مُنْقَلَبِهِمْ قَالُوا: يَا لَيْتَ إِخْوَانَنَا يَعْلَمُونَ بِمَا صَنَعَ اللهُ لَنَا، لِئَلَّا يَزْهَدُوا فِي الْجِهَادِ، وَلَا يَنْكُلُوا عَنْ الْحَرْبِ؟ فَقَالَ اللهُ عز و جل: أَنَا أُبَلِّغُهُمْ عَنْكُمْ »، فَأَنْزَلَ اللهُ عز و جل هَؤُلَاءِ الْآيَاتِ عَلَى رَسُولِهِ { وَلَا تَحْسَبَنَّ ٱلَّذِينَ قُتِلُوا۟ فِى سَبِيلِ ٱللَّهِ أَمْوَٰتَۢا ۚ بَلْ أَحْيَآءٌ }. واللفظ لأحمد.","id":""}],"172":[{"ar":"عن ابن عباس رضي الله عنها قال: لما انصرف أبو سفيان والمشركون عن أحد وبلغوا الروحاء، قال أبو سفيان: لا محمداً قتلتم، ولا الكواعب أردفتم، شر ما صنعتم. فبلغ ذلك رسول الله ﷺ، فندب الناس فانتدبوا حتى بلغوا حمر الأسد أو بئر بني عيينة، فأنزل الله عز و جل { ٱلَّذِينَ ٱسْتَجَابُوا۟ لِلَّهِ وَٱلرَّسُولِ مِنۢ بَعْدِ مَآ أَصَابَهُمُ ٱلْقَرْحُ ۚ  }، وذلك أن أبا سفيان قال للنبي ﷺ: موعدك موسم بدر حيث قتلتم أصحابنا، فأما الجبان فرجع، وأما الشجاع فأخذ أهبة القتال والتجارة، فأتوه فلم يجدوا به أحداً، وتسوفوا، فأنزل الله جل ذكره { فَٱنقَلَبُوا۟ بِنِعْمَةٍ مِّنَ ٱللَّهِ وَفَضْلٍ لَّمْ يَمْسَسْهُمْ سُوٓءٌ }.","id":""}],"181":[{"ar":"قال سعيد بن جبير رحمه الله: عن ابن عباس رضي الله عنهما: لما نزل قوله تعالى مَن { مَّن ذَا ٱلَّذِى يُقْرِضُ ٱللَّهَ قَرْضًا حَسَنًا فَيُضَـٰعِفَهُۥ لَهُۥٓ أَضْعَافًا كَثِيرَةً ۚ } قالت اليهود: يا محمد: افتقر ربك فسأل عباده القرض؟ فأنزل { لَّقَدْ سَمِعَ ٱللَّهُ قَوْلَ ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ فَقِيرٌ وَنَحْنُ أَغْنِيَآءُ ۘ } الآية.","id":""},{"ar":"عن ابن عباس رضي الله عنهما قال: دخل أبو بكر الصديق رضي الله عنه بيت المدراس، فوجد من يهود ناساً كثيرة قد اجتمعوا على رجل منهم يقال له: فنحاص، وكان من علمائهم وأحبارهم، ومعه حبر يقال له: أشيع، فقال له أبو بكر رضي الله عنه: ويحك يا فنحاص اتق الله وأسلم، فوالله لتعلم أن محمداً رسول من عند الله قد جاءكم بالحق من عنده، تجدونه مكتوباً عندكم في التوراة والإنجيل.\nفقال فنحاص: والله يا أبا بكر ما بنا إلى الله من حاجة من فقر، وإنه إلينا لفقير، وما نتضرع إليه كما يتضرع إلينا، وإنا عنه لأغنياء، ولو كان عنا غنياً ما استقرض منا كما يزعم صاحبكم، ينهاكم عن الربا ويعطيناه، ولو كان غنياً ما أعطانا الربا. فغضب أبو بكر رضي الله عنه، فضرب وجه فنحاص ضرباً شديداً، وقال: والذي نفسي بيده لولا الذي بيننا وبينك من العهد لضربت عنقك يا عدو الله، فأكذبونا ما استطعتم إن كنتم صادقين.\nفذهب فنحاص إلى رسول الله صلى الله تعالى عليه وعلى آله وسلم فقال: يا محمد أبصر ما صنع بي صاحبك، فقال رسول الله ﷺ: « ما حملك على ما صنعت يا أبا بكر » فقال: يا رسول الله، إن عدو الله قال قولاً عظيماً، يزعم أن الله فقير وأنهم عنه أغنياء، فلما قال ذلك غضبت لله مما قال فضربت وجهه فجحد فنحاص ذلك، وقال: ما قلت ذلك، فأنزل الله فيما قال فنحاص: { لَّقَدْ سَمِعَ ٱللَّهُ قَوْلَ ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ فَقِيرٌ وَنَحْنُ أَغْنِيَآءُ ۘ } الآية.","id":""}],"186":[{"ar":"عَنْ كَعْبِ بْنِ مَالِكٍ رضي الله عنه، وَكَانَ أَحَدَ الثَّلَاثَةِ الَّذِينَ تِيبَ عَلَيْهِمْ:\nكَانَ كَعْبُ بْنُ الْأَشْرَفِ يَهْجُو النَّبِيَّ ﷺ وَيُحَرِّضُ عَلَيْهِ كُفَّارَ قُرَيْشٍ، وَكَانَ النَّبِيُّ ﷺ حِينَ قَدِمَ الْمَدِينَةَ وَأَهْلُهَا أَخْلَاطٌ: مِنْهُمْ الْمُسْلِمُونَ وَالْمُشْرِكُونَ يَعْبُدُونَ الْأَوْثَانَ، وَالْيَهُودُ، وَكَانُوا يُؤْذُونَ النَّبِيَّ ﷺ وَأَصْحَابَهُ، فَأَمَرَ اللهُ عز و جل نَبِيَّهُ بِالصَّبْرِ وَالْعَفْوِ، فَفِيهِمْ أَنْزَلَ اللهُ { وَلَتَسْمَعُنَّ مِنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ مِن قَبْلِكُمْ } الْآيَةَ، فَلَمَّا أَبَى كَعْبُ بْنُ الْأَشْرَفِ أَنْ يَنْزِعَ عَنْ أَذَى النَّبِيِّ ﷺ، أَمَرَ النَّبِيُّ ﷺ سَعْدَ بْنَ مُعَاذٍ أَنْ يَبْعَثَ رَهْطاً يَقْتُلُونَهُ، فَبَعَثَ مُحَمَّدَ بْنَ مَسْلَمَةَ، وَذَكَرَ قِصَّةَ قَتْلِهِ، فَلَمَّا قَتَلُوهُ فَزَعَتِ الْيَهُودُ وَالْمُشْرِكُونَ، فَغَدَوْا عَلَى النَّبِيِّ ﷺ فَقَالُوا: طُرِقَ صَاحِبُنَا فَقُتِلَ، فَذَكَرَ لَهُمُ النَّبِيُّ ﷺ الَّذِي كَانَ يَقُولُ، وَدَعَاهُمُ النَّبِيُّ ﷺ إِلَى أَنْ يَكْتُبَ بَيْنَهُ وَبَيْنَهُمْ كِتَاباً يَنْتَهُونَ إِلَى مَا فِيهِ، فَكَتَبَ النَّبِيُّ ﷺ بَيْنَهُ وَبَيْنَهُمْ وَبَيْنَ الْمُسْلِمِينَ عَامَّةٌ صَحِيفَةٌ.","id":""}],"188":[{"ar":"عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رضي الله عنه: أَنَّ رِجَالاً مِنْ الْمُنَافِقِينَ عَلَى عَهْدِ رَسُولِ اللَّهِ ﷺ، كَانَ إِذَا خَرَجَ رَسُولُ اللهِ ﷺ إِلَى الْغَزْوِ تَخَلَّفُوا عَنْهُ، وَفَرِحُوا بِمَقْعَدِهِمْ خِلَافَ رَسُولِ اللهِ ﷺ، فَإِذَا قَدِمَ رَسُولُ اللهِ ﷺ اعْتَذَرُوا إِلَيْهِ وَحَلَفُوا، وَأَحَبُّوا أَنْ يُحْمَدُوا بِمَا لَمْ يَفْعَلُوا، فَنَزَلَتْ { لَا تَحْسَبَنَّ ٱلَّذِينَ يَفْرَحُونَ بِمَآ أَتَوا۟ وَّيُحِبُّونَ أَن يُحْمَدُوا۟ بِمَا لَمْ يَفْعَلُوا۟ } الآية. واللفظ للبخاري.","id":""},{"ar":"وهناك سبب ثان لنزول هذه الآية: فقد جاء عَنْ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ، أَنَّ مَرْوَانَ قَالَ: اذْهَبْ يَا رَافِعُ، لِبَوَّابِهِ، إِلَى ابْنِ عَبَّاسٍ فَقُلْ: لَئِنْ كَانَ كُلُّ امْرِىءٍ مِنَّا فَرِحَ بِمَا أَتَى، وَأَحَبَّ أَنْ يُحْمَدَ بِمَا لَمْ\nيَفْعَلْ، مُعَذَّباً، لَنُعَذَّبَنَّ أَجْمَعُونَ.\nفَقَالَ ابْنُ عَبَّاسٍ: مَا لَكُمْ وَلِهَذِهِ الْآيَةِ؟ إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي أَهْلِ الْكِتَابِ، ثُمَّ تَلَا ابْنُ عَبَّاسٍ: { وَإِذْ أَخَذَ ٱللَّهُ مِيثَـٰقَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ لَتُبَيِّنُنَّهُۥ لِلنَّاسِ وَلَا تَكْتُمُونَهُۥ } هَذِهِ الْآيَةَ، وَتَلَا ابْنُ عَبَّاسٍ { لَا تَحْسَبَنَّ ٱلَّذِينَ يَفْرَحُونَ بِمَآ أَتَوا۟ وَّيُحِبُّونَ أَن يُحْمَدُوا۟ بِمَا لَمْ يَفْعَلُوا۟ }.\nوَقَالَ ابْنُ عَبَّاسٍ: سَأَلَهُمْ النَّبِيُّ ﷺ عَنْ شَيْءٍ، فَكَتَمُوهُ إِيَّاهُ، وَأَخْبَرُوهُ بِغَيْرِهِ، فَخَرَجُوا قَدْ أَرَوْهُ أَنْ قَدْ أَخْبَرُوهُ بِمَا سَأَلَهُمْ عَنْهُ، وَاسْتَحْمَدُوا بِذَلِكَ إِلَيْهِ، وَفَرِحُوا بِمَا أَتَوْا مِنْ كِتْمَانِهِمْ إِيَّاهُ مَا سَأَلَهُمْ عَنْهُ، واللفظ لمسلم.","id":""}],"195":[{"ar":"عَنْ أُمِّ سَلَمَةَ رضي الله عنها قَالَتْ: يَا رَسُولَ اللهِ، لَا أَسْمَعُ اللهَ ذَكَرَ النِّسَاءَ فِي الْهِجْرَةِ، فَأَنْزَلَ اللهُ تَعَالَى { أَنِّى لَآ أُضِيعُ عَمَلَ عَٰمِلٍ مِّنكُم مِّن ذَكَرٍ أَوْ أُنثَىٰ ۖ بَعْضُكُم مِّنۢ بَعْضٍ ۖ }. واللفظ للترمذي.","id":""}]},"mapping_ayat":{"3:1":[{"p":"Nasa'i","n":1378,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "},{"p":"Tirmidzi","n":3224,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ الْقَدَّاحِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ آلِ عِمْرَانَ{ الم اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidullah bin Abu Ziyad Al Qaddah] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Nama Allah Allah yang paling agung ada dalam kedua ayat ini, yaitu: \"Dan Tuhanmu adalah Tuhan Yang Maha Esa; tidak ada Tuhan melainkan Dia Yang Maha Pemurah lagi Maha Penyayang\", (QS. Albaqarah 163) dan permulaan Surat Ali Imran; \"Alif laam miim. Allah, tidak ada Tuhan (yang berhak disembah) melainkan Dia. Yang hidup kekal lagi terus menerus mengurus makhluk-Nya.\" (QS.Ali Imran 1-2), Abu Isa berkata; hadits ini adalah hadits hasan shahih."}],"3:2":[{"p":"Tirmidzi","n":3224,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ الْقَدَّاحِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ آلِ عِمْرَانَ{ الم اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidullah bin Abu Ziyad Al Qaddah] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Nama Allah Allah yang paling agung ada dalam kedua ayat ini, yaitu: \"Dan Tuhanmu adalah Tuhan Yang Maha Esa; tidak ada Tuhan melainkan Dia Yang Maha Pemurah lagi Maha Penyayang\", (QS. Albaqarah 163) dan permulaan Surat Ali Imran; \"Alif laam miim. Allah, tidak ada Tuhan (yang berhak disembah) melainkan Dia. Yang hidup kekal lagi terus menerus mengurus makhluk-Nya.\" (QS.Ali Imran 1-2), Abu Isa berkata; hadits ini adalah hadits hasan shahih."}],"3:3":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"3:8":[{"p":"Malik","n":158,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ أَبِي عُبَيْدٍ مَوْلَى سُلَيْمَانَ بْنِ عَبْدِ الْمَلِكِ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ قَيْسِ بْنِ الْحَارِثِ عَنْ أَبِي عَبْدِ اللَّهِ الصُّنَابِحِيِّ قَالَقَدِمْتُ الْمَدِينَةَ فِي خِلَافَةِ أَبِي بَكْرٍ الصِّدِّيقِ فَصَلَّيْتُ وَرَاءَهُ الْمَغْرِبَ فَقَرَأَ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ بِأُمِّ الْقُرْآنِ وَسُورَةٍ سُورَةٍ مِنْ قِصَارِ الْمُفَصَّلِ ثُمَّ قَامَ فِي الثَّالِثَةِ فَدَنَوْتُ مِنْهُ حَتَّى إِنَّ ثِيَابِي لَتَكَادُ أَنْ تَمَسَّ ثِيَابَهُ فَسَمِعْتُهُ قَرَأَ بِأُمِّ الْقُرْآنِ وَبِهَذِهِ الْآيَةِ{ رَبَّنَا لَا تُزِغْ قُلُوبَنَا بَعْدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِنْ لَدُنْكَ رَحْمَةً إِنَّكَ أَنْتَ الْوَهَّابُ }","trj":"Telah menceritakan kepadaku dari Malik dari [Abu 'Ubaid] mantan budak Sulaiman bin Abdul Malik, dari [Ubadah bin Nusai] dari [Qais bin Al Harits] dari [Abu Abdullah Ash Shunabihi] ia berkata; \"Aku datang ke Madinah pada masa kekhilafahan [Abu Bakar As Shiddiq] . Lalu aku shalat maghrib di belakangnya, dia membaca Ummul Qur'an pada dua rakaat pertama dan surat-surat Al Mufashshal yang pendek. Kemudian dia berdiri menuju rakaat yang ketiga, lalu aku mendekat kepadanya hingga kainku hampir menempel pakaiannya. Aku mendengar ia membaca Ummul Qur'an dan ayat ini; '(Ya Tuhan kami, janganlah Engkau jadikan hati kami condong kepada kesesatan sesudah Engkau beri petunjuk kepada kami, dan karuniakanlah kepada kami Rahmat dari sisi Engkau; Karena Engkau-lah Maha pemberi (karunia) '.\" (Qs. Ali Imran: 8) . "}],"3:17":[{"p":"Tirmidzi","n":3043,"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَعَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ وَاقْرَءُوا إِنْ شِئْتُمْ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }وَفِي الْجَنَّةِ شَجَرَةٌ يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ وَظِلٍّ مَمْدُودٍ }وَمَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ فَمَنْ زُحْزِحَ عَنْ النَّارِ وَأُدْخِلَ الْجَنَّةَ فَقَدْ فَازَ وَمَا الْحَيَاةُ الدُّنْيَا إِلَّا مَتَاعُ الْغُرُورِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Bismillahirrahmanirrahim. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami ['Abdah bin Sulaiman] serta [Abdur Rahim bin Sulaiman] dari [Muhammad bin 'Amr], ia berkata; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah berfirman: \"Aku telah mempersiapkan bagi para hambaku yang shalih, apa yang belum pernah dilihat mata, belum pernah didengar telinga, dan tidak terlintas dalam hati manusia.\" Apabila kalian kehendaki maka bacalah: \"Tak seorangpun mengetahui berbagai nikmat yang dirahasiakan bagi mereka, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan.\" (QS. Assajdah 17), Di Surga terdapat pohon yang mana seorang pengendara berjalan di bawah naungannya selama seratus tahun tidak mampu menyeberanginya. Apabila kalian menghendaki maka bacalah: \"Dan naungan yang terbentang luas\" (QS. Alwaqi'ah 30), Dan tempat cemeti di Surga lebih baik daripada dunia dan seisinya. Apabila kalian menghendaki maka bacalah: \"Barangsiapa dijauhkan dari neraka dan dimasukkan ke dalam syurga, maka sungguh ia telah beruntung. Kehidupan dunia itu tidak lain hanyalah kesenangan yang memperdayakan.\" (QS. Ali'Imran 185), Abu Isa berkata: hadits ini adalah hadits hasan shahih."}],"3:18":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"3:20":[{"p":"Muslim","n":277,"ar":"و حَدَّثَنَا حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا أَبُو عَاصِمٍ يَعْنِي مُحَمَّدَ بْنَ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ الْفَقِيرُ قَالَكُنْتُ قَدْ شَغَفَنِي رَأْيٌ مِنْ رَأْيِ الْخَوَارِجِ فَخَرَجْنَا فِي عِصَابَةٍ ذَوِي عَدَدٍ نُرِيدُ أَنْ نَحُجَّ ثُمَّ نَخْرُجَ عَلَى النَّاسِ قَالَ فَمَرَرْنَا عَلَى الْمَدِينَةِ فَإِذَا جَابِرُ بْنُ عَبْدِ اللَّهِ يُحَدِّثُ الْقَوْمَ جَالِسٌ إِلَى سَارِيَةٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِذَا هُوَ قَدْ ذَكَرَ الْجَهَنَّمِيِّينَ قَالَ فَقُلْتُ لَهُ يَا صَاحِبَ رَسُولِ اللَّهِ مَا هَذَا الَّذِي تُحَدِّثُونَ وَاللَّهُ يَقُولُ{ إِنَّكَ مَنْ تُدْخِلْ النَّارَ فَقَدْ أَخْزَيْتَهُ }وَ{ كُلَّمَا أَرَادُوا أَنْ يَخْرُجُوا مِنْهَا أُعِيدُوا فِيهَا }فَمَا هَذَا الَّذِي تَقُولُونَ قَالَ فَقَالَ أَتَقْرَأُ الْقُرْآنَ قُلْتُ نَعَمْ قَالَ فَهَلْ سَمِعْتَ بِمَقَامِ مُحَمَّدٍ عَلَيْهِ السَّلَام يَعْنِي الَّذِي يَبْعَثُهُ اللَّهُ فِيهِ قُلْتُ نَعَمْ قَالَ فَإِنَّهُ مَقَامُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَحْمُودُ الَّذِي يُخْرِجُ اللَّهُ بِهِ مَنْ يُخْرِجُ قَالَ ثُمَّ نَعَتَ وَضْعَ الصِّرَاطِ وَمَرَّ النَّاسِ عَلَيْهِ قَالَ وَأَخَافُ أَنْ لَا أَكُونَ أَحْفَظُ ذَاكَ قَالَ غَيْرَ أَنَّهُ قَدْ زَعَمَ أَنَّ قَوْمًا يَخْرُجُونَ مِنْ النَّارِ بَعْدَ أَنْ يَكُونُوا فِيهَا قَالَ يَعْنِي فَيَخْرُجُونَ كَأَنَّهُمْ عِيدَانُ السَّمَاسِمِ قَالَ فَيَدْخُلُونَ نَهَرًا مِنْ أَنْهَارِ الْجَنَّةِ فَيَغْتَسِلُونَ فِيهِ فَيَخْرُجُونَ كَأَنَّهُمْ الْقَرَاطِيسُفَرَجَعْنَا قُلْنَا وَيْحَكُمْ أَتُرَوْنَ الشَّيْخَ يَكْذِبُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَجَعْنَا فَلَا وَاللَّهِ مَا خَرَجَ مِنَّا غَيْرُ رَجُلٍ وَاحِدٍ أَوْ كَمَا قَالَ أَبُو نُعَيْمٍ","trj":"Dan telah menceritakan kepada kami [Hajjaj bin asy-Syair] telah menceritakan kepada kami [al-Fadll bin Dukain] telah menceritakan kepada kami [Abu 'Ashim] -yaitu Muhammad bin Abu Ayyub- dia berkata, telah menceritakan kepadaku [Yazid al-Faqir] dia berkata, \"Dahulu aku telah terpengaruh dengan pemikiran Khawarij, kemudian kami keluar dalam sebuah rombongan besar untuk melaksanakan haji. Ketika kami keluar dan melewati madinah, ternyata [Jabir bin Abdullah] sedang menceritakan hadits Rasulullah shallallahu 'alaihi wasallam kepada suatu kaum sambil bersandar pada sebuah tiang.\" Yazil al Faqir berkata lagi, \"Tiba-tiba dia menyebutkan al-Jahannamiyyin.\" Maka aku pun berkata kepadanya, 'Wahai sahabat Rasulullah, apa-apaan yang kau ceritakan! Padahal Allah berfirman: '(Sesungguhnya barangsiapa yang Kamu masukkan ke dalam neraka, maka sungguh kamu telah menghinakannya) ' (Qs. Ali Imran: 192), dan ayat: '(Setiap kali mereka berkeinginan untuk keluar darinya, niscaya mereka dikembalikan ke dalamnya) ' (Qs. As-Sajadah: 20). Apa yang kalian katakan ini? ' Jabir menjawab, 'Apakah kalian membaca al-Qur'an? ' Kami menjawab, 'Ya.' Jabir bertanya lagi, 'Apakah kamu mendengar kedudukan Muhammad shallallahu 'alaihi wasallam, yaitu memberikan syafa'at yang mana Allah mengutusnya di dalamnya? ' Aku menjawab, 'Ya.' Jbir lalu berkata, 'Maka itulah kedudukan Muhammad shallallahu 'alaihi wasallam yang terpuji, dengannya Allah mengeluarkan orang yang dia keluarkan (dari neraka).' Yazid berkata, 'Kemudian Jabir memperagakan peletakan shirath, dan manusia lewat di atasnya.' Kata Yazid, 'Dan aku sangat khawatir tidak selamat dari hal tersebut. Hanya saja Jabir tetap berkeyakinan bahwa sekelompok kaum pasti akan keluar dari neraka, setelah mereka tinggal beberapa lama.' Kata Jabir, 'Maksudnya mereka keluar seakan-akan tongkat arang yang hitam kelam.' Kata Jabir meneruskan, 'Lalu mereka masuki salah satu sungai surga, mereka mandi di dalamnya, mereka keluar dari sungai seakan-akan kertas (putih), dan kami pun pulang.' Kami berkata, 'Celaka kalian, apakah kalian taksir bahwa syaikh ini berdusta atas nama Rasulullah shallallahu 'alaihi wasallam!.' Kami pun kembali, demi Allah, tidak ada yang keluar dari kami melainkan hanya satu orang atau sebagaimana yang diucapkan Abu Na'im.\""}],"3:30":[{"p":"Tirmidzi","n":3043,"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَعَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ وَاقْرَءُوا إِنْ شِئْتُمْ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }وَفِي الْجَنَّةِ شَجَرَةٌ يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ وَظِلٍّ مَمْدُودٍ }وَمَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ فَمَنْ زُحْزِحَ عَنْ النَّارِ وَأُدْخِلَ الْجَنَّةَ فَقَدْ فَازَ وَمَا الْحَيَاةُ الدُّنْيَا إِلَّا مَتَاعُ الْغُرُورِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Bismillahirrahmanirrahim. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami ['Abdah bin Sulaiman] serta [Abdur Rahim bin Sulaiman] dari [Muhammad bin 'Amr], ia berkata; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah berfirman: \"Aku telah mempersiapkan bagi para hambaku yang shalih, apa yang belum pernah dilihat mata, belum pernah didengar telinga, dan tidak terlintas dalam hati manusia.\" Apabila kalian kehendaki maka bacalah: \"Tak seorangpun mengetahui berbagai nikmat yang dirahasiakan bagi mereka, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan.\" (QS. Assajdah 17), Di Surga terdapat pohon yang mana seorang pengendara berjalan di bawah naungannya selama seratus tahun tidak mampu menyeberanginya. Apabila kalian menghendaki maka bacalah: \"Dan naungan yang terbentang luas\" (QS. Alwaqi'ah 30), Dan tempat cemeti di Surga lebih baik daripada dunia dan seisinya. Apabila kalian menghendaki maka bacalah: \"Barangsiapa dijauhkan dari neraka dan dimasukkan ke dalam syurga, maka sungguh ia telah beruntung. Kehidupan dunia itu tidak lain hanyalah kesenangan yang memperdayakan.\" (QS. Ali'Imran 185), Abu Isa berkata: hadits ini adalah hadits hasan shahih."}],"3:36":[{"p":"Bukhari","n":3120,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ قَالَ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ بَنِي آدَمَ مَوْلُودٌ إِلَّا يَمَسُّهُ الشَّيْطَانُ حِينَ يُولَدُ فَيَسْتَهِلُّ صَارِخًا مِنْ مَسِّ الشَّيْطَانِ غَيْرَ مَرْيَمَ وَابْنِهَا ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ{ وَإِنِّي أُعِيذُهَا بِكَ وَذُرِّيَّتَهَا مِنْ الشَّيْطَانِ الرَّجِيمِ }","trj":"Telah bercerita kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata telah bercerita kepadaku [Sa'id bin Al Musayyab] berkata; [Abu Hurairah radliallahu 'anhu] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pun dari anak keturunan Adam yang dilahirkan kecuali dia disentuh oleh setan saat dilahirkan, maka dia akan berteriak (menangis dengan keras) karena sentuhan setan tersebut kecuali Maryam dan anaknya\". Kemudian Abu Hurairah radliallahu 'anhu membaca firman Allah Ta'ala: (\"…dan aku memohon perlindungan kepada-Mu, ya Allah untuknya (Maryam) dan untuk anak keturunannya dari setan yang terketuk\"). (QS Ali 'Imran ayat 36)."}],"3:52":[{"p":"Muslim","n":1141,"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْفَزَارِيُّ يَعْنِي مَرْوَانَ بْنَ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ حَكِيمٍ الْأَنْصَارِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }الْآيَةَ الَّتِي فِي الْبَقَرَةِ وَفِي الْآخِرَةِ مِنْهُمَا{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Fazari yaitu Marwan bin Muawiyah] dari [Utsman bin Hakim Al Anshari], katanya; telah menceritakan kepadaku [Said bin Yasar] bahwa [Ibnu Abbas] mengabarinya; bahwa dalam dua raka'at fajar, tepatnya di raka'at pertama, Rasulullah shallallahu 'alaihi wasallam membaca \"Katakanlah, kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" QS. Albaqarah 136, dan pada rakaat kedua membaca \"Kami beriman kepada Allah, dan saksikanlah bahwa kami orang muslim.\" QS. Ali Imran 52."}],"3:54":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"3:55":[{"p":"Abu Dawud","n":3889,"ar":"حَدَّثَنَا أَبُو ظَفَرٍ عَبْدُ السَّلَامِ حَدَّثَنَا جَعْفَرٌ عَنْ عَوْفٍ قَالَ سَمِعْتُ الْحَجَّاجَ يَخْطُبُ وَهُوَ يَقُولُإِنَّ مَثَلَ عُثْمَانَ عِنْدَ اللَّهِ كَمَثَلِ عِيسَى ابْنِ مَرْيَمَ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ يَقْرَؤُهَا وَيُفَسِّرُهَا{ إِذْ قَالَ اللَّهُ يَا عِيسَى إِنِّي مُتَوَفِّيكَ وَرَافِعُكَ إِلَيَّ وَمُطَهِّرُكَ مِنْ الَّذِينَ كَفَرُوا }يُشِيرُ إِلَيْنَا بِيَدِهِ وَإِلَى أَهْلِ الشَّامِ","trj":"Telah menceritakan kepada kami [Abu Zhafar Abdussalam] berkata, telah menceritakan kepada kami [Ja'far] dari [Auf] ia berkata; Aku mendengar [Al Hajjaj] berkhutbah, ia mengatakan, \"Permisalan Utsman di sisi Allah seperti Isa putra Maryam, lalu ia membaca ayat ini dan mentafsirkannya: '(Ingatlah), ketika Allah berfirman: \"Hai Isa, sesungguhnya Aku akan menyampaikan kamu kepada akhir ajalmu dan mengangkat kamu kepada-Ku serta membersihkan kamu dari orang-orang yang kafir…) ' -Qs. Ali Imran: 55- lalu dengan tangannya ia menunjuk ke arah kami dan ke arah penduduk Syam.\""}],"3:64":[{"p":"Muslim","n":3089,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَابْنُ أَبِي عُمَرَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ وَاللَّفْظُ لِابْنِ رَافِعٍ قَالَ ابْنُ رَافِعٍ وَابْنُ أَبِي عُمَرَ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ أَبَا سُفْيَانَ أَخْبَرَهُ مِنْ فِيهِ إِلَى فِيهِ قَالَانْطَلَقْتُ فِي الْمُدَّةِ الَّتِي كَانَتْ بَيْنِي وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَبَيْنَا أَنَا بِالشَّأْمِ إِذْ جِيءَ بِكِتَابٍ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هِرَقْلَ يَعْنِي عَظِيمَ الرُّومِ قَالَ وَكَانَ دَحْيَةُ الْكَلْبِيُّ جَاءَ بِهِ فَدَفَعَهُ إِلَى عَظِيمِ بُصْرَى فَدَفَعَهُ عَظِيمُ بُصْرَى إِلَى هِرَقْلَ فَقَالَ هِرَقْلُ هَلْ هَاهُنَا أَحَدٌ مِنْ قَوْمِ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ قَالُوا نَعَمْ قَالَ فَدُعِيتُ فِي نَفَرٍ مِنْ قُرَيْشٍ فَدَخَلْنَا عَلَى هِرَقْلَ فَأَجْلَسَنَا بَيْنَ يَدَيْهِ فَقَالَ أَيُّكُمْ أَقْرَبُ نَسَبًا مِنْ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَقَالَ أَبُو سُفْيَانَ فَقُلْتُ أَنَا فَأَجْلَسُونِي بَيْنَ يَدَيْهِ وَأَجْلَسُوا أَصْحَابِي خَلْفِي ثُمَّ دَعَا بِتَرْجُمَانِهِ فَقَالَ لَهُ قُلْ لَهُمْ إِنِّي سَائِلٌ هَذَا عَنْ الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَإِنْ كَذَبَنِي فَكَذِّبُوهُ قَالَ فَقَالَ أَبُو سُفْيَانَ وَايْمُ اللَّهِ لَوْلَا مَخَافَةُ أَنْ يُؤْثَرَ عَلَيَّ الْكَذِبُ لَكَذَبْتُ ثُمَّ قَالَ لِتَرْجُمَانِهِ سَلْهُ كَيْفَ حَسَبُهُ فِيكُمْ قَالَ قُلْتُ هُوَ فِينَا ذُو حَسَبٍ قَالَ فَهَلْ كَانَ مِنْ آبَائِهِ مَلِكٌ قُلْتُ لَا قَالَ فَهَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ قُلْتُ لَا قَالَ وَمَنْ يَتَّبِعُهُ أَشْرَافُ النَّاسِ أَمْ ضُعَفَاؤُهُمْ قَالَ قُلْتُ بَلْ ضُعَفَاؤُهُمْ قَالَ أَيَزِيدُونَ أَمْ يَنْقُصُونَ قَالَ قُلْتُ لَا بَلْ يَزِيدُونَ قَالَ هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ سَخْطَةً لَهُ قَالَ قُلْتُ لَا قَالَ فَهَلْ قَاتَلْتُمُوهُ قُلْتُ نَعَمْ قَالَ فَكَيْفَ كَانَ قِتَالُكُمْ إِيَّاهُ قَالَ قُلْتُ تَكُونُ الْحَرْبُ بَيْنَنَا وَبَيْنَهُ سِجَالًا يُصِيبُ مِنَّا وَنُصِيبُ مِنْهُ قَالَ فَهَلْ يَغْدِرُ قُلْتُ لَا وَنَحْنُ مِنْهُ فِي مُدَّةٍ لَا نَدْرِي مَا هُوَ صَانِعٌ فِيهَا قَالَ فَوَاللَّهِ مَا أَمْكَنَنِي مِنْ كَلِمَةٍ أُدْخِلُ فِيهَا شَيْئًا غَيْرَ هَذِهِ قَالَ فَهَلْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ قَالَ قُلْتُ لَا قَالَ لِتَرْجُمَانِهِ قُلْ لَهُ إِنِّي سَأَلْتُكَ عَنْ حَسَبِهِ فَزَعَمْتَ أَنَّهُ فِيكُمْ ذُو حَسَبٍ وَكَذَلِكَ الرُّسُلُ تُبْعَثُ فِي أَحْسَابِ قَوْمِهَا وَسَأَلْتُكَ هَلْ كَانَ فِي آبَائِهِ مَلِكٌ فَزَعَمْتَ أَنْ لَا فَقُلْتُ لَوْ كَانَ مِنْ آبَائِهِ مَلِكٌ قُلْتُ رَجُلٌ يَطْلُبُ مُلْكَ آبَائِهِ وَسَأَلْتُكَ عَنْ أَتْبَاعِهِ أَضُعَفَاؤُهُمْ أَمْ أَشْرَافُهُمْ فَقُلْتَ بَلْ ضُعَفَاؤُهُمْ وَهُمْ أَتْبَاعُ الرُّسُلِ وَسَأَلْتُكَ هَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ فَزَعَمْتَ أَنْ لَا فَقَدْ عَرَفْتُ أَنَّهُ لَمْ يَكُنْ لِيَدَعَ الْكَذِبَ عَلَى النَّاسِ ثُمَّ يَذْهَبَ فَيَكْذِبَ عَلَى اللَّهِ وَسَأَلْتُكَ هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَهُ سَخْطَةً لَهُ فَزَعَمْتَ أَنْ لَا وَكَذَلِكَ الْإِيمَانُ إِذَا خَالَطَ بَشَاشَةَ الْقُلُوبِ وَسَأَلْتُكَ هَلْ يَزِيدُونَ أَوْ يَنْقُصُونَ فَزَعَمْتَ أَنَّهُمْ يَزِيدُونَ وَكَذَلِكَ الْإِيمَانُ حَتَّى يَتِمَّ وَسَأَلْتُكَ هَلْ قَاتَلْتُمُوهُ فَزَعَمْتَ أَنَّكُمْ قَدْ قَاتَلْتُمُوهُ فَتَكُونُ الْحَرْبُ بَيْنَكُمْ وَبَيْنَهُ سِجَالًا يَنَالُ مِنْكُمْ وَتَنَالُونَ مِنْهُ وَكَذَلِكَ الرُّسُلُ تُبْتَلَى ثُمَّ تَكُونُ لَهُمْ الْعَاقِبَةُ وَسَأَلْتُكَ هَلْ يَغْدِرُ فَزَعَمْتَ أَنَّهُ لَا يَغْدِرُ وَكَذَلِكَ الرُّسُلُ لَا تَغْدِرُ وَسَأَلْتُكَ هَلْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ فَزَعَمْتَ أَنْ لَا فَقُلْتُ لَوْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ قُلْتُ رَجُلٌ ائْتَمَّ بِقَوْلٍ قِيلَ قَبْلَهُ قَالَ ثُمَّ قَالَ بِمَ يَأْمُرُكُمْ قُلْتُ يَأْمُرُنَا بِالصَّلَاةِ وَالزَّكَاةِ وَالصِّلَةِ وَالْعَفَافِ قَالَ إِنْ يَكُنْ مَا تَقُولُ فِيهِ حَقًّا فَإِنَّهُ نَبِيٌّ وَقَدْ كُنْتُ أَعْلَمُ أَنَّهُ خَارِجٌ وَلَمْ أَكُنْ أَظُنُّهُ مِنْكُمْ وَلَوْ أَنِّي أَعْلَمُ أَنِّي أَخْلُصُ إِلَيْهِ لَأَحْبَبْتُ لِقَاءَهُ وَلَوْ كُنْتُ عِنْدَهُ لَغَسَلْتُ عَنْ قَدَمَيْهِ وَلَيَبْلُغَنَّ مُلْكُهُ مَا تَحْتَ قَدَمَيَّ قَالَ ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ سَلَامٌ عَلَى مَنْ اتَّبَعَ الْهُدَى أَمَّا بَعْدُ فَإِنِّي أَدْعُوكَ بِدِعَايَةِ الْإِسْلَامِ أَسْلِمْ تَسْلَمْ وَأَسْلِمْ يُؤْتِكَ اللَّهُ أَجْرَكَ مَرَّتَيْنِ وَإِنْ تَوَلَّيْتَ فَإِنَّ عَلَيْكَ إِثْمَ الْأَرِيسِيِّينَ وَ{ يَا أَهْلَ الْكِتَابِ تَعَالَوْا إِلَى كَلِمَةٍ سَوَاءٍ بَيْنَنَا وَبَيْنَكُمْ أَنْ لَا نَعْبُدَ إِلَّا اللَّهَ وَلَا نُشْرِكَ بِهِ شَيْئًا وَلَا يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًا مِنْ دُونِ اللَّهِ فَإِنْ تَوَلَّوْا فَقُولُوا اشْهَدُوا بِأَنَّا مُسْلِمُونَ }فَلَمَّا فَرَغَ مِنْ قِرَاءَةِ الْكِتَابِ ارْتَفَعَتْ الْأَصْوَاتُ عِنْدَهُ وَكَثُرَ اللَّغْطُ وَأَمَرَ بِنَا فَأُخْرِجْنَا قَالَ فَقُلْتُ لِأَصْحَابِي حِينَ خَرَجْنَا لَقَدْ أَمِرَ أَمْرُ ابْنِ أَبِي كَبْشَةَ إِنَّهُ لَيَخَافُهُ مَلِكُ بَنِي الْأَصْفَرِ قَالَ فَمَا زِلْتُ مُوقِنًا بِأَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَيَظْهَرُ حَتَّى أَدْخَلَ اللَّهُ عَلَيَّ الْإِسْلَامَو حَدَّثَنَاه حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ بِهَذَا الْإِسْنَادِ وَزَادَ فِي الْحَدِيثِ وَكَانَ قَيْصَرُ لَمَّا كَشَفَ اللَّهُ عَنْهُ جُنُودَ فَارِسَ مَشَى مِنْ حِمْصَ إِلَى إِيلِيَاءَ شُكْرًا لِمَا أَبْلَاهُ اللَّهُ وَقَالَ فِي الْحَدِيثِ مِنْ مُحَمَّدٍ عَبْدِ اللَّهِ وَرَسُولِهِ وَقَالَ إِثْمَ الْيَرِيسِيِّينَ وَقَالَ بِدَاعِيَةِ الْإِسْلَامِ","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dan [Ibnu Abu Umar] serta [Muhammad bin Rafi'] dan [Abd bin Humaid] sedangkan lafadznya dari Ibnu Rafi', Ibnu Rafi' dan Ibnu Abu Umar mengatakan; telah menceritakan kepada kami, sedangkan yang dua mengatakan; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] bahwa [Abu Sufyan] mengisahkan dari mulutnya sendiri sebagai berikut, \"Pada saat berlangsungnya perjanjian damai antara aku dengan Rasulullah shallallahu 'alaihi wasallam, aku pergi berniaga ke negeri Syam. Ketika aku berada di sana, ada seseorang yang mengirim sepucuk surat dari Rasulullah shallallahu 'alaihi wasallam kepada kaisar Heraclius, penguasa agung Rumawi, yang membawa surat itu adalah Dihyah Al Kalbi kepada pembesar Bushra, kemudian pembesar Bushra menyampaikannya kepada Heraclius. Lantas Heraclius bertanya, \"Adakah di sini orang yang berasal dari kaumnya laki-laki yang mengaku sebagai Nabi ini (Rasulullah)? ' mereka menjawab, \"Ya.\" Lalu aku dipanggil untuk menghadap Heraclius bersama beberapa kawanku dari suku Quraisy, kami masuk dan duduk menghadap Hiraclius. Heraclius lantas bertanya, \"Siapakah di antara kalian, yang dekat pertalian darahnya dengan orang yang mendakwakan dirinya menjadi Nabi itu?\" Abu Sufyan berkata, \"Lalu aku menjawab, \"Aku.\" Lalu aku duduk di depan, sedangkan kawan-kawanku duduk di belakangku. Kemudian dia memanggil penerjemahnya, lalu dia berkata kepada penerjemahnya, \"Katakanlah kepada mereka, bahwa aku menanyakan kepada mereka perihal laki-laki yang mendakwakan dirinya sebagai Nabi, jika dia berdusta, katakan dia telah berdusta.\" Abu Sufyan berkata, \"Demi Allah, kalaulah aku tidak takut dicap sebagai pendusta, sungguh telah ku dustai mereka.\" Kemudian Heraclius berkata kepada penerjemahnya, \"Tanyakan kepadanya, bagaimana kebangsaan orang itu di kalanganmu.\" Abu Sufyan berkata, \"Jawabku, \"Dia seorang bangsawan di kalangan kami.\" Dia bertanya, \"Apakah dia keturunan raja?\" aku menjawab, \"Tidak.\" Dia bertanya, \"Pernahkah kalian mengatakannya sebagai pembohong sebelum ia menjadi seorang Nabi?\" Jaawabku, \"Tidak.\" Dia bertanya, \"Apakah orang-orang yang mengikutinya dari kalangan pembesar ataukah hanya rakyat kecil?\" jawabku, \"Hanya rakyat kecil.\" Dia bertanya, \"Apakah pengikutnya selalu bertambah?\" Jawabku, \"Mereka selalu bertambah.\" Dia bertanya, \"Adakah di antara pengikutnya itu murtad karena benci terhadap agama yang dikembangkannya?\" Jawabku, \"Tidak.\" Dia bertanya, \"Apakah kamu berperang melawannya?\" Jawabku, \"Ya, pernah.\" Dia bertanya, \"Bagaimana perjalanan peperanganmu melawannya?\" Jawabku, \"Peperangan kami berjalan silih berganti antara menang dan kalah. Kadang-kadang kamilah yang menang dan dia yang kalah, dan terkadang pula kami yang kalah dan dia yang menang.\" Dia bertanya, \"Apakah dia pernah ingkat janji?\" Jawabku, \"Tidak, bahkan kami sedang dalam masa perjanjian damai, yaitu tidak akan serang menyerang dengannya. Aku tidak tahu apa yang akan dibuatnya terhadap perjanjian tersebut.\" Kata Abu Sufyan selanjutnya, \"Demi Allah, tidak ada kalimat lain yang dapat kami ucapkan selain dari pada itu semua.\" Dia bertanya, \"Apakah ada orang lain sebelum dia, yang mendakwakan dirinya sebagai Nabi seperti dia?\" Jawabku, \"Tidak.\" Kemudian dia berkata kepada penerjemahnya, \"Katakan kepadanya, \"Kutanyakan kepadamu tentang bangsanya (status sosialnya), maka kalian katakan dia termasuk dari bangsawan. Memang demikianlah halnya semua para rasul, mereka dibangkitkan dari kalangan bangsawan kaumnya. Kutanyakan pula kepadamu, apakah dia dari keturunan para raja? Jawabmu 'tidak', kalau sekiranya bapak dan kakeknya yang menjadi raja, tentunya ada sangkaan bahwa dia ingin mengembalikan kekusaan nenek moyangnya. Kutanyakan pula tentang pengikutnya, apakah terdiri dari rakyat kecil atau dari orang-orang besar? Kamu menjawab 'hanya terdiri dari rakyat kecil', memang merekalah pengikut para rasul. Kutanyakan pula, pernahkah kamu menuduhnya sebagai pembohong sebelumnya? Kamu menjawab 'tidak', aku tahu, bahwa dia tidak akan pernah berdusta kepada manusia, apalagi bedusta kepada Allah. Aku tanyakan kepadamu; adakah pengikutnya yang murtad atau mereka membenci agama baru setelah memeluknya? Jawabmu 'tidak', memang begitulah halnya, apabila iman telah tertanam dalam hati seseorang. Aku bertanya kepadamu, apakah pengikutnya berkurang? Jawabmu 'bahkan mereka selalu bertambah', memang seperti itulah iman hingga ia tumbuh sempurna. Kutanya pula, pernahkah kamu memeranginya? Jawabmu 'ya kami memerangi, dan peperangan silih berganti, terkadang menang dan terkadang kalah'. Memang demikianlah halnya, para rasul itu selalu diuji. Namun demikian, kemengangan terakhir selalu dipihak mereka. Kutanyakan pula, pernahkah dia ingkar janji? Jawabmu 'tidak pernah', memang demikian para rasul tidak mungkin ingkar janji. Kutanyakan pula kepadamu, adakah orang lain sebelum dia yang mengaku menjadi Nabi seperti dia? Jawabmu 'tidak', begitulah, kalau ada orang sebelumnya yang mendakwakan dirinya sebagai Nabi seperti dia, mungkin dia hanya ikut-ikutan dengan orang yang sebelumnya.\" Kemudian dia bertanya, \"Apa saja yang diperintahkanya kepadamu?\" Jawabku, \"Dia menyuruh kami shalat, membayar zakat, menjalin tali silaturrahmi dan menjaga kehormatan diri.\" dia berkata, \"Jika yang kamu katakan itu benar semuanya, maka tak salah lagi bahwa lelaki tersebut adalah seorang Nabi, aku tahu bahwa dia akan muncul, akan tetapi aku tidak menduga bahwa dia akan muncul dari kalangan kalian, sekiranya aku dapat bertemu dengannya, saat di sampingnya maka sungguh aku akan membasuh kedua kakinya. Dan daerah kekuasaannya kelak, akan sampai ke daerah kekuasanku ini.\" Abu Sufyan berkata, \"Kemudian dia meminta surat dari Rasulullah shallallahu 'alaihi wasallam dan membacanya, di dalamnya tertulis: \"Dengan nama Allah yang Maha pengasih lagi Maha penyayang, dari Muhammad Rasulullah kepada Heraclius pembesar Rumawi. Keselamatan bagi orang yang mengikuti petunjuk, sesungguhnya aku mengajak anda untuk masuk Islam, masuk Islamlah anda niscaya anda akan selamat. Masuk Islamlah anda, niscaya Allah akan memberi pahala kepada anda dengan berlipat ganda. Jika anda menolak, maka anda akan memikul dosa kaum 'arisyiyun. '(Hai ahli kitab, marilah (berpegang) kepada suatu kalimat (ketetapan) yang tidak ada perselisihan antara kami dan kamu, bahwa kita tidak akan menyembah kecuali Allah dan tidak kita persekutukan dia dengan sesuatupun dan tidak (pula) sebagian kita menjadikan sebagian yang lain sebagai Tuhan selain Allah. jika mereka menolak, maka Katakanlah kepada mereka: \"Saksikanlah, bahwa kami adalah orang-orang yang berserah diri (kepada Allah) ' (Qs. Ali Imran: 64) Setelah dia selesai membaca surat tersebut, tiba-tiba terdengar suara heboh di sekitarnya. Dia memerintahkan kami supaya keluar. Sesampainya di luar, aku berkata kepada kawan-kawanku, \"Sungguh luar biasa urusan Ibnu Abu Kabsyah (maksudnya Rasulullah), hingga dia diikuti oleh raja bani Ashfar (bangsa berkulit kuning), karena itu aku senantiasa yakin bahwa agama Rasulullah shallallahu 'alaihi wasallam ini pasti menang, dan akhirnya Allah memasukkan hidayah Islam ke dalam hati sanubariku.\" Dan telah menceritakan kepada kami [Hasan Al Khulwani] dan [Abd bin Humaid] keduanya berkata; telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim bin Sa'd- telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] dengan isnad ini, dan ia menambahkan dalam haditsnya, \"Setelah Allah memenangkan tentara Persi atasnya, maka Kaisar berjalan kaki dari daerah Himsha hingga Iliya` sebagai bentuk syukur akan ujian Allah.\" Dan dalam hadits itu pula disebutkan, \"Dari Muhammad, seorang hamba Allah dan Rasul-Nya.\" Dan dia juga menyebutkan, \"Dosa kaum Yarisiyin.\" Dan dia menyebutkan, \"Dengan seruan Islam.\""}],"3:70":[{"p":"Nasa'i","n":1378,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "}],"3:77":[{"p":"Abu Dawud","n":3061,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ الْأَشْعَثِ قَالَكَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ لِلْيَهُودِيِّ احْلِفْ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفُ وَيَذْهَبُ بِمَالِي فَأَنْزَلَ اللَّهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Al Asy'ats] ia berkata, \"Aku dan seorang laki-laki Yahudi berselisih atas sebuah lahan, kemudian ia mengingkariku. Maka aku pun datang menemui Nabi shallallahu 'alaihi wasallam dan mengadukan hal itu kepadanya, Nabi shallallahu 'alaihi wasallam lalu berkata kepadaku: \"Apakah engkau memiliki bukti?\" Aku menjawab, \"Tidak.\" Beliau bersabda kepada orang Yahudi tersebut: \"Bersumpahlah!\" Maka aku katakan, \"Wahai Rasulullah, jika demikian ia akan bersumpah dan membawa hartaku!\" Kemudian Allah menurunkan ayat: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit…) ' (Qs. Ali Imran: 77) hingga akhir ayat.\""},{"p":"Ahmad","n":1708,"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ جَرِيرِ بْنِ حَازِمٍ قَالَ حَدَّثَنَا عَدِيُّ بْنُ عَدِيٍّ قَالَ أَخْبَرَنِي رَجَاءُ بْنُ حَيْوَةَ وَالْعُرْسُ ابْنُ عَمِيرَةَ عَنْ أَبِيهِ عَدِيٍّ قَالَخَاصَمَ رَجُلٌ مِنْ كِنْدَةَ يُقَالُ لَهُ امْرُؤُ الْقَيْسِ بْنُ عَابِسٍ رَجُلًا مِنْ حَضَرَمَوْتَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَرْضٍ فَقَضَى عَلَى الْحَضْرَمِيِّ بِالْبَيِّنَةِ فَلَمْ تَكُنْ لَهُ بَيِّنَةٌ فَقَضَى عَلَى امْرِئِ الْقَيْسِ بِالْيَمِينِ فَقَالَ الْحَضْرَمِيُّ إِنْ أَمْكَنْتَهُ مِنْ الْيَمِينِ يَا رَسُولَ اللَّهِ ذَهَبَتْ وَاللَّهِ أَوْ وَرَبِّ الْكَعْبَةِ أَرْضِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبَةٍ لِيَقْتَطِعَ بِهَا مَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ قَالَ رَجَاءُ وَتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }فَقَالَ امْرُؤُ الْقَيْسِ مَاذَا لِمَنْ تَرَكَهَا يَا رَسُولَ اللَّهِ قَالَ الْجَنَّةُ قَالَ فَاشْهَدْ أَنِّي قَدْ تَرَكْتُهَا لَهُ كُلَّهَا","trj":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Jarir bin Hazim] ia berkata, Telah menceritakan kepada kami [Adi bin Adi] ia berkata, telah mengabarkan kepadaku [Raja` bin Haiwah] dan [Al Urs bin Amirah] dari bapaknya [Adi] ia berkata, \"Seorang laki-laki dari Kindah yang biasa dipanggil Umru`ul Qais bin Abis bersengketa dengan seorang laki-laki dari Hadhramut, mereka mengadukan kepada Rasulullah shallallahu 'alaihi wasallam prihal tanah. Maka beliau memberi putusan kepada Al Hadlrami agar ia menunjukkan bukti, namun ia tidak dapat menunjukkan bukti apapun. Kemudian Rasulullah shallallahu 'alaihi wasallam memberi putusan kepada Al Qais agar ia bersumpah. Al Hadlrami pun berkata, \"Jika tuan memberi keluasan baginya untuk bersumpah, niscaya tanah itu akan menjadi miliknya. Demi Allah, atau demi Rabb-nya Ka'bah, tanah itu adalah milikku.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan sumpah palsu untuk mengambil harta saudaranya, maka ia akan menemui Allah, sedang Allah dalam keadaan murka atasnya.\" Raja` berkata, \"Lalu Rasulullah shallallahu 'alaihi wasallam membacakan ayat: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit,..) ' (Qs. Ali Imran: 77). Maka Umru`ul Qais berkata, \"Wahai Rasulullah, lalu apa balasan bagi orang yang meninggalkannya?\" beliau menjawab: \"Baginya surga.\" Ia berkata, \"Saksikanlah, saya telah meninggalkannya (menyerahkan tanah itu) semua untuknya.\""},{"p":"Ahmad","n":1710,"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا سَيْفٌ قَالَ سَمِعْتُ عَدِيَّ بْنَ عَدِيٍّ الْكِنْدِيَّ يُحَدِّثُ عَنْ مُجَاهِدٍ قَالَ حَدَّثَنِي مَوْلًى لَنَا أَنَّهُ سَمِعَ عَدِيًّا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يُعَذِّبُ الْعَامَّةَ بِعَمَلِ الْخَاصَّةِ حَتَّى يَرَوْا الْمُنْكَرَ بَيْنَ ظَهْرَانَيْهِمْ وَهُمْ قَادِرُونَ عَلَى أَنْ يُنْكِرُوهُ فَلَا يُنْكِرُوهُ فَإِذَا فَعَلُوا ذَلِكَ عَذَّبَ اللَّهُ الْخَاصَّةَ وَالْعَامَّةَحَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ جَرِيرُ بْنُ حَازِمٍ قَالَ حَدَّثَنِي عَدِيُّ بْنُ عَدِيٍّ عَنْ رَجَاءِ بْنِ حَيْوَةَ وَالْعُرْسِ ابْنِ عَمِيرَةَ عَنْ أَبِيهِ عَدِيٍّ فَذَكَرَ الْحَدِيثَ قَالَ جَرِيرٌ وَزَادَنِي أَيُّوبُ وَكُنَّا جَمِيعًا حِينَ سَمِعْنَا الْحَدِيثَ مِنْ عَدِيٍّ قَالَ قَالَ عَدِيٌّ وَحَدَّثَنَا الْعُرْسُ ابْنُ عَمِيرَةَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِهَا وَلَمْ أَحْفَظْهُ أَنَا يَوْمَئِذٍ مِنْ عَدِيٍّ","trj":"Telah menceritakan kepada kami [Ibnu Numair] Telah menceritakan kepada kami [Saif] ia berkata, saya mendengar [Adi bin Adi Al Kindi] menceritakan dari [Mujahid] ia berkata, telah menceritakan kepadaku [Budak milik kami] bahwa ia mendengar [Adi] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla tidak mengadzab manusia secara umum hanya karena perbuatan dosa segelintir orang, sehingga mereka melihat kemungkaran dan mereka pun mampu untuk mengingkarinya, namun mereka tidak mengingkarinya. Jika mereka telah melakukan hal itu, maka Allah akan menyiksa segelintir orang itu dan juga manusia secara menyeluruh.\" Telah menceritakan kepada kami [Yazid bin Harun] dari [Jarir bin Hazim] ia berkata, telah menceritakan kepadaku [Adi bin Adi] dari [Raja` bin Haiwah] dan [Al Urs bin Amirah] dari bapaknya [Adi] lalu ia menyebutkan hadits tersebut.\" [Jarir] berkata, \" [Ayyub] menambahkan kepadaku, \"Ketika kami semua mendengar hadits itu dari Adi, ia berkata, \"Dan telah menceritakan kepada kami Al Ursu bin Amirah; Maka turunlah ayat ini: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit..) ' (Qs. Ali Imran: 77) -hingga akhir ayat- Saat itu aku belum menghafalnya dari Adi.\""},{"p":"Bukhari","n":1946,"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا الْعَوَّامُ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَقَامَ سِلْعَةً وَهُوَ فِي السُّوقِ فَحَلَفَ بِاللَّهِ لَقَدْ أَعْطَى بِهَا مَا لَمْ يُعْطِ لِيُوقِعَ فِيهَا رَجُلًا مِنْ الْمُسْلِمِينَ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }الْآيَةَ","trj":"Telah menceritakan kepada kami ['Amru bin Muhammad] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Al 'Awwam] dari [Ibrahim bin 'Abdurrahman] dari ['Abdullah bin Abi Aufa radliallahu 'anhu] bahwa ada seseorang menyiapkan barang dagangan dipasar, lalu ia bersumpah atas nama Allah, sesungguhnya ia telah memberikan barang tersebut dengan apa yang tidak ada padanya kepada seseorang dari kaum muslimin, lalu turunlah ayat: (\"Sesungguhnya orang-orang yang menukar janjinya dengan Allah dan sumpah-sumpah mereka dengan harga yang sedikit\"). (QS Al 'Imran: 77). "},{"p":"Bukhari","n":2472,"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ وَهُوَ فِيهَا فَاجِرٌ لِيَقْتَطِعَ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُقَالَ فَقَالَ الْأَشْعَثُ بْنُ قَيْسٍ فِيَّ وَاللَّهِ كَانَ ذَلِكَ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قَالَ قُلْتُ لَا قَالَ فَقَالَ لِلْيَهُودِيِّ احْلِفْ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفَ وَيَذْهَبَ بِمَالِي قَالَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari ['Abdullah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah dengan sumpah curang, dan bermaksud mengambil harta seorang muslim maka nanti dia akan berjumpa dengan Allah, sedang Allah murka kepadanya\". Dia berkata,, maka [Al Ays'ats bin Qais] berkata: \"Demi Allah, hadits itu berkenaan dengan aku, yang antara aku dan seorang Yahudi ada sebidang lahan, lalu dia mempermasalahkannya sehingga aku adukan kepada Nabi shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Apakah kamu memiliki bukti?\" Aku katakan: \"Tidak\". Lalu Beliau berkata kepada si Yahudi: \"Bersumpahlah kamu\". 'Abdullah berkata; Aku katakan: \"Wahai Rasulullah, kalau dia bersumpah nanti dia musti membawa hartaku\". 'Abdullah berkata: \"Maka turunlah firman Allah yang artinya: (\"Sesungguhnya orang-orang yang menjualjanjinya dengan Allah dan sumpah mereka dengan harga yang murah …hingga akhir ayat\") (QS. Ali Imran 77)."},{"p":"Bukhari","n":2479,"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْعَوَّامُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ أَبُو إِسْمَاعِيلَ السَّكْسَكِيُّ سَمِعَ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَقَامَ رَجُلٌ سِلْعَتَهُ فَحَلَفَ بِاللَّهِ لَقَدْ أَعْطَى بِهَا مَا لَمْ يُعْطِهَا فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }وَقَالَ ابْنُ أَبِي أَوْفَى النَّاجِشُ آكِلُ رِبًا خَائِنٌ","trj":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al 'Awwam] berkata, telah menceritakan kepadaku [Ibrahim Abu Isma'il as-Saksakiy] dia mendengar ['Abdullah bin Abu Awfaa radliallahu 'anhuma] berkata; Ada seseorang yang menunggui barang dagangannya, lalu dia bersumpah atas nama Allah bahwa dia hanya memberikan dagangannya dengan harga sekian-sekian padahal bohong belaka, maka turunlah firman Allah yang artinya: (\"Sesungguhnya orang-orang yang menjual janjinya kepada Allah dan sumpah mereka dengan harga yang murah..) (QS. Ali'Imran 77). Dan berkata Ibnu Abi Awfaa: \"Orang yang menipu orang lain, sama artinya dengan pemakan riba dan pengkhianat\"."},{"p":"Bukhari","n":2480,"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبًا لِيَقْتَطِعَ مَالَ رَجُلٍ أَوْ قَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ تَصْدِيقَ ذَلِكَ فِي الْقُرْآنِ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا الْآيَةَ إِلَى قَوْلِهِ عَذَابٌ أَلِيمٌ }فَلَقِيَنِي الْأَشْعَثُ فَقَالَ مَا حَدَّثَكُمْ عَبْدُ اللَّهِ الْيَوْمَ قُلْتُ كَذَا وَكَذَا قَالَ فِيَّ أُنْزِلَتْ","trj":"Telah menceritakan kepada kami [Bisyir bin Khalid] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah palsu (berdusta) yang dengan sumpahnya itu dia bermaksud mengambil harta orang lain atau Beliau bersabda dengan redaksi 'saudaranya', maka dia berjumpa Allah sedang Allah murka kepadanya\". Lalu Allah menurunkan ayat Al Qur'an sebagai pembenaran atas sabda Beliau ini yang artinya: (\"Sesungguhnya orang-orang yang menjual janjinya kepada Allah dan sumpah mereka dengan harga yang murah.. hingga firman-Nya …siksa yang pedih) (QS. Ali'Imran 77). Kemudian [Al Asy'ats] menemuiku seraya berkata: \"Apa yang diceritakan 'Abdullah kepada kalian hari ini?\" Aku katakan: \"Begini-begini\". Maka dia berkata: \"Ayat itu turun berkenaan dengan aku\"."},{"p":"Bukhari","n":5835,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ وَمَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبَةٍ يَقْتَطِعَ بِهَا مَالَ رَجُلٍ مُسْلِمٍ أَوْ قَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ }قَالَ سُلَيْمَانُ فِي حَدِيثِهِ فَمَرَّ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا يُحَدِّثُكُمْ عَبْدُ اللَّهِ قَالُوا لَهُ فَقَالَ الْأَشْعَثُ نَزَلَتْ فِيَّ وَفِي صَاحِبٍ لِي فِي بِئْرٍ كَانَتْ بَيْنَنَا","trj":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Syu'bah] dari [Sulaiman] dan [Manshur] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan sumpah dusta untuk menguasai harta seorang muslim -atau ia katakan dengan redaksi untuk menguasai harta saudaranya-- ia bertemu Allah sedang Allah dalam keadaan murka kepadanya.\" Kemudian Allah menurunkan ayat yang membenarkannya; 'Sesungguhnya orang-orang yang menukar janji Allah,,, dst (QS. Ali'Imran 77), [Sulaiman] berkata dalam haditsnya; kemudian Al Asy'ats bin Qais lewat dan berujar; 'Apa yang diceritakan Abdullah kepada kalian? ' Mereka pun menjawabnya dengan suatu jawaban sebagaimana diutarakan Abdullah. Lantas [Asy'ats] menerangkan; 'Sesungguhnya ayat diatas diturunkan tentang saya dan kawan saya karena suatu sumur yang ada diantara kami.'"},{"p":"Bukhari","n":5850,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِفَدَخَلَ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا حَدَّثَكُمْ أَبُو عَبْدِ الرَّحْمَنِ فَقَالُوا كَذَا وَكَذَا قَالَ فِيَّ أُنْزِلَتْ كَانَتْ لِي بِئْرٌ فِي أَرْضِ ابْنِ عَمٍّ لِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَيِّنَتُكَ أَوْ يَمِينُهُ قُلْتُ إِذًا يَحْلِفُ عَلَيْهَا يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ وَهُوَ فِيهَا فَاجِرٌ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ يَوْمَ الْقِيَامَةِ وَهُوَ عَلَيْهِ غَضْبَانُ","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu menuturkan; Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Barangsiapa bersumpah mengada-ada di depan hakim, dengan tujuan untuk memperoleh harta seorang muslim, maka ia berjumpa dengan Allah dan Allah murka kepadanya, \" kemudian Allah menurunkan ayat yang membenarkan hal ini dengan ayat; 'Sesungguhnya orang-orang yang menukar janji Allah dan sumpah mereka dengan harga yang sedikit' (QS. Ali'imran 77) hingga akhir ayat. Maka [Al Asy'ats bin Qais] masuk dan bertanya; 'Apa yang diceritakan Abu Abdurrahman kepada kalian? ' Mereka menjawab; 'begini dan begini'. Maka Al Asy'ats bin Qais berkata; 'ayat itu diturunkan kepada kami, yang ketika itu saya mempunyai sumur di pekarangan keponakanku, maka kudatangi Rasulullah Shallallahu'alaihi wa sallam dan beliau bersabda: \"Sekarang engkau harus menyertakan bukti kepemiikanmu atau dia melakukan sumpahnya!\" Aku menjawab; 'kalau begitu, dia pasti akan bersumpah Ya Rasulullah! ' Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Barangsiapa bersumpah dengan sumpah dusta (diada-adakan), ia melakukan kejahatan dengan sumpahnya itu dengan tujuan untuk merampas harta seorang muslim, ia akan menjumpai Allah sedang Allah dalam keadaan murka kepadanya.\""},{"p":"Muslim","n":196,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَاللَّفْظُ لَهُ أَخْبَرَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ هُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُقَالَ فَدَخَلَ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ قَالُوا كَذَا وَكَذَا قَالَ صَدَقَ أَبُو عَبْدِ الرَّحْمَنِ فِيَّ نَزَلَتْ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ أَرْضٌ بِالْيَمَنِ فَخَاصَمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ لَكَ بَيِّنَةٌ فَقُلْتُ لَا قَالَ فَيَمِينُهُ قُلْتُ إِذَنْ يَحْلِفُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ هُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالًا هُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِ الْأَعْمَشِ غَيْرَ أَنَّهُ قَالَ كَانَتْ بَيْنِي وَبَيْنَ رَجُلٍ خُصُومَةٌ فِي بِئْرٍ فَاخْتَصَمْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ شَاهِدَاكَ أَوْ يَمِينُهُ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki']. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abu Muawiyah] dan [Waki']. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Ishaq bin Ibrahim al-Hanzhali] dan lafazh tersebut miliknya, telah mengabarkan kepada kami [Waki'] telah menceritakan kepada kami [al-A'masy] dari [Abu Wail] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa bersumpah atas untuk mengambil harta seorang muslim, maka karena itu ia menjadi seorang yang durhaka, dia akan bertemu Allah sementara Allah murka kepadanya.\" Perawi berkata, \"Lalu [al-Ats'asy bin Qais] masuk seraya bertanya, \"Apa yang diceritakan Abu Abdurrahman kepada kalian?\" Mereka menjawab, \"Demikian dan demikian.\" Asy'ats berkata, \"Abu Abdurrahman benar, hadits tersebut turun berkenaan denganku. Ada perselisihan antara aku dengan seorang laki-laki tentang tanah di Yaman, lalu aku mengajukan hal itu ke hadapan Nabi shallallahu 'alaihi wasallam, maka beliau bertanya: 'Apakah kamu mempunyai bukti'. Aku menjawab, 'Tidak.' Beliau bersabda: \"Maka sumpahnya (dijadikan sebagai alat hukum).' Aku berkata, 'Jadi dia bersumpah? ' Saat itu juga beliau langsung bersabda: \"Barangsiapa bersumpah untuk mengambil harta seorang Muslim, maka karena itu ia menjadi seorang yang durhaka, dia akan bertemu Allah sementara Allah murka kepadanya.\" Lalu turunlah ayat: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit, mereka itu tidak mendapat bahagian (pahala) di akhirat, dan Allah tidak akan berkata-kata dengan mereka dan tidak akan melihat kepada mereka pada hari kiamat dan tidak (pula) akan mensucikan mereka. Bagi mereka azab yang pedih) ' (Qs. Ali Imran: 77). Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Abu Wail] dari [Abdullah] dia berkata, 'Barangsiapa bersumpah untuk mendapatkan harta (orang lain), maka karena itu ia menjadi seorang yang durhaka, dan ia akan berjumpa dengan Allah sementara Allah dalam kondisi murka kepadanya.\" Kemudian dia menyebutkan semisal hadits al-A'masy, hanya saja dia menyebutkan, \"Pernah terjadi perselisihan antara aku dengan seorang laki-laki dalam masalah sumur. Maka kami mengadukannya kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lalu bersabda: \"Hendaklah kamu menghadirkan dua saksi, atau dia bersumpah'.\""},{"p":"Muslim","n":197,"ar":"و حَدَّثَنَا ابْنُ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ عَنْ جَامِعِ بْنِ أَبِي رَاشِدٍ وَعَبْدِ الْمَلِكِ بْنِ أَعْيَنَ سَمِعَا شَقِيقَ بْنَ سَلَمَةَ يَقُولُ سَمِعْتُ ابْنَ مَسْعُودٍ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَلَفَ عَلَى مَالِ امْرِئٍ مُسْلِمٍ بِغَيْرِ حَقِّهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ قَالَ عَبْدُ اللَّهِ ثُمَّ قَرَأَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِصْدَاقَهُ مِنْ كِتَابِ اللَّهِ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","trj":"Dan telah menceritakan kepada kami [Ibnu Abu Umar al-Makki] telah menceritakan kepada kami [Sufyan] dari [Jami' bin Abu Rasyid] dan [Abdul Malik bin A'yan] keduanya mendengar [Syaqiq bin Salamah] berkata, saya mendengar [Ibnu Mas'ud] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah atas harta seorang muslim tanpa haknya, niscaya dia menemui Allah, sedangkan Dia dalam keadaan marah kepadanya.\" Abdullah berkata, \"Kemudian Rasulullah membacakan untuk kami dalilnya dari Kitabullah: '(Sesungguhnya orang-orang yang menjual janji Allah dan sumpah mereka dengan harga yang murah…) ' (Qs. Ali Imran: 77), hingga akhir ayat.\""}],"3:92":[{"p":"Darimi","n":1243,"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَ كَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ مَالًا نَخْلًا وَكَانَتْ أَحَبَّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءُ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَائِهَا طَيِّبٌ فَقَالَ أَنَسٌ فَلَمَّا أُنْزِلَتْ هَذِهِ الْآيَةُ { لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ } قَالَ إِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءُ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ شِئْتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخٍ ذَلِكَ مَالٌ رَابِحٌ أَوْ رَائِحٌ وَقَدْ سَمِعْتُ مَا قُلْتَ فِيهِ وَإِنِّي أَرَى أَنْ تَجْعَلَهُ فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَّمَهُ أَبُو طَلْحَةَ فِي قَرَابَةِ بَنِي عَمِّهِ","trj":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas] ia berkata, \"Abu Thalhah adalah orang anshar yang paling banyak hartanya di kota Madinah, yaitu pohon kurma. Harta yang paling ia senangi adalah Bairuha` (kebun kurma) yang menghadap ke masjid. Ia biasa masuk untuk makan (buha) dan meminum airnya yang jernih.\" Anas berkata, \"Kemudian tatkala ayat: '(Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sehahagian harta yang kamu cintai) ' (Qs. Ali Imran: 92). Abu Thalhah berkata, \"Sungguh, hartaku yang paling aku senangi adalah Bairuha`, dan sesungguhnya kebun tersebut adalah sedekah untuk Allah, aku mengharapkan kebaikan dan simpanan pahalanya di sisi Allah. Maka pergunakan di mana engkau kehendaki wahai Rasul! \" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Bakh, itu adalah harta yang menguntungkan, sungguh aku telah mendengar apa yang engkau katakan. Namun menurutku, sebaiknya itu engkau berikan kepada para kerabat.\" Kemudian Abu Thalhah berkata, \"Aku akan melakukannya wahai Rasulullah! \" Abu Thalhah lalu membaginya di antara para kerabat anak pamannya.\""},{"p":"Malik","n":1575,"ar":"و حَدَّثَنِي مَالِك عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ مَالًا مِنْ نَخْلٍ وَكَانَ أَحَبَّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءَ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَاءٍ فِيهَا طَيِّبٍ قَالَ أَنَسٌ فَلَمَّا أُنْزِلَتْ هَذِهِ الْآيَةُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَامَ أَبُو طَلْحَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }وَإِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءَ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ شِئْتَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخْ ذَلِكَ مَالٌ رَابِحٌ ذَلِكَ مَالٌ رَابِحٌ وَقَدْ سَمِعْتُ مَا قُلْتَ فِيهِ وَإِنِّي أَرَى أَنْ تَجْعَلَهَا فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَمَهَا أَبُو طَلْحَةَ فِي أَقَارِبِهِ وَبَنِي عَمِّهِ","trj":"Telah menceritakan kepadaku Malik dari [Ishaq bin Abdullah bin Abu Thalhah] Bahwasanya ia mendengar [Anas bin Malik] berkata, \"Abu Thalhah adalah orang Anshar yang paling banyak hartanya di Madinah yang berupa kurma. Adapun harta yang paling dia sukai ialah Bairuha yang berada di depan masjid. Rasulullah shallallahu 'alaihi wasallam biasa memasukinya dan minum dari airnya yang jernih.\" Anas berkata; \"Ketika ayat ini diturunkan: '(Kalian sekali-kali tidak akan mendapatkan kebaikan (yang sempurna) sehingga kalian menginfakkan sebagian harta yang kalian sukai) .' (Qs. Ali Imran: 92) Abu Thalhah berdiri menghadap Rasulullah shallallahu 'alaihi wasallam kemudian berkata; 'Wahai Rasulullah, Allah Tabaraka Wa Ta'ala berfirman: '(Kalian sekali-kali tidak akan mendapatkan kebaikan (yang sempurna) sehingga kalian menginfakkan sebagian harta yang kalian sukai) ', sungguh harta yang paling aku sukai adalah Bairuha, kebun itu saya infakkan karena Allah, aku harap kebaikannya dan penyimpanannya di sisi Allah. Wahai Rasulullah, pergunakanlah harta tersebut sebagaimana anda kehendaki.\" Anas berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hebat…! Itu adalah harta yang menguntungkan, itu adalah harta yang menguntungkan. Aku telah mendengar apa yang engkau katakan. Menurutku sebaiknya kamu memberikannya kepada karib kerabat.' Maka Abu Thalhah berkata, \"Wahai Rasulullah, akan aku lakukan.\" Kemudian dia membaginya untuk keluarga dan anak pamannya.\""},{"p":"Nasa'i","n":3445,"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَالَ أَبُو طَلْحَةَ إِنَّ رَبَّنَا لَيَسْأَلُنَا عَنْ أَمْوَالِنَا فَأُشْهِدُكَ يَا رَسُولَ اللَّهِ أَنِّي قَدْ جَعَلْتُ أَرْضِي لِلَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلْهَا فِي قَرَابَتِكَ فِي حَسَّانَ بْنِ ثَابِتٍ وَأُبَيِّ بْنِ كَعْبٍ","trj":"Telah mengabarkan kepada kami [Abu Bakr bin Nafi'] berkata; telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami [Hammad] berkata; telah menceritakan kepada kami [Tsabit] dari [Anas] berkata, \"Tatkala turun ayat ini: '(Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebagian harta yang kamu cintai) ' (Qs. Ali Imran: 92), maka Abu Thalhah berkata, \"Sungguh, tuhan kita akan bertanya kepada kita mengenai harta-harta kita. Maka aku meminta persaksianmu wahai Rasulullah, bahwa aku telah menjadikan lahanku untuk Allah.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jadikanlah lahan tersebut untuk para kerabatmu, yaitu Hasan bin Tsabit dan Ubay bin Ka'b.\""},{"p":"Tirmidzi","n":2822,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }أَوْ{ مَنْ ذَا الَّذِي يُقْرِضُ اللَّهَ قَرْضًا حَسَنًا }قَالَ أَبُو طَلْحَةَ وَكَانَ لَهُ حَائِطٌ فَقَالَ يَا رَسُولَ اللَّهِ حَائِطِي لِلَّهِ وَلَوْ اسْتَطَعْتُ أَنْ أُسِرَّهُ لَمْ أُعْلِنْهُ فَقَالَ اجْعَلْهُ فِي قَرَابَتِكَ أَوْ أَقْرَبِيكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكِ","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdullah bin Bakr As Sahmani] telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata; \"Ketika turun ayat Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebahagian harta yang kamu cintai.\" QS Ali 'Imran: 92 atau Siapakah yang mau memberi pinjaman kepada Allah, pinjaman yang baik (menafkahkan hartanya di jalan Allah). QS Al-Baqarah: 245, kemudian Abu Thalhah, yang memiliki kebun berkata; \"Wahai Rasulullah, saya (infakkan) kebun saya ini di jalan Allah. Dan sekiranya saya mampu untuk menyembunyikannya tentu saya tidak menyatakannya. lalu beliau mengatakan \"Berikanlah kepada kerabat atau orang yang terdekat denganmu!\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan [Malik bin Anas] telah meriwayatkan dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] "}],"3:93":[{"p":"Bukhari","n":6618,"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ وَامْرَأَةٍ مِنْ الْيَهُودِ قَدْ زَنَيَا فَقَالَ لِلْيَهُودِ مَا تَصْنَعُونَ بِهِمَا قَالُوا نُسَخِّمُ وُجُوهَهُمَا وَنُخْزِيهِمَا قَالَ{ فَأْتُوا بِالتَّوْرَاةِ فَاتْلُوهَا إِنْ كُنْتُمْ صَادِقِينَ }فَجَاءُوا فَقَالُوا لِرَجُلٍ مِمَّنْ يَرْضَوْنَ يَا أَعْوَرُ اقْرَأْ فَقَرَأَ حَتَّى انْتَهَى إِلَى مَوْضِعٍ مِنْهَا فَوَضَعَ يَدَهُ عَلَيْهِ قَالَ ارْفَعْ يَدَكَ فَرَفَعَ يَدَهُ فَإِذَا فِيهِ آيَةُ الرَّجْمِ تَلُوحُ فَقَالَ يَا مُحَمَّدُ إِنَّ عَلَيْهِمَا الرَّجْمَ وَلَكِنَّا نُكَاتِمُهُ بَيْنَنَا فَأَمَرَ بِهِمَا فَرُجِمَا فَرَأَيْتُهُ يُجَانِئُ عَلَيْهَا الْحِجَارَةَ","trj":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Ismail] dari [Ayyub] dari [Nafi'] dari [Ibn Umar] radliyallahu'anhuma berkata, \"Seorang laki-laki dan wanita Yahudi yang berzina didatangkan kepada nabi shallallahu 'alaihi wasallam, Nabi lalu bertanya kepada si Yahudi: 'Hukuman apa biasa kalian lakukan terhadap keduanya? ' Mereka menjawab, 'Kami biasanya menghukum mereka dengan menghitami wajah keduanya dan menghinakannya.' Lantas nabi bersabda (dengan mengutip ayat): '(Maka datangkanlah Taurat dan bacalah, jika kalian orang-orang yang benar) ', (Qs. Ali 'Imran: 93), lantas mereka datang dan mereka katakan kepada seseorang yang mereka percayai, 'Hai A'war bacalah! Lantas A'war membaca hingga sampai ayat (yang berkenaan hukum perzinaan), dengan terburu-buru ia menutupi dengan tangannya, maka Nabi menegur: 'Hai, angkatlah tanganmu! ' Maka ia angkat tangannya. Dan ternyata yang ia tutupi adalah ayat rajam, lantas A'war berkata, 'Hai Muhammad, kedua orang itu wajib dirajam, hanya kami merahasiakannya di antara kami.' Maka Nabi perintahkan agar keduanya dirajam, dan kemudian keduanya pun dirajam. Sungguh, aku lihat yang laki-laki membungkukkan badannya ke arah wanita untuk mencegahnya agar tidak terkena batu.\""}],"3:97":[{"p":"Tirmidzi","n":2849,"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا مُنْصُورُ بْنُ وَرْدَانَ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِيهِ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ عَلِيٍّ قَالَلَمَّا نَزَلَتْ{ وَلِلَّهِ عَلَى النَّاسِ حِجُّ الْبَيْتِ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا }قَالُوا يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ فَسَكَتَ قَالُوا يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ قَالَ لَا وَلَوْ قُلْتُ نَعَمْ لَوَجَبَتْ فَأَنْزَلَ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ عَلِيٍّ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ","trj":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Manshur bin Wardan] dari [Ali bin Abdul A'la] dari [Ayahnya] dari [Abu al Bakhtari] dari [Ali] ia berkata; Tatkala turun ayat Mengerjakan haji adalah kewajiban manusia terhadap Allah, yaitu (bagi) orang yang sanggup mengadakan perjalanan ke Baitullah QS Ali Imran: 97, para sahabat bertanya; \"Wahai Rasulullah, apakah (dilakukan) setiap tahun?\" Beliau terdiam, mereka bertanya lagi; \"Wahai Rasulullah, apakah (dilakukan) setiap tahun?\" beliau menjawab: \"Tidak, seandainya tadi kujawab ya, pasti akan menjadi wajib (hukumnya).\" Lalu Allah menurunkan Hai orang-orang yang beriman, janganlah kamu menanyakan (kepada Nabimu) hal-hal yang jika diterangkan kepadamu akan menyusahkan Kamu. QS Al Mai`idah: 101. Abu Isa mengatakan bahwa hadits ini hasan gharib."}],"3:101":[{"p":"Tirmidzi","n":2849,"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا مُنْصُورُ بْنُ وَرْدَانَ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِيهِ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ عَلِيٍّ قَالَلَمَّا نَزَلَتْ{ وَلِلَّهِ عَلَى النَّاسِ حِجُّ الْبَيْتِ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا }قَالُوا يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ فَسَكَتَ قَالُوا يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ قَالَ لَا وَلَوْ قُلْتُ نَعَمْ لَوَجَبَتْ فَأَنْزَلَ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ عَلِيٍّ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ","trj":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Manshur bin Wardan] dari [Ali bin Abdul A'la] dari [Ayahnya] dari [Abu al Bakhtari] dari [Ali] ia berkata; Tatkala turun ayat Mengerjakan haji adalah kewajiban manusia terhadap Allah, yaitu (bagi) orang yang sanggup mengadakan perjalanan ke Baitullah QS Ali Imran: 97, para sahabat bertanya; \"Wahai Rasulullah, apakah (dilakukan) setiap tahun?\" Beliau terdiam, mereka bertanya lagi; \"Wahai Rasulullah, apakah (dilakukan) setiap tahun?\" beliau menjawab: \"Tidak, seandainya tadi kujawab ya, pasti akan menjadi wajib (hukumnya).\" Lalu Allah menurunkan Hai orang-orang yang beriman, janganlah kamu menanyakan (kepada Nabimu) hal-hal yang jika diterangkan kepadamu akan menyusahkan Kamu. QS Al Mai`idah: 101. Abu Isa mengatakan bahwa hadits ini hasan gharib."}],"3:102":[{"p":"Nasa'i","n":1378,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "}],"3:110":[{"p":"Tirmidzi","n":2825,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي قَوْلِهِ تَعَالَى{ كُنْتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ }قَالَ إِنَّكُمْ تَتِمُّونَ سَبْعِينَ أُمَّةً أَنْتُمْ خَيْرُهَا وَأَكْرَمُهَا عَلَى اللَّهِهَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ بَهْزِ بْنِ حَكِيمٍ نَحْوَ هَذَا وَلَمْ يَذْكُرُوا فِيهِ{ كُنْتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ }","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda tentang firman Allah Ta'ala; Kamu adalah umat yang terbaik yang dilahirkan untuk manusia. QS Ali Imran: 110, beliau bersabda: \"Sesungguhnya kalian terbagi menjadi tujuh puluh umat, dan kalianlah yang terbaik (diantara mereka) serta paling mulia di sisi Allah.\" Hadits ini hasan. Beberapa perawi meriwayatkan hadits ini dari Bahz bin Hakim seperti ini, namun mereka tidak menyebut: Kamu adalah umat yang terbaik yang dilahirkan untuk manusia QS Ali Imran: 110."}],"3:116":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""}],"3:122":[{"p":"Bukhari","n":3546,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَزَلَتْ هَذِهِ الْآيَةُ فِينَا{ إِذْ هَمَّتْ طَائِفَتَانِ مِنْكُمْ أَنْ تَفْشَلَا }بَنِي سَلِمَةَ وَبَنِي حَارِثَةَ وَمَا أُحِبُّ أَنَّهَا لَمْ تَنْزِلْ وَاللَّهُ يَقُولُ{ وَاللَّهُ وَلِيُّهُمَا }","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Ibnu Uyainah] dari ['Amru] dari [Jabir] radliallahu 'anhu, dia berkata, \"Ayat ini turun kepada kami: '(Ketika dua golongan dari padamu ingin (mundur) Karena takut..) ' (Qs. Ali Imran: 122), yaitu bani Salimah dan Bani Haritsah, dan aku lebih suka jika ayat tersebut tidak turun, Allah berfirman: '(padahal Allah adalah penolong bagi kedua golongan itu) '."},{"p":"Muslim","n":4221,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَأَحْمَدُ بْنُ عَبْدَةَ وَاللَّفْظُ لِإِسْحَقَ قَالَا أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَفِينَا نَزَلَتْ{ إِذْ هَمَّتْ طَائِفَتَانِ مِنْكُمْ أَنْ تَفْشَلَا وَاللَّهُ وَلِيُّهُمَا }بَنُو سَلِمَةَ وَبَنُو حَارِثَةَ وَمَا نُحِبُّ أَنَّهَا لَمْ تَنْزِلْ لِقَوْلِ اللَّهِ عَزَّ وَجَلَّ{ وَاللَّهُ وَلِيُّهُمَا }","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dan [Ahmad bin 'Abdah], lafazh ini milik Ishaq keduanya berkata; Telah mengabarkan kepada kami [Sufyan] dari ['Amru] dari [Jabir bin 'Abdullah] dia berkata; \"Ada ayat Al Qur'an yang turun berkenaan dengan kami yaitu: 'Ingatlah ketika dua golongan ingin mundur karena takut, padahal Allah penolong kedua golongan tersebut. '(Qs. Ali 'lmraan (2): 122) Keduanya adalah Bani Salimah dan Bani Haritsah. Kami tidak senang jika ayat ini tidak turun, karena firman Allah yang berbunyi: \"Padahal Allah penolong kedua golongan itu (QS. Ali-Imran 122)."}],"3:128":[{"p":"Bukhari","n":3559,"ar":"حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ السُّلَمِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي سَالِمٌ عَنْ أَبِيهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ مِنْ الرَّكْعَةِ الْآخِرَةِ مِنْ الْفَجْرِ يَقُولُ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا وَفُلَانًا بَعْدَ مَا يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ فَأَنْزَلَ اللَّهُ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ إِلَى قَوْلِهِ فَإِنَّهُمْ ظَالِمُونَ }وَعَنْ حَنْظَلَةَ بْنِ أَبِي سُفْيَانَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو عَلَى صَفْوَانَ بْنِ أُمَيَّةَ وَسُهَيْلِ بْنِ عَمْرٍو وَالْحَارِثِ بْنِ هِشَامٍ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ إِلَى قَوْلِهِ فَإِنَّهُمْ ظَالِمُونَ }","trj":"Telah menceritakan kepada kami [Yahya bin Abdullah As Sulami] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah menceritakan kepadaku [Salim] dari [Ayahnya] bahwa dia mendengar saat Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya dari rukuk di rakaat terakhir shalat shubuh, beliau mengucapkan: \"Ya Allah, laknatlah fulan, fulan dan fulan, \" yaitu setelah beliau mengucapkan: \"Sami'allahu liman hamidah, rabbanaa walakalhamdu.\" Setelah itu Allah menurunkan ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu -hingga firmanNya- Sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128). Dan dari [Hanzhalah bin Abu Sufyan] aku mendengar [Salim bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mendo'akan (kejelekkan) kepada Shofwan bin Umayyah, Suhail bin 'Amru dan Harits bin Hisyam, lalu turunlah ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu -hingga firmanNya- Sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128)."},{"p":"Bukhari","n":6447,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي صَلَاةِ الْفَجْرِ وَرَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ فِي الْأَخِيرَةِ ثُمَّ قَالَ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibn Umar] ia mendengar nabi shallallahu 'alaihi wasallam berdoa ketika shalat fajar dan ketika mengangkat kepalanya dari rukuk: 'ALLAAHUMMA RABBANAA WALAKAL HAMDU (Ya Allah rabb kami, bagi-Mu segala puji) ', itu beliau ucapkan pada rukuk terakhir. Kemudian beliau berdoa: 'ALLAAHUMMA IL 'AN FULAANAN WAFULAANAN (Ya Allah, laknatlah si A dan si B) '. Lantas Allah menurunkan ayat: '(Sama sekali engkau tidak mempunyai wewenang terhadap urusan mereka itu, Allah mengampuni mereka atau menyiksa mereka, sebab mereka adalah orang-orang yang zhalim) ' (Qs. Ali'Imran: 128)."},{"p":"Darimi","n":1194,"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يَدْعُوَ عَلَى أَحَدٍ أَوْ يَدْعُوَ لِأَحَدٍ قَنَتَ بَعْدَ الرُّكُوعِ فَرُبَّمَا قَالَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا سِنِينَ كَسِنِي يُوسُفَ وَيَجْهَرُ بِذَلِكَ يَقُولُ فِي بَعْضِ صَلَاتِهِ فِي صَلَاةِ الْفَجْرِ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا لِحَيَّيْنِ مِنْ أَحْيَاءِ الْعَرَبِ فَأَنْزَلَ اللَّهُ تَعَالَى { لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }","trj":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Ibnu Al Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam jika ingin mendoakan keburukan atas seseorang atau mendoakan kebaikan untuk seseorang, maka beliau melakukan qunut setelah rukuk. Barangkali setelah mengucapkan SAMI'ALLAAHU LIMAN HAMIDAH, RABBANAA WA LAKAL HAMDU (Semoga Allah mendengar pujian orang yang memuji-Nya. Ya Rabb kami, kepada-Mu lah segala pujian), beliau berdoa: \"Ya Allah, selamatkan Al Walid bin Al Walid, Salamah bin Hisyam, 'Ayyasy bin Abu Rabi'ah dan orang-orang Mukmin yang lemah. Ya Allah, keraskan siksa-Mu atas Mudlar, timpakahlah kepada mereka masa paceklik sebagaimana paceklik pada masa Yusuf.\" Beliau mengeraskan doa tersebut. Dan beliau mengucapkan pada sebagian shalatnya; shalat subuh: \"Ya Allah, laknatlah Fulan dan Fulan.\" Beliau menyebutkan dua kampung dari kampung-kampung Arab. Kemudian Allah Ta'ala menurunkan ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka karena sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128)."},{"p":"Muslim","n":1049,"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ بْنُ يَحْيَى قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُمَا سَمِعَا أَبَا هُرَيْرَةَ يَقُولُاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حِينَ يَفْرُغُ مِنْ صَلَاةِ الْفَجْرِ مِنْ الْقِرَاءَةِ وَيُكَبِّرُ وَيَرْفَعُ رَأْسَهُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ يَقُولُ وَهُوَ قَائِمٌ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا عَلَيْهِمْ كَسِنِي يُوسُفَ اللَّهُمَّ الْعَنْ لِحْيَانَ وَرِعْلًا وَذَكْوَانَ وَعُصَيَّةَ عَصَتْ اللَّهَ وَرَسُولَهُ ثُمَّ بَلَغَنَا أَنَّهُ تَرَكَ ذَلِكَ لَمَّا أُنْزِلَ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ قَالَا حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ إِلَى قَوْلِهِ وَاجْعَلْهَا عَلَيْهِمْ كَسِنِي يُوسُفَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ","trj":"Telah menceritakan kepadaku [Abu At Thahir] dan [Harmalah bin Yahya], keduanya berkata; telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] katanya; telah mengabarkan kepadaku [Said bin Musayyab] dan [Abu Salamah bin Abdurrahman bin 'Auf], keduanya mendengar [Abu Hurairah] berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam shalat fajar (subuh), yaitu setelah membaca, bertakbir dan mengangkat kepalanya, beliau membaca \"Sami'allahu liman hamidah. Rabbanaa walakal hamdu.\" Kemudian beliau membaca lagi dan beliau masih berdiri, yaitu; ALLAAHUMMA ANJI ALWALID BIN WALID WA SALAMAH BIN HISYAM, WA AYYASY BIN ABU RABIAH, WAL MUSTADH'AFIINA MINAL MUL'MINIINA, ALLAAHUMMASY DUD WATH'ATHAKA 'ALAA MUDHARR WAJ'ALHAA 'ALIHIM KASINII YUUSUFA, ALLAAHUMMAL'AN LIHYAANA WARI'LAN WADZAKWAAANA WA'USHAYYAH ASHATALLAAHA WARASUULAHU (Ya Allah, selamatkanlah Walid bin walid, Salamah bin Hisyam, Ayyasy bin Abu Rabiah dan orang-orang mukmin yang lemah, Ya Allah, perkuatlah hukumanmu kepada Mudharr dan jadikanlah untuk mereka masa-masa paceklik sebagaimana paceklik Yusuf, Ya Allah, laknatilah Lihyan, Ri'l, dan Dzakwan, mereka yang telah membangkang Allah dan Rasul-Nya.\" Kemudian sampai berita kepada kami, bahwa beliau meninggakan doa (qunut) tersebut, tepatnya ketika turun ayat \"Tidak ada urusanmu entah Allah mengampuni mereka atau menyiksa mereka, sesungguhnya mereka orang-orang yang zhalim (QS. Ali Imran 128), Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan ['Amru An Naqid], keduanya berkata; telah menceritakan kepada kami [Ibn 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam hingga sabdanya: \"Ya Allah, jadikanlah untuk mereka tahun-tahun paceklik sebagaimana tahun-tahun paceklik Yusuf.\" Dan ia tidak menyebutkan kalimat sesudahnya."},{"p":"Muslim","n":3113,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُسِرَتْ رَبَاعِيَتُهُ يَوْمَ أُحُدٍ وَشُجَّ فِي رَأْسِهِ فَجَعَلَ يَسْلُتُ الدَّمَ عَنْهُ وَيَقُولُ كَيْفَ يُفْلِحُ قَوْمٌ شَجُّوا نَبِيَّهُمْ وَكَسَرُوا رَبَاعِيَتَهُ وَهُوَ يَدْعُوهُمْ إِلَى اللَّهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ }","trj":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas], bahwa gigi geraham Rasulullah shallallahu 'alaihi wasallam pecah ketika perang Uhud, dan kepala beliau juga terluka hingga mengalirkan darah, beliau lalu bersabda: \"Bagaimana mungkin suatu kaum akan beruntung, sedangkan mereka melukai nabinya dan mematahkan gigi gerahamnya.\" Oleh karena itu beliau memohon kepada Allah untuk mengutuk mereka, lalu Allah Azza wa jalla menurunkan ayat: '(Kamu tidak memiliki wewenang apa-apa terhadap urusan mereka…) ' (Qs. Ali Imran: 128)."},{"p":"Tirmidzi","n":2826,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُسِرَتْ رَبَاعِيَتُهُ يَوْمَ أُحُدٍ وَشُجَّ وَجْهُهُ شَجَّةً فِي جَبْهَتِهِ حَتَّى سَالَ الدَّمُ عَلَى وَجْهِهِ فَقَالَ كَيْفَ يُفْلِحُ قَوْمٌ فَعَلُوا هَذَا بِنَبِيِّهِمْ وَهُوَ يَدْعُوهُمْ إِلَى اللَّهِ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ }إِلَى آخِرِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid] dari [Anas] bahwa pada perang Uhud, rahang Rasulullah shallallahu 'alaihi wasallam retak dan pelipisnya terluka hingga wajahnya mengalirkan darah. Beliau bersabda: \"Bagaimana mungkin suatu kaum akan beruntung sedang mereka memperlakukan nabinya seperti ini, padahal ia menyeru mereka ke jalan Allah.\" lalu turunlah ayat: Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka. QS Ali Imran: 128, Abu Isa mengatakan bahwa hadits ini hasan shahih."},{"p":"Tirmidzi","n":2827,"ar":"حَدَّثَنَا أَبُو السَّائِبِ سَلْمُ بْنُ جُنَادَةَ بْنِ سَلْمٍ الْكُوفِيُّ حَدَّثَنَا أَحْمَدُ بْنُ بَشِيرٍ عَنْ عُمَرَ بْنِ حَمْزَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ اللَّهُمَّ الْعَنْ أَبَا سُفْيَانَ اللَّهُمَّ الْعَنْ الْحَارِثَ بْنَ هِشَامٍ اللَّهُمَّ الْعَنْ صَفْوَانَ بْنَ أُمَيَّةَ قَالَ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ }فَتَابَ اللَّهُ عَلَيْهِمْ فَأَسْلَمُوا فَحَسُنَ إِسْلَامُهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ يُسْتَغْرَبُ مِنْ حَدِيثِ عُمَرَ بْنِ حَمْزَةَ عَنْ سَالِمٍ عَنْ أَبِيهِ وَقَدْ رَوَاهُ الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِ لَمْ يَعْرِفْهُ مُحَمَّدُ بْنُ إِسْمَعِيلَ مِنْ حَدِيثِ عُمَرَ بْنِ حَمْزَةَ وَعَرَفَهُ مِنْ حَدِيثِ الزُّهْرِيِّ","trj":"Telah menceritakan kepada kami [Abu As Sa`ib Salm bin Junadah bin Salm Al Kufi] telah menceritakan kepada kami [Ahmad bin Basyir] dari [Umar bin Hamzah] dari [Salim bin Abdullah bin Umar] dari [Ayahnya] ia mengatakan; Rasulullah shallallahu 'alaihi wasallam pernah berdoa pada perang Uhud: \"Ya Allah, laknatlah Abu Sufyan, laknatlah Al Harits bin Hisyam, ya Allah, laknatlah Shafwan bin 'Umayyah.\" lalu turunlah ayat Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka. QS Ali Imran: 128, akan tetapi Allah mengampuni mereka, akhirnya mereka pun masuk Islam, dengan keIslaman yang baik.\" Abu Isa mengatakan bahwa hadits ini hasan gharib, dinilai asing dari hadits Umar bin Hamzah dari Salim dari Ayahnya, [Az Zuhri] telah meriwayatkan dari [Salim] dari [Ayahnya], namun Muhammad bin Isma'il tidak mengetahui dari Umar bin Hamzah, dan dia hanya mengetahui dari hadits Az Zuhri."},{"p":"Tirmidzi","n":2828,"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ الْبَصْرِيُّ حَدَّثَنَا خَالِدُ ابْنُ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو عَلَى أَرْبَعَةِ نَفَرٍ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }فَهَدَاهُمْ اللَّهُ لِلْإِسْلَامِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ يُسْتَغْرَبُ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ نَافِعٍ عَنْ ابْنِ عُمَرَ وَرَوَاهُ يَحْيَى بْنُ أَيُّوبَ عَنْ ابْنِ عَجْلَانَ","trj":"Telah menceritakan kepada kami [Yahya bin Habib bin 'Arabi Al Bashri] telah menceritakan kepada kami [Khalid bin Al Harits] dari [Muhammad bin 'Ajlan] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam mendakwahi empat orang, kemudian Allah menurunkan ayat; Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka karena sesungguhnya mereka itu orang-orang yang zhalim. QS Ali Imran: 128, lalu Allah memberi petunjuk mereka kepada Islam.\" Abu Isa berkata; Hadits in hasan gharib shahih dan dinilai gharib melalui sanad ini dari hadits Nafi' dari Ibnu Umar. [Yahya bin Ayub] juga meriwayatkannya dari [Ibnu 'Ajlan]."}],"3:135":[{"p":"Tirmidzi","n":2829,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَا��َةَ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ عَنْ عَلِيِّ بْنِ رَبِيعَةَ عَنْ أَسْمَاءَ بْنِ الْحَكَمِ الْفَزَارِيِّ قَال سَمِعْتُ عَلِيًّا يَقُولُإِنِّي كُنْتُ رَجُلًا إِذَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا نَفَعَنِي اللَّهُ مِنْهُ بِمَا شَاءَ أَنْ يَنْفَعَنِي وَإِذَا حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِهِ اسْتَحْلَفْتُهُ فَإِذَا حَلَفَ لِي صَدَّقْتُهُ وَإِنَّهُ حَدَّثَنِي أَبُو بَكْرٍ وَصَدَقَ أَبُو بَكْرٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ رَجُلٍ يُذْنِبُ ذَنْبًا ثُمَّ يَقُومُ فَيَتَطَهَّرُ ثُمَّ يُصَلِّي ثُمَّ يَسْتَغْفِرُ اللَّهَ إِلَّا غَفَرَ لَهُ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ{ وَالَّذِينَ إِذَا فَعَلُوا فَاحِشَةً أَوْ ظَلَمُوا أَنْفُسَهُمْ ذَكَرُوا اللَّهَ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ قَدْ رَوَاهُ شُعْبَةُ وَغَيْرُ وَاحِدٍ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَرَفَعُوهُ وَرَوَاهُ مِسْعَرٌ وَسُفْيَانُ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَلَمْ يَرْفَعَاهُ وَقَدْ رَوَاهُ بَعْضُهُمْ عَنْ مِسْعَرٍ فَأَوْقَفَهُ وَرَفَعَهُ بَعْضُهُمْ وَرَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَأَوْقَفَهُ وَلَا نَعْرِفُ لِأَسْمَاءَ بْنِ الْحَكَمِ حَدِيثًا إِلَّا هَذَا","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Utsman bin Al Mughirah] dari [Ali bin Rabi'ah] dari [Asma` bin Al Hakam Al Fazari] ia berkata; Aku mendengar [Ali] berkata; Aku adalah seseorang yang bila mendengar suatu hadits dari Rasulullah shallallahu 'alaihi wasallam, Allah memanfaatkanku darinya seperti yang Ia kehendaki dan bila seseorang sahabatku menceritakan kepadaku, aku memintanya bersumpah, bila ia bersumpah, aku membenarkannya. [Abu Bakar] pernah menceritakan kepadaku, sementara Abu Bakar adalah orang yang jujur, ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang melakukan suatu dosa, kemudian berdiri, wudhu lalu shalat, setelah itu ia meminta ampun kepada Allah melainkan pasti diampuni.\" Setelah itu Abu Bakar membaca ayat ini: Dan (juga) orang-orang yang apabila mengerjakan perbuatan keji atau menganiaya diri sendiri, mereka ingat akan Allah, lalu memohon ampun terhadap dosa-dosa mereka. QS Ali Imran: 135, hingga akhir ayat. Abu Isa berkata; Hadits ini diriwayatkan oleh [Syu'bah] dan beberapa orang dari [Utsman bin Al Mughirah] dan mereka memarfu'kannya. Diriwayatkan juga oleh [Mis'ar] dan [Sufyan] dari [Utsman bin Al Mughirah], tapi keduanya tidak memarfu'kannya. Sebagian lainnya meriwayatkannya dari Mis'ar dan memauqufkannya, sementara sebagian lainnya memarfu'kannya. Sufyan Ats Tsauri meriwayatkannya dari Utsman bin Al Mughirah lalu memauqufkannya. Kami tidak mengetahui hadits Amsa` bin Al Hakam selain hadits ini."}],"3:136":[{"p":"Muslim","n":1141,"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْفَزَارِيُّ يَعْنِي مَرْوَانَ بْنَ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ حَكِيمٍ الْأَنْصَارِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }الْآيَةَ الَّتِي فِي الْبَقَرَةِ وَفِي الْآخِرَةِ مِنْهُمَا{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Fazari yaitu Marwan bin Muawiyah] dari [Utsman bin Hakim Al Anshari], katanya; telah menceritakan kepadaku [Said bin Yasar] bahwa [Ibnu Abbas] mengabarinya; bahwa dalam dua raka'at fajar, tepatnya di raka'at pertama, Rasulullah shallallahu 'alaihi wasallam membaca \"Katakanlah, kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" QS. Albaqarah 136, dan pada rakaat kedua membaca \"Kami beriman kepada Allah, dan saksikanlah bahwa kami orang muslim.\" QS. Ali Imran 52."}],"3:161":[{"p":"Abu Dawud","n":3371,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا خُصَيْفٌ حَدَّثَنَا مِقْسَمٌ مَوْلَى ابْنِ عَبَّاسٍ قَالَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَانَزَلَتْ هَذِهِ الْآيَةُ{ وَمَا كَانَ لِنَبِيٍّ أَنْ يَغُلَّ }فِي قَطِيفَةٍ حَمْرَاءَ فُقِدَتْ يَوْمَ بَدْرٍ فَقَالَ بَعْضُ النَّاسِ لَعَلَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَهَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَمَا كَانَ لِنَبِيٍّ أَنْ يَغُلَّ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو دَاوُد يَغُلَّ مَفْتُوحَةُ الْيَاءِ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Khushaif] telah menceritakan kepada kami [Miqsam] mantan budak Ibnu Abbas, ia berkata, [Ibnu Abbas] radliallahu 'anhu berkata, \"Turunnya ayat ini: '(Tidak mungkin seorang nabi berkhianat dalam urusan harta rampasan perang) ' (Qs. Ali Imran: 161), berkenaan dengan hilangnya kasur merah di badar. Sebagian orang mengatakan, \"Kemungkinan Rasulullah shallallahu 'alaihi wasallam mengambilnya, maka Allah 'azza wajalla menurunkan ayat: '(Tidak mungkin seorang nabi berkhianat dalam urusan harta rampasan perang) ' (Qs. Ali Imran: 161), hingga akhir ayat.\" Abu Daud berkata, \"Yaghulla, dengan memberi harakat fathah pada huruf ya'.\""}],"3:163":[{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""},{"p":"Tirmidzi","n":3224,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ الْقَدَّاحِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ آلِ عِمْرَانَ{ الم اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidullah bin Abu Ziyad Al Qaddah] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Nama Allah Allah yang paling agung ada dalam kedua ayat ini, yaitu: \"Dan Tuhanmu adalah Tuhan Yang Maha Esa; tidak ada Tuhan melainkan Dia Yang Maha Pemurah lagi Maha Penyayang\", (QS. Albaqarah 163) dan permulaan Surat Ali Imran; \"Alif laam miim. Allah, tidak ada Tuhan (yang berhak disembah) melainkan Dia. Yang hidup kekal lagi terus menerus mengurus makhluk-Nya.\" (QS.Ali Imran 1-2), Abu Isa berkata; hadits ini adalah hadits hasan shahih."}],"3:165":[{"p":"Bukhari","n":1165,"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنِي مَعْمَرٌ وَيُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ قَالَتْأَقْبَلَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ عَلَى فَرَسِهِ مِنْ مَسْكَنِهِ بِالسُّنْحِ حَتَّى نَزَلَ فَدَخَلَ الْمَسْجِدَ فَلَمْ يُكَلِّمْ النَّاسَ حَتَّى دَخَلَ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَتَيَمَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُسَجًّى بِبُرْدِ حِبَرَةٍ فَكَشَفَ عَنْ وَجْهِهِ ثُمَّ أَكَبَّ عَلَيْهِ فَقَبَّلَهُ ثُمَّ بَكَى فَقَالَ بِأَبِي أَنْتَ يَا نَبِيَّ اللَّهِ لَا يَجْمَعُ اللَّهُ عَلَيْكَ مَوْتَتَيْنِ أَمَّا الْمَوْتَةُ الَّتِي كُتِبَتْ عَلَيْكَ فَقَدْ مُتَّهَاقَالَ أَبُو سَلَمَةَ فَأَخْبَرَنِي ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ خَرَجَ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُ يُكَلِّمُ النَّاسَ فَقَالَ اجْلِسْ فَأَبَى فَقَالَ اجْلِسْ فَأَبَى فَتَشَهَّدَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَمَالَ إِلَيْهِ النَّاسُ وَتَرَكُوا عُمَرَ فَقَالَ أَمَّا بَعْدُ فَمَنْ كَانَ مِنْكُمْ يَعْبُدُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ مَاتَ وَمَنْ كَانَ يَعْبُدُ اللَّهَ فَإِنَّ اللَّهَ حَيٌّ لَا يَمُوتُ قَالَ اللَّهُ تَعَالَى{ وَمَا مُحَمَّدٌ إِلَّا رَسُولٌ قَدْ خَلَتْ مِنْ قَبْلِهِ الرُّسُلُ إِلَى الشَّاكِرِينَ }وَاللَّهِ لَكَأَنَّ النَّاسَ لَمْ يَكُونُوا يَعْلَمُونَ أَنَّ اللَّهَ أَنْزَلَهَا حَتَّى تَلَاهَا أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَتَلَقَّاهَا مِنْهُ النَّاسُ فَمَا يُسْمَعُ بَشَرٌ إِلَّا يَتْلُوهَا","trj":"Telah menceritakan kepada kami [Bisyir bin Muhammad] telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada saya [Ma'mar] dan [Yunus] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Abu Salamah] bahwa ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya, katanya; [Abu Bakar] radliallahu 'anhu menunggang kudanya dari suatu tempat bernama Sunih hingga sampai dan masuk ke dalam masjid dan dia tidak berbicara dengan orang-orang, lalu dia menemui 'Aisyah radliallahu 'anha dan langsung mendatangi Nabi shallallahu 'alaihi wasallam yang sudah ditutupi (jasadnya) dengan kain terbuat dari katun. Kemudian dia membuka tutup wajah Beliau lalu Abu Bakar bersimpuh didepan jasad Nabi, lalu menutupnya kembali. Kemudian Abu Bakar menangis dan berkata: \"Demi bapak dan ibuku, wahai Nabi Allah, Allah tidak akan menjadikan kematian dua kali kepadamu. Adapun kematian pertama yang telah ditetapkan buatmu itu sudah terjadi\". Berkata, [Abu Salamah]; telah mengabarkan kepada saya [Ibnu 'Abbas] radliallahu 'anhuma bahwa; Kemudian [Abu Bakar] radliallahu 'anhu keluar bertepatan 'Umar radliallahu 'anhu sedang berbicara dengan orang banyak. Maka (Abu Bakar radliallahu 'anhu) berkata, kepada (\"Umar radliallahu 'anhu): \"Duduklah!\". Namun 'Umar tidak mempedulikannya. Lalu Abu Bakar berkata, lagi: \"Duduklah!\". Namun 'Umar tetap tidak mempedulikannya. Akhirnya Abu Bakar bersaksi (tentang kewafatan Nabi shallallahu 'alaihi wasallam) sehingga orang-orang berkumpul kepadanya dan meninggalkan 'Umar, lalu Abu Bakar berkata: \"Kemudian, barangsiapa dari kalian yang menyembah Muhammad shallallahu 'alaihi wasallam, sungguh Muhammad shallallahu 'alaihi wasallam sekarang sudah wafat dan barangsiapa dari kalian yang menyembah Allah, sungguh Allah Maha Hidup yang tidak akan pernah mati. Allah Ta'ala telah berfirman: (yang artinya): \"Dan Muhammad itu tidak lain kecuali hanyalah seorang rasul sebagaimana telah berlalu (mati) rasul-rasul sebelum dia\"..seterusnya hingga akhir ayat … Allah akan memberi balasan pahala bagi orang-orang yang bersyukur\" (QS. Ali'Imran 165). Demi Allah, seakan-akan orang-orang belum pernah mengetahui bahwa Allah sudah menurunkan ayat tersebut sampai Abu Bakar radliallahu 'anhu membacakannya. Akhirnya orang-orang memahaminya dan tidak ada satupun orang yang mendengarnya (wafatnya Nabi) kecuali pasti membacakannya\"."}],"3:169":[{"p":"Muslim","n":3260,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ وَعِيسَى بْنُ يُونُسَ جَمِيعًا عَنْ الْأَعْمَشِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَسْبَاطٌ وَأَبُو مُعَاوِيَةَ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ قَالَسَأَلْنَا عَبْدَ اللَّهِ عَنْ هَذِهِ الْآيَةِ{ وَلَا تَحْسَبَنَّ الَّذِينَ قُتِلُوا فِي سَبِيلِ اللَّهِ أَمْوَاتًا بَلْ أَحْيَاءٌ عِنْدَ رَبِّهِمْ يُرْزَقُونَ }قَالَ أَمَا إِنَّا قَدْ سَأَلْنَا عَنْ ذَلِكَ فَقَالَ أَرْوَاحُهُمْ فِي جَوْفِ طَيْرٍ خُضْرٍ لَهَا قَنَادِيلُ مُعَلَّقَةٌ بِالْعَرْشِ تَسْرَحُ مِنْ الْجَنَّةِ حَيْثُ شَاءَتْ ثُمَّ تَأْوِي إِلَى تِلْكَ الْقَنَادِيلِ فَاطَّلَعَ إِلَيْهِمْ رَبُّهُمْ اطِّلَاعَةً فَقَالَ هَلْ تَشْتَهُونَ شَيْئًا قَالُوا أَيَّ شَيْءٍ نَشْتَهِي وَنَحْنُ نَسْرَحُ مِنْ الْجَنَّةِ حَيْثُ شِئْنَا فَفَعَلَ ذَلِكَ بِهِمْ ثَلَاثَ مَرَّاتٍ فَلَمَّا رَأَوْا أَنَّهُمْ لَنْ يُتْرَكُوا مِنْ أَنْ يُسْأَلُوا قَالُوا يَا رَبِّ نُرِيدُ أَنْ تَرُدَّ أَرْوَاحَنَا فِي أَجْسَادِنَا حَتَّى نُقْتَلَ فِي سَبِيلِكَ مَرَّةً أُخْرَى فَلَمَّا رَأَى أَنْ لَيْسَ لَهُمْ حَاجَةٌ تُرِكُوا","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dan [Isa bin Yunus] semuanya dari [Al A'masy]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] sedangkan lafadznya dari dia, telah menceritakan kepada kami [Asbath] dan [Abu Mu'awiyah] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dia berkata, \"Kami pernah bertanya kepada [Abdullah] perihal ayat ini: '(Dan janganlah kalian mengira bahwa orang-orang yang terbunuh di jalan Allah itu (memang) mati, akan tetapi sebenarnya mereka itu hidup di sisi Rabb mereka dan diberi rezeki (yang melimpah) ' (Qs. Ali Imran: 169) Dia berkata, \"Kami dulu pernah menanyakan hal itu, dan beliau menjawab: \"Ruh mereka berada di dalam rongga burung hijau yang mempunyai banyak pelita yang bergantungan di 'Arsy, ia dapat keluar masuk surga sesuka hati kemudian beristirahat lagi di pelita-pelita itu, kemudian Rabb mereka menengok mereka seraya berkata: 'Apakah kalian menginginkan sesuatu? ' Mereka menjawab, 'Apa lagi yang kami inginkan kalau kami sudah dapat keluar masuk ke surga sesuka hati kami? ' Lalu Allah terus mengulangi pertanyaan itu hingga tiga kali. Ketika mereka melihat kalau mereka tidak akan ditinggalkan sebelum menjawab pertanyaan itu, maka merekapun menjawab, 'Duhai Rabb, kami menginginkan ruh kami dikembalikan lagi ke jasad kami hingga kami dapat berperang lagi di jalan-Mu untuk kesekian kalinya.' Ketika Allah melihat kalau mereka tidak lagi membutuhkan sesuatu, akhirnya mereka ditinggal pergi.\""}],"3:172":[{"p":"Bukhari","n":3566,"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ الَّذِينَ اسْتَجَابُوا لِلَّهِ وَالرَّسُولِ مِنْ بَعْدِ مَا أَصَابَهُمْ الْقَرْحُ لِلَّذِينَ أَحْسَنُوا مِنْهُمْ وَاتَّقَوْا أَجْرٌ عَظِيمٌ }قَالَتْ لِعُرْوَةَ يَا ابْنَ أُخْتِي كَانَ أَبَوَاكَ مِنْهُمْ الزُّبَيْرُ وَأَبُو بَكْرٍ لَمَّا أَصَابَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَصَابَ يَوْمَ أُحُدٍ وَانْصَرَفَ عَنْهُ الْمُشْرِكُونَ خَافَ أَنْ يَرْجِعُوا قَالَ مَنْ يَذْهَبُ فِي إِثْرِهِمْ فَانْتَدَبَ مِنْهُمْ سَبْعُونَ رَجُلًا قَالَ كَانَ فِيهِمْ أَبُو بَكْرٍ وَالزُّبَيْرُ","trj":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam] dari [Ayahnya] dari ['Aisyah] radliallahu 'anha mengenai ayat: '((yaitu) orang-orang yang mentaati perintah Allah dan rasul-Nya sesudah mereka mendapat luka (dalam peperangan Uhud). bagi orang-orang yang berbuat kebaikan diantara mereka dan yang bertakwa ada pahala yang besar) ' (Qs. Ali Imran: 172). Aisyah berkata kepada 'Urwah, \"Wahai keponakanku, sesungguhnya ayahmu termasuk dari mereka (yang diterangkan dalam ayat), yaitu Az Zubair dan Abu Bakr. Ketika Rasulullah Shallallahu 'alahi wasallam terluka pada perang Uhud, disaat beliau khawatir kaum Musyrikin yang telah pergi akan kembali, beliau bersabda: \"Siapakah yang akan mengintai mereka?\", lalu beliau memilih tujuh puluh orang.\" Perawi berkata, \"Termasuk diantara mereka adalah Abu Bakr dan Az Zubair.\""}],"3:185":[{"p":"Tirmidzi","n":3043,"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَعَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ وَاقْرَءُوا إِنْ شِئْتُمْ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }وَفِي الْجَنَّةِ شَجَرَةٌ يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ وَظِلٍّ مَمْدُودٍ }وَمَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ فَمَنْ زُحْزِحَ عَنْ النَّارِ وَأُدْخِلَ الْجَنَّةَ فَقَدْ فَازَ وَمَا الْحَيَاةُ الدُّنْيَا إِلَّا مَتَاعُ الْغُرُورِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Bismillahirrahmanirrahim. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami ['Abdah bin Sulaiman] serta [Abdur Rahim bin Sulaiman] dari [Muhammad bin 'Amr], ia berkata; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah berfirman: \"Aku telah mempersiapkan bagi para hambaku yang shalih, apa yang belum pernah dilihat mata, belum pernah didengar telinga, dan tidak terlintas dalam hati manusia.\" Apabila kalian kehendaki maka bacalah: \"Tak seorangpun mengetahui berbagai nikmat yang dirahasiakan bagi mereka, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan.\" (QS. Assajdah 17), Di Surga terdapat pohon yang mana seorang pengendara berjalan di bawah naungannya selama seratus tahun tidak mampu menyeberanginya. Apabila kalian menghendaki maka bacalah: \"Dan naungan yang terbentang luas\" (QS. Alwaqi'ah 30), Dan tempat cemeti di Surga lebih baik daripada dunia dan seisinya. Apabila kalian menghendaki maka bacalah: \"Barangsiapa dijauhkan dari neraka dan dimasukkan ke dalam syurga, maka sungguh ia telah beruntung. Kehidupan dunia itu tidak lain hanyalah kesenangan yang memperdayakan.\" (QS. Ali'Imran 185), Abu Isa berkata: hadits ini adalah hadits hasan shahih."}],"3:187":[{"p":"Muslim","n":4627,"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ وَاللَّفْظُ لِزُهَيْرٍ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَخْبَرَهُأَنَّ مَرْوَانَ قَالَ اذْهَبْ يَا رَافِعُ لِبَوَّابِهِ إِلَى ابْنِ عَبَّاسٍ فَقُلْ لَئِنْ كَانَ كُلُّ امْرِئٍ مِنَّا فَرِحَ بِمَا أَتَى وَأَحَبَّ أَنْ يُحْمَدَ بِمَا لَمْ يَفْعَلْ مُعَذَّبًا لَنُعَذَّبَنَّ أَجْمَعُونَ فَقَالَ ابْنُ عَبَّاسٍ مَا لَكُمْ وَلِهَذِهِ الْآيَةِ إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي أَهْلِ الْكِتَابِ ثُمَّ تَلَا ابْنُ عَبَّاسٍ{ وَإِذْ أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ }هَذِهِ الْآيَةَ وَتَلَا ابْنُ عَبَّاسٍ{ لَا تَحْسَبَنَّ الَّذِينَ يَفْرَحُونَ بِمَا أَتَوْا وَيُحِبُّونَ أَنْ يُحْمَدُوا بِمَا لَمْ يَفْعَلُوا }وَقَالَ ابْنُ عَبَّاسٍ سَأَلَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَيْءٍ فَكَتَمُوهُ إِيَّاهُ وَأَخْبَرُوهُ بِغَيْرِهِ فَخَرَجُوا قَدْ أَرَوْهُ أَنْ قَدْ أَخْبَرُوهُ بِمَا سَأَلَهُمْ عَنْهُ وَاسْتَحْمَدُوا بِذَلِكَ إِلَيْهِ وَفَرِحُوا بِمَا أَتَوْا مِنْ كِتْمَانِهِمْ إِيَّاهُ مَا سَأَلَهُمْ عَنْهُ","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Harun bin 'Abdullah] -dan lafadh ini milik Zuhair- mereka berdua berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij]; telah mengabarkan kepadaku [Ibnu Abu Malikah] bahwasanya [Humaid bin 'Abdurrahman bin 'Auf] mengabarkan kepadanya bahwasanya Marwan berkata; \"Wahai Abu Rafi', katakan kepada kepada penjaga pintu agar dia pergi menemui Ibnu Abbas, tanyakan kepadanya; 'Apabila setiap orang dari kita yang merasa senang dengan apa yang dia kerjakan dan yang menyukai untuk dipuji terhadap apa yang belum dia kerjakan akan di adzab, dengan demikian berarti kita semua akan di adzab? [Ibnu Abbas] berkata; 'Apa hubungannya kalian dengan ayat ini? ' Ayat ini hanya di turunkan mengenai Ahlu kitab. Lalu Ibnu Abbas membaca ayat; \"Dan (ingatlah), ketika Allah mengambil janji dari orang-orang yang telah diberi (yaitu), \"Hendaklah kamu benar-benar menerangkannya (isi kitab itu) kepada manusia dan janganlah kamu menyembunyikannya. (QS. Ali Imran 187) \" Dan Ibnu Abbas membaca ayat; \"Dan janganlah sekali-kali kamu mengira bahwa orang yang gembira dengan apa yang telah mereka kerjakan dan mereka suka dipuji atas perbuatan yang tidak mereka lakukan. (QS. Ali'Imran 188) \" Ibnu Abbas berkata; Yaitu ketika nabi shallallahu 'alaihi wasallam menanyakan kepada mereka tentang sesuatu, namun mereka menyembunyikannya dan mengabarkan hal yang lain. Lalu mereka keluar. Sungguh aku melihat beliau diberitahu tentang yang beliau tanyakan kepada mereka hingga mereka ingin dipuji dengan apa yang telah mereka kabarkan itu dan mereka senang dengan apa yang telah mereka kerjakan dari menyembunyikan sesuatu yang beliau tanyakan.'"}],"3:188":[{"p":"Muslim","n":4627,"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ وَاللَّفْظُ لِزُهَيْرٍ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَخْبَرَهُأَنَّ مَرْوَانَ قَالَ اذْهَبْ يَا رَافِعُ لِبَوَّابِهِ إِلَى ابْنِ عَبَّاسٍ فَقُلْ لَئِنْ كَانَ كُلُّ امْرِئٍ مِنَّا فَرِحَ بِمَا أَتَى وَأَحَبَّ أَنْ يُحْمَدَ بِمَا لَمْ يَفْعَلْ مُعَذَّبًا لَنُعَذَّبَنَّ أَجْمَعُونَ فَقَالَ ابْنُ عَبَّاسٍ مَا لَكُمْ وَلِهَذِهِ الْآيَةِ إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي أَهْلِ الْكِتَابِ ثُمَّ تَلَا ابْنُ عَبَّاسٍ{ وَإِذْ أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ }هَذِهِ الْآيَةَ وَتَلَا ابْنُ عَبَّاسٍ{ لَا تَحْسَبَنَّ الَّذِينَ يَفْرَحُونَ بِمَا أَتَوْا وَيُحِبُّونَ أَنْ يُحْمَدُوا بِمَا لَمْ يَفْعَلُوا }وَقَالَ ابْنُ عَبَّاسٍ سَأَلَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَيْءٍ فَكَتَمُوهُ إِيَّاهُ وَأَخْبَرُوهُ بِغَيْرِهِ فَخَرَجُوا قَدْ أَرَوْهُ أَنْ قَدْ أَخْبَرُوهُ بِمَا سَأَلَهُمْ عَنْهُ وَاسْتَحْمَدُوا بِذَلِكَ إِلَيْهِ وَفَرِحُوا بِمَا أَتَوْا مِنْ كِتْمَانِهِمْ إِيَّاهُ مَا سَأَلَهُمْ عَنْهُ","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Harun bin 'Abdullah] -dan lafadh ini milik Zuhair- mereka berdua berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij]; telah mengabarkan kepadaku [Ibnu Abu Malikah] bahwasanya [Humaid bin 'Abdurrahman bin 'Auf] mengabarkan kepadanya bahwasanya Marwan berkata; \"Wahai Abu Rafi', katakan kepada kepada penjaga pintu agar dia pergi menemui Ibnu Abbas, tanyakan kepadanya; 'Apabila setiap orang dari kita yang merasa senang dengan apa yang dia kerjakan dan yang menyukai untuk dipuji terhadap apa yang belum dia kerjakan akan di adzab, dengan demikian berarti kita semua akan di adzab? [Ibnu Abbas] berkata; 'Apa hubungannya kalian dengan ayat ini? ' Ayat ini hanya di turunkan mengenai Ahlu kitab. Lalu Ibnu Abbas membaca ayat; \"Dan (ingatlah), ketika Allah mengambil janji dari orang-orang yang telah diberi (yaitu), \"Hendaklah kamu benar-benar menerangkannya (isi kitab itu) kepada manusia dan janganlah kamu menyembunyikannya. (QS. Ali Imran 187) \" Dan Ibnu Abbas membaca ayat; \"Dan janganlah sekali-kali kamu mengira bahwa orang yang gembira dengan apa yang telah mereka kerjakan dan mereka suka dipuji atas perbuatan yang tidak mereka lakukan. (QS. Ali'Imran 188) \" Ibnu Abbas berkata; Yaitu ketika nabi shallallahu 'alaihi wasallam menanyakan kepada mereka tentang sesuatu, namun mereka menyembunyikannya dan mengabarkan hal yang lain. Lalu mereka keluar. Sungguh aku melihat beliau diberitahu tentang yang beliau tanyakan kepada mereka hingga mereka ingin dipuji dengan apa yang telah mereka kabarkan itu dan mereka senang dengan apa yang telah mereka kerjakan dari menyembunyikan sesuatu yang beliau tanyakan.'"}],"3:190":[{"p":"Bukhari","n":6543,"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنِي شَرِيكُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ فِي بَيْتِ مَيْمُونَةَ لَيْلَةً وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا لِأَنْظُرَ كَيْفَ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَتَحَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَهْلِهِ سَاعَةً ثُمَّ رَقَدَ فَلَمَّا كَانَ ثُلُثُ اللَّيْلِ الْآخِرُ أَوْ بَعْضُهُ قَعَدَ فَنَظَرَ إِلَى السَّمَاءِ فَقَرَأَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ إِلَى قَوْلِهِ لِأُولِي الْأَلْبَابِ }ثُمَّ قَامَ فَتَوَضَّأَ وَاسْتَنَّ ثُمَّ صَلَّى إِحْدَى عَشْرَةَ رَكْعَةً ثُمَّ أَذَّنَ بِلَالٌ بِالصَّلَاةِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى لِلنَّاسِ الصُّبْحَ","trj":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] telah mengabarkan kepadaku [Syarik bin Abdullah bin Abu Namir] dari [Kuraib] dari [Ibn Abbas] mengatakan, \"Suatu malam aku bermalam di rumah maimunah sedang Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam di sisinya, itu kulakukan dengan niat agar aku bisa melihat Shalat Rasulullah Shallallahu'alaihiwasallam ketika malam. Rasulullah Shallallahu'alaihiwasallam berbincang-bincang bersama isterinya beberapa saat, kemudian tidur, ketika sepertiga malam terakhir tiba, atau sebagiannya, beliau duduk dan menatap langit lantas membaca ayat: '(Sesungguhnya dalam penciptaan langit dan bumi hingga ayat terdapat tanda-tanda bagi orang yang berakal) ' (QS. Ali'Imran: 190). Kemudian beliau berdiri dan berwudlu', beliau membersihkan gigi-giginya kemudian shalat sebelas rakaat. Kemudian setelah Bilal mengumandangkan adzan (subuh), beliau shalat dua rakaat, kemudian keluar untuk mengimami orang-orang shalat subuh.\""}],"3:191":[{"p":"Muslim","n":369,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو الْمُتَوَكِّلِ أَنَّ ابْنَ عَبَّاسٍ حَدَّثَهُأَنَّهُ بَاتَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَقَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ آخِرِ اللَّيْلِ فَخَرَجَ فَنَظَرَ فِي السَّمَاءِ ثُمَّ تَلَا هَذِهِ الْآيَةَ فِي آلِ عِمْرَانَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ حَتَّى بَلَغَ فَقِنَا عَذَابَ النَّارِ }ثُمَّ رَجَعَ إِلَى الْبَيْتِ فَتَسَوَّكَ وَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى ثُمَّ اضْطَجَعَ ثُمَّ قَامَ فَخَرَجَ فَنَظَرَ إِلَى السَّمَاءِ فَتَلَا هَذِهِ الْآيَةَ ثُمَّ رَجَعَ فَتَسَوَّكَ فَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى","trj":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ismail bin Muslim] telah menceritakan kepada kami [Abu al-Mutawakkil] bahwa [Ibnu Abbas] telah menceritakan kepadanya, bahwa dia bermalam di sisi Nabi shallallahu 'alaihi wasallam pada suatu malam, maka Rasulullah bangun di akhir malam dan keluar, lalu beliau melihat di langit seraya membaca ayat ini pada surat Ali Imran: '(Sesungguhnya dalam penciptaan langit langit dan bumi, dan silih bergantinya malam dan siang terdapat tanda-tanda bagi orang-orang yang berakal, (yaitu) orang-orang yang mengingat Allah sambil berdiri atau duduk atau dalam keadaan berbaring dan mereka memikirkan tentang penciptaan langit dan bumi (seraya berkata), 'Ya Rabb kami, tiadalah Engkau menciptakan ini dengan sia-sia Maha Suci Engkau, maka peliharalah kami dari siksa neraka) ' (Qs. Ali Imran: 191-192). Kemudian beliau kembali pulang ke rumah, beliau lalu bersiwak, berwudlu, lalu berdiri shalat. Setelah itu beliau berbaring, kemudian berdiri keluar melihat langit lalu membaca ayat ini lagi. Kemudian beliau kembali bersiwak dan wudlu, lalu berdiri melaksanakan shalat.\""}],"3:192":[{"p":"Muslim","n":277,"ar":"و حَدَّثَنَا حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا أَبُو عَاصِمٍ يَعْنِي مُحَمَّدَ بْنَ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ الْفَقِيرُ قَالَكُنْتُ قَدْ شَغَفَنِي رَأْيٌ مِنْ رَأْيِ الْخَوَارِجِ فَخَرَجْنَا فِي عِصَابَةٍ ذَوِي عَدَدٍ نُرِيدُ أَنْ نَحُجَّ ثُمَّ نَخْرُجَ عَلَى النَّاسِ قَالَ فَمَرَرْنَا عَلَى الْمَدِينَةِ فَإِذَا جَابِرُ بْنُ عَبْدِ اللَّهِ يُحَدِّثُ الْقَوْمَ جَالِسٌ إِلَى سَارِيَةٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِذَا هُوَ قَدْ ذَكَرَ الْجَهَنَّمِيِّينَ قَالَ فَقُلْتُ لَهُ يَا صَاحِبَ رَسُولِ اللَّهِ مَا هَذَا الَّذِي تُحَدِّثُونَ وَاللَّهُ يَقُولُ{ إِنَّكَ مَنْ تُدْخِلْ النَّارَ فَقَدْ أَخْزَيْتَهُ }وَ{ كُلَّمَا أَرَادُوا أَنْ يَخْرُجُوا مِنْهَا أُعِيدُوا فِيهَا }فَمَا هَذَا الَّذِي تَقُولُونَ قَالَ فَقَالَ أَتَقْرَأُ الْقُرْآنَ قُلْتُ نَعَمْ قَالَ فَهَلْ سَمِعْتَ بِمَقَامِ مُحَمَّدٍ عَلَيْهِ السَّلَام يَعْنِي الَّذِي يَبْعَثُهُ اللَّهُ فِيهِ قُلْتُ نَعَمْ قَالَ فَإِنَّهُ مَقَامُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَحْمُودُ الَّذِي يُخْرِجُ اللَّهُ بِهِ مَنْ يُخْرِجُ قَالَ ثُمَّ نَعَتَ وَضْعَ الصِّرَاطِ وَمَرَّ النَّاسِ عَلَيْهِ قَالَ وَأَخَافُ أَنْ لَا أَكُونَ أَحْفَظُ ذَاكَ قَالَ غَيْرَ أَنَّهُ قَدْ زَعَمَ أَنَّ قَوْمًا يَخْرُجُونَ مِنْ النَّارِ بَعْدَ أَنْ يَكُونُوا فِيهَا قَالَ يَعْنِي فَيَخْرُجُونَ كَأَنَّهُمْ عِيدَانُ السَّمَاسِمِ قَالَ فَيَدْخُلُونَ نَهَرًا مِنْ أَنْهَارِ الْجَنَّةِ فَيَغْتَسِلُونَ فِيهِ فَيَخْرُجُونَ كَأَنَّهُمْ الْقَرَاطِيسُفَرَجَعْنَا قُلْنَا وَيْحَكُمْ أَتُرَوْنَ الشَّيْخَ يَكْذِبُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَجَعْنَا فَلَا وَاللَّهِ مَا خَرَجَ مِنَّا غَيْرُ رَجُلٍ وَاحِدٍ أَوْ كَمَا قَالَ أَبُو نُعَيْمٍ","trj":"Dan telah menceritakan kepada kami [Hajjaj bin asy-Syair] telah menceritakan kepada kami [al-Fadll bin Dukain] telah menceritakan kepada kami [Abu 'Ashim] -yaitu Muhammad bin Abu Ayyub- dia berkata, telah menceritakan kepadaku [Yazid al-Faqir] dia berkata, \"Dahulu aku telah terpengaruh dengan pemikiran Khawarij, kemudian kami keluar dalam sebuah rombongan besar untuk melaksanakan haji. Ketika kami keluar dan melewati madinah, ternyata [Jabir bin Abdullah] sedang menceritakan hadits Rasulullah shallallahu 'alaihi wasallam kepada suatu kaum sambil bersandar pada sebuah tiang.\" Yazil al Faqir berkata lagi, \"Tiba-tiba dia menyebutkan al-Jahannamiyyin.\" Maka aku pun berkata kepadanya, 'Wahai sahabat Rasulullah, apa-apaan yang kau ceritakan! Padahal Allah berfirman: '(Sesungguhnya barangsiapa yang Kamu masukkan ke dalam neraka, maka sungguh kamu telah menghinakannya) ' (Qs. Ali Imran: 192), dan ayat: '(Setiap kali mereka berkeinginan untuk keluar darinya, niscaya mereka dikembalikan ke dalamnya) ' (Qs. As-Sajadah: 20). Apa yang kalian katakan ini? ' Jabir menjawab, 'Apakah kalian membaca al-Qur'an? ' Kami menjawab, 'Ya.' Jabir bertanya lagi, 'Apakah kamu mendengar kedudukan Muhammad shallallahu 'alaihi wasallam, yaitu memberikan syafa'at yang mana Allah mengutusnya di dalamnya? ' Aku menjawab, 'Ya.' Jbir lalu berkata, 'Maka itulah kedudukan Muhammad shallallahu 'alaihi wasallam yang terpuji, dengannya Allah mengeluarkan orang yang dia keluarkan (dari neraka).' Yazid berkata, 'Kemudian Jabir memperagakan peletakan shirath, dan manusia lewat di atasnya.' Kata Yazid, 'Dan aku sangat khawatir tidak selamat dari hal tersebut. Hanya saja Jabir tetap berkeyakinan bahwa sekelompok kaum pasti akan keluar dari neraka, setelah mereka tinggal beberapa lama.' Kata Jabir, 'Maksudnya mereka keluar seakan-akan tongkat arang yang hitam kelam.' Kata Jabir meneruskan, 'Lalu mereka masuki salah satu sungai surga, mereka mandi di dalamnya, mereka keluar dari sungai seakan-akan kertas (putih), dan kami pun pulang.' Kami berkata, 'Celaka kalian, apakah kalian taksir bahwa syaikh ini berdusta atas nama Rasulullah shallallahu 'alaihi wasallam!.' Kami pun kembali, demi Allah, tidak ada yang keluar dari kami melainkan hanya satu orang atau sebagaimana yang diucapkan Abu Na'im.\""},{"p":"Muslim","n":369,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو الْمُتَوَكِّلِ أَنَّ ابْنَ عَبَّاسٍ حَدَّثَهُأَنَّهُ بَاتَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَقَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ آخِرِ اللَّيْلِ فَخَرَجَ فَنَظَرَ فِي السَّمَاءِ ثُمَّ تَلَا هَذِهِ الْآيَةَ فِي آلِ عِمْرَانَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ حَتَّى بَلَغَ فَقِنَا عَذَابَ النَّارِ }ثُمَّ رَجَعَ إِلَى الْبَيْتِ فَتَسَوَّكَ وَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى ثُمَّ اضْطَجَعَ ثُمَّ قَامَ فَخَرَجَ فَنَظَرَ إِلَى السَّمَاءِ فَتَلَا هَذِهِ الْآيَةَ ثُمَّ رَجَعَ فَتَسَوَّكَ فَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى","trj":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ismail bin Muslim] telah menceritakan kepada kami [Abu al-Mutawakkil] bahwa [Ibnu Abbas] telah menceritakan kepadanya, bahwa dia bermalam di sisi Nabi shallallahu 'alaihi wasallam pada suatu malam, maka Rasulullah bangun di akhir malam dan keluar, lalu beliau melihat di langit seraya membaca ayat ini pada surat Ali Imran: '(Sesungguhnya dalam penciptaan langit langit dan bumi, dan silih bergantinya malam dan siang terdapat tanda-tanda bagi orang-orang yang berakal, (yaitu) orang-orang yang mengingat Allah sambil berdiri atau duduk atau dalam keadaan berbaring dan mereka memikirkan tentang penciptaan langit dan bumi (seraya berkata), 'Ya Rabb kami, tiadalah Engkau menciptakan ini dengan sia-sia Maha Suci Engkau, maka peliharalah kami dari siksa neraka) ' (Qs. Ali Imran: 191-192). Kemudian beliau kembali pulang ke rumah, beliau lalu bersiwak, berwudlu, lalu berdiri shalat. Setelah itu beliau berbaring, kemudian berdiri keluar melihat langit lalu membaca ayat ini lagi. Kemudian beliau kembali bersiwak dan wudlu, lalu berdiri melaksanakan shalat.\""}],"3:195":[{"p":"Tirmidzi","n":2836,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ رَجُلٍ مِنْ وَلَدِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْيَا رَسُولَ اللَّهِ لَا أَسْمَعُ اللَّهَ ذَكَرَ النِّسَاءَ فِي الْهِجْرَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ أَنِّي لَا أُضِيعُ عَمَلَ عَامِلٍ مِنْكُمْ مِنْ ذَكَرٍ أَوْ أُنْثَى بَعْضُكُمْ مِنْ بَعْضٍ }","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [seseorang] anak Ummu Salamah, dari [Ummu Salamah] ia berkata; \"Wahai Rasulullah, aku tidak mendengar Allah menyebut kaum wanita dalam hijrah.\" Lalu Allah Ta'ala menurunkan Maka Rabb mereka memperkenankan permohonannya (dengan berfirman): 'Sesungguhnya Aku tidak menyia-nyiakan amal orang-orang yang beramal di antara kamu, baik laki-laki atau perempuan, (karena) sebagian kamu adalah turunan dari sebagian yang lain. QS Ali Imran: 195."}],"3:200":[{"p":"Malik","n":849,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَ كَتَبَ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ إِلَى عُمَرَ بْنِ الْخَطَّابِيَذْكُرُ لَهُ جُمُوعًا مِنْ الرُّومِ وَمَا يَتَخَوَّفُ مِنْهُمْ فَكَتَبَ إِلَيْهِ عُمَرُ بْنُ الْخَطَّابِ أَمَّا بَعْدُ فَإِنَّهُ مَهْمَا يَنْزِلْ بِعَبْدٍ مُؤْمِنٍ مِنْ مُنْزَلِ شِدَّةٍ يَجْعَلْ اللَّهُ بَعْدَهُ فَرَجًا وَإِنَّهُ لَنْ يَغْلِبَ عُسْرٌ يُسْرَيْنِ وَأَنَّ اللَّهَ تَعَالَى يَقُولُ فِي كِتَابِهِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اصْبِرُوا وَصَابِرُوا وَرَابِطُوا وَاتَّقُوا اللَّهَ لَعَلَّكُمْ تُفْلِحُونَ }","trj":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] berkata; \"Abu Ubaidah bin Al Jarrah menulis surat kepada Umar bin Al Khattab tentang jumlah pasukan Ramawi dan ketakutan (kaum muslimin) terhadap mereka. Lalu [Umar bin Khattab] membalas kepadanya; \"Amma ba'du: Sekiranya turun penderitaan kepada seorang hamba yang beriman, niscaya Allah akan menjadikan kemudahan setelah itu. Sesungguhnya satu kesulitan tidak akan bisa mengalahkan dua kemudahan, Allah berfirman dalam kitab-Nya: '(Hai orang-orang yang beriman, Bersabarlah kamu dan kuatkanlah kesabaranmu dan tetaplah bersiap siaga (di perbatasan negerimu) dan bertakwalah kepada Allah, supaya kamu beruntung) ' (Qs. Ali Imran: 200)"}]},"mapping_surah":[{"p":"Abu Dawud","n":726,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ عَاصِمِ بْنِ حُمَيْدٍ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَقُمْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَقَامَ فَقَرَأَ سُورَةَ الْبَقَرَةِ لَا يَمُرُّ بِآيَةِ رَحْمَةٍ إِلَّا وَقَفَ فَسَأَلَ وَلَا يَمُرُّ بِآيَةِ عَذَابٍ إِلَّا وَقَفَ فَتَعَوَّذَ قَالَ ثُمَّ رَكَعَ بِقَدْرِ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ سَجَدَ بِقَدْرِ قِيَامِهِ ثُمَّ قَالَ فِي سُجُودِهِ مِثْلَ ذَلِكَ ثُمَّ قَامَ فَقَرَأَ بِآلِ عِمْرَانَ ثُمَّ قَرَأَ سُورَةً سُورَةً","trj":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari ['Amru bin Qais] dari ['Ashim bin Humaid] dari ['Auf bin Malik Al Asyja'i] dia berkata; \"Di suatu malam, aku mengerjakan shalat bersama Rasulullah shallallahu 'alaihi wasallam, beliau kemudian berdiri dan membaca surat Al Baqarah, tidaklah beliau melewati ayat tentang rahmat, pasti beliau berhenti dan memohon kepada-Nya, dan tidaklah melewati ayat tentang adzab, melainkan beliau berhenti dan meminta perlindungan darinya.\" katanya melanjutkan; \"Kemudian beliau ruku' yang lamanya seperti beliau berdiri, dalam ruku'nya beliau mengucapkan: \"subahaana dzil jabaruuti wal malakuuti wal kibriyaa`i wal 'azhamati (Maha suci dzat yang memiliki sifat kekuasaan, kerajaan, kebesaran dan keagungan).\" Kemudian beliau sujud yang lamanya seperti beliau berdiri, dalam sujudnya beliau mengucapkan seperti itu juga, sesudah itu beliau berdiri, lalu membaca surat Ali Imran, kemudian membaca surat demi surat.\""},{"p":"Abu Dawud","n":989,"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدٍ حَدَّثَنَا عَمِّي حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ حَدَّثَنِي هِشَامُ بْنُ عُرْوَةَ وَعَبْدُ اللَّهِ بْنُ أَبِي سَلَمَةَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ كُلُّهُمْ قَدْ حَدَّثَنِي عَنْ عُرْوَةَ عَنْ عَائِش��ةَ قَالَتْكُسِفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ فَقَامَ فَحَزَرْتُ قِرَاءَتَهُ فَرَأَيْتُ أَنَّهُ قَرَأَ بِسُورَةِ الْبَقَرَةِ وَسَاقَ الْحَدِيثَ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَأَطَالَ الْقِرَاءَةَ فَحَزَرْتُ قِرَاءَتَهُ أَنَّهُ قَرَأَ بِسُورَةِ آلِ عِمْرَانَ","trj":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'd] telah menceritakan kepada kami [pamanku] telah menceritakan kepada kami [ayahku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Hisyam bin 'Urwah] dan [Abdullah bin Abu Salamah] dari [Sulaiman bin Yasar], semuanya telah menceritakan kepadaku, dari ['Urwah] dari [Aisyah] dia berkata; \"Terjadi gerhana Matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam keluar untuk mengerjakan shalat bersama orang-orang, setelah itu beliau berdiri. Maka aku memperkirakan bacaan beliau, bahwa beliau membaca surat Al Baqarah …\" kemudian dia melanjutkan hadits tersebut -\"lalu beliau sujud dua kali, kemudian beliau berdiri dan memanjangkan bacaannya, maka aku memperkirakan bacaan beliau, bahwa beliau membaca surat Ali Imran.\""},{"p":"Abu Dawud","n":1053,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ كَثِيرًا مِمَّا كَانَ يَقْرَأُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَكْعَتَيْ الْفَجْرِ بِ{ آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }هَذِهِ الْآيَةُ قَالَ هَذِهِ فِي الرَّكْعَةِ الْأُولَى وَفِي الرَّكْعَةِ الْآخِرَةِ بِ{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Utsman bin Hakim] telah menceritakan kepadaku [Sa'id bin Yasar] dari [Abdullah bin Abbas] bahwa kebanyakan yang di baca Rasulullah shallallahu 'alaihi wasallam dalam dua raka'at fajar adalah \"Kami beriman kepada Allah dan apa yang diturunkan kepada kami\" (QS Al Baqarah; 136). Kata Ibnu Abbas; \"ayat ini di baca beliau di raka'at pertama, sedangkan di raka'at terakhir beliau membaca \"……kami beriman kepada Allah; dan saksikanlah bahwa Sesungguhnya kami adalah orang-orang yang berserah diri.\" (QS Ali Imran; 52). "},{"p":"Abu Dawud","n":1054,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ بْنِ سُفْيَانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عُثْمَانَ بْنِ عُمَرَ يَعْنِي ابْنَ مُوسَى عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ{ قُلْ آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ عَلَيْنَا }فِي الرَّكْعَةِ الْأُولَى وَفِي الرَّكْعَةِ الْأُخْرَى بِهَذِهِ الْآيَةِ{ رَبَّنَا آمَنَّا بِمَا أَنْزَلْتَ وَاتَّبَعْنَا الرَّسُولَ فَاكْتُبْنَا مَعَ الشَّاهِدِينَ }أَوْ{ إِنَّا أَرْسَلْنَاكَ بِالْحَقِّ بَشِيرًا وَنَذِيرًا وَلَا تُسْأَلُ عَنْ أَصْحَابِ الْجَحِيمِ }شَكَّ الدَّارَوَرْدِيُّ","trj":"Telah menceritakan kepada kami [Muhammad bin As Shabbah bin Sufyan] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Utsman bin Umar yaitu Ibnu Musa] dari [Abu Al Ghaits] dari [Abu Hurairah] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam membaca dalam dua raka'at fajar dengan; \"Katakanlah: \"Kami beriman kepada Allah dan kepada apa yang diturunkan kepada kami…\" QS Ali Imran; 84, ayat ini beliau baca di raka'at pertama, sedangkan di raka'at kedua, beliau membaca dengan ayat ini; \"Ya Tuhan kami, kami Telah beriman kepada apa yang Telah Engkau turunkan dan Telah kami ikuti rasul, Karena itu masukanlah kami ke dalam golongan orang-orang yang menjadi saksi (tentang keesaan Allah) \" (QS Ali Imran; 53) atau membaca; \"Sesungguhnya kami Telah mengutusmu (Muhammad) dengan kebenaran; sebagai pembawa berita gembira dan pemberi peringatan, dan kamu tidak akan diminta (pertanggungan jawab) tentang penghuni-penghuni neraka Jahannam.\" (QS Al Baqarah; 119) -Ad Darawardi ragu mengenai redaksi hadits ini-.\""},{"p":"Abu Dawud","n":1119,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَجُلًا قَامَ مِنْ اللَّيْلِ فَقَرَأَ فَرَفَعَ صَوْتَهُ بِالْقُرْآنِ فَلَمَّا أَصْبَحَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُ اللَّهُ فُلَانًا كَأَيٍّ مِنْ آيَةٍ أَذْكَرَنِيهَا اللَّيْلَةَ كُنْتُ قَدْ أَسْقَطْتُهَاقَالَ أَبُو دَاوُد رَوَاهُ هَارُونُ النَّحْوِيُّ عَنْ حَمَّادِ بْنِ سَلَمَةَ فِي سُورَةِ آلِ عِمْرَانَ فِي الْحُرُوفِ{ وَكَأَيٍّ مِنْ نَبِيٍّ }","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Hisyam bin 'Urwah] dari [Urwah] dari [Aisyah] radliallahu 'anha, bahwa seorang laki-laki sedang mengerjakan shalat malam, lalu membaca Al Qur'an dengan mengangkat suaranya, keesokan harinya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah merahmati fulan, dia telah mengingatkanku terhadap ayat Al Qur'an yang aku lupa ayat tersebut.\" Abu Daud berkata; \"di riwayatkan pula oleh Harun An Nahwi dari Hammad bin Salamah mengenai surat Ali Imran pada ayat; \"Dan berapa banyak dari para Nabi…\""},{"p":"Abu Dawud","n":1130,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ الْفَضْلِ بْنِ عَبَّاسٍ قَالَبِتُّ لَيْلَةً عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَنْظُرَ كَيْفَ يُصَلِّي فَقَامَ فَتَوَضَّأَ وَصَلَّى رَكْعَتَيْنِ قِيَامُهُ مِثْلُ رُكُوعِهِ وَرُكُوعُهُ مِثْلُ سُجُودِهِ ثُمَّ نَامَ ثُمَّ اسْتَيْقَظَ فَتَوَضَّأَ وَاسْتَنَّ ثُمَّ قَرَأَ بِخَمْسِ آيَاتٍ مِنْ آلِ عِمْرَانَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ }فَلَمْ يَزَلْ يَفْعَلُ هَذَا حَتَّى صَلَّى عَشْرَ رَكَعَاتٍ ثُمَّ قَامَ فَصَلَّى سَجْدَةً وَاحِدَةً فَأَوْتَرَ بِهَا وَنَادَى الْمُنَادِي عِنْدَ ذَلِكَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَمَا سَكَتَ الْمُؤَذِّنُ فَصَلَّى سَجْدَتَيْنِ خَفِيفَتَيْنِ ثُمَّ جَلَسَ حَتَّى صَلَّى الصُّبْحَقَالَ أَبُو دَاوُد خَفِيَ عَلَيَّ مِنْ ابْنِ بَشَّارٍ بَعْضُهُ","trj":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Syarik bin Abdullah bin Abu Namir] dari [Kuraib] dari [Al Fadl bin Abbas] dia berkata; \"Aku pernah bermalam di sisi Nabi shallallahu 'alaihi wasallam untuk melihat bagaimana cara beliau shalat (malam). Maka (aku melihat) beliau bangun lalu berwudlu' dan shalat dua raka'at. (lama) beliau berdiri sama seperti ruku' dan sujudnya. Setelah itu beliau tidur, kemudian beliau bangun lagi, lalu berwudlu dan bersiwak, kemudian beliau mengucapkan lima ayat dari surat Ali Imran, yaitu; \"Sesungguhnya dalam penciptaan langit dan bumi, dan silih bergantinya malam dan siang…\" (QS Ali Imran; 190), beliau selalu mengerjakan perbuatan ini, sehingga beliau mengerjakan shalat sepuluh raka'at, kemudian beliau bangun dan mengerjakan shalat satu raka'at sebagai witirnya. Setelah seorang Muadzin menyerukan adzan, maka Rasulullah shallallahu 'alaihi wasallam akan mengerjakan shalat dua raka'at yang ringan, kemudian beliau duduk hingga tiba shalat subuh.\" Abu Daud berkata; \"Aku tidak jelas sebagian (riwayat) dari Ibnu Basyar.\""},{"p":"Abu Dawud","n":3061,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ الْأَشْعَثِ قَالَكَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ لِلْيَهُودِيِّ احْلِفْ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفُ وَيَذْهَبُ بِمَالِي فَأَنْزَلَ اللَّهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Al Asy'ats] ia berkata, \"Aku dan seorang laki-laki Yahudi berselisih atas sebuah lahan, kemudian ia mengingkariku. Maka aku pun datang menemui Nabi shallallahu 'alaihi wasallam dan mengadukan hal itu kepadanya, Nabi shallallahu 'alaihi wasallam lalu berkata kepadaku: \"Apakah engkau memiliki bukti?\" Aku menjawab, \"Tidak.\" Beliau bersabda kepada orang Yahudi tersebut: \"Bersumpahlah!\" Maka aku katakan, \"Wahai Rasulullah, jika demikian ia akan bersumpah dan membawa hartaku!\" Kemudian Allah menurunkan ayat: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit…) ' (Qs. Ali Imran: 77) hingga akhir ayat.\""},{"p":"Abu Dawud","n":3371,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا خُصَيْفٌ حَدَّثَنَا مِقْسَمٌ مَوْلَى ابْنِ عَبَّاسٍ قَالَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَانَزَلَتْ هَذِهِ الْآيَةُ{ وَمَا كَانَ لِنَبِيٍّ أَنْ يَغُلَّ }فِي قَطِيفَةٍ حَمْرَاءَ فُقِدَتْ يَوْمَ بَدْرٍ فَقَالَ بَعْضُ النَّاسِ لَعَلَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَهَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَمَا كَانَ لِنَبِيٍّ أَنْ يَغُلَّ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو دَاوُد يَغُلَّ مَفْتُوحَةُ الْيَاءِ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Khushaif] telah menceritakan kepada kami [Miqsam] mantan budak Ibnu Abbas, ia berkata, [Ibnu Abbas] radliallahu 'anhu berkata, \"Turunnya ayat ini: '(Tidak mungkin seorang nabi berkhianat dalam urusan harta rampasan perang) ' (Qs. Ali Imran: 161), berkenaan dengan hilangnya kasur merah di badar. Sebagian orang mengatakan, \"Kemungkinan Rasulullah shallallahu 'alaihi wasallam mengambilnya, maka Allah 'azza wajalla menurunkan ayat: '(Tidak mungkin seorang nabi berkhianat dalam urusan harta rampasan perang) ' (Qs. Ali Imran: 161), hingga akhir ayat.\" Abu Daud berkata, \"Yaghulla, dengan memberi harakat fathah pada huruf ya'.\""},{"p":"Abu Dawud","n":3889,"ar":"حَدَّثَنَا أَبُو ظَفَرٍ عَبْدُ السَّلَامِ حَدَّثَنَا جَعْفَرٌ عَنْ عَوْفٍ قَالَ سَمِعْتُ الْحَجَّاجَ يَخْطُبُ وَهُوَ يَقُولُإِنَّ مَثَلَ عُثْمَانَ عِنْدَ اللَّهِ كَمَثَلِ عِيسَى ابْنِ مَرْيَمَ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ يَقْرَؤُهَا وَيُفَسِّرُهَا{ إِذْ قَالَ اللَّهُ يَا عِيسَى إِنِّي مُتَوَفِّيكَ وَرَافِعُكَ إِلَيَّ وَمُطَهِّرُكَ مِنْ الَّذِينَ كَفَرُوا }يُشِيرُ إِلَيْنَا بِيَدِهِ وَإِلَى أَهْلِ الشَّامِ","trj":"Telah menceritakan kepada kami [Abu Zhafar Abdussalam] berkata, telah menceritakan kepada kami [Ja'far] dari [Auf] ia berkata; Aku mendengar [Al Hajjaj] berkhutbah, ia mengatakan, \"Permisalan Utsman di sisi Allah seperti Isa putra Maryam, lalu ia membaca ayat ini dan mentafsirkannya: '(Ingatlah), ketika Allah berfirman: \"Hai Isa, sesungguhnya Aku akan menyampaikan kamu kepada akhir ajalmu dan mengangkat kamu kepada-Ku serta membersihkan kamu dari orang-orang yang kafir…) ' -Qs. Ali Imran: 55- lalu dengan tangannya ia menunjuk ke arah kami dan ke arah penduduk Syam.\""},{"p":"Ahmad","n":1708,"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ جَرِيرِ بْنِ حَازِمٍ قَالَ حَدَّثَنَا عَدِيُّ بْنُ عَدِيٍّ قَالَ أَخْبَرَنِي رَجَاءُ بْنُ حَيْوَةَ وَالْعُرْسُ ابْنُ عَمِيرَةَ عَنْ أَبِيهِ عَدِيٍّ قَالَخَاصَمَ رَجُلٌ مِنْ كِنْدَةَ يُقَالُ لَهُ امْرُؤُ الْقَيْسِ بْنُ عَابِسٍ رَجُلًا مِنْ حَضَرَمَوْتَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَرْضٍ فَقَضَى عَلَى الْحَضْرَمِيِّ بِالْبَيِّنَةِ فَلَمْ تَكُنْ لَهُ بَيِّنَةٌ فَقَضَى عَلَى امْرِئِ الْقَيْسِ بِالْيَمِينِ فَقَالَ الْحَضْرَمِيُّ إِنْ أَمْكَنْتَهُ مِنْ الْيَمِينِ يَا رَسُولَ اللَّهِ ذَهَبَتْ وَاللَّهِ أَوْ وَرَبِّ الْكَعْبَةِ أَرْضِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبَةٍ لِيَقْتَطِعَ بِهَا مَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ قَالَ رَجَاءُ وَتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }فَقَالَ امْرُؤُ الْقَيْسِ مَاذَا لِمَنْ تَرَكَهَا يَا رَسُولَ اللَّهِ قَالَ الْجَنَّةُ قَالَ فَاشْهَدْ أَنِّي قَدْ تَرَكْتُهَا لَهُ كُلَّهَا","trj":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Jarir bin Hazim] ia berkata, Telah menceritakan kepada kami [Adi bin Adi] ia berkata, telah mengabarkan kepadaku [Raja` bin Haiwah] dan [Al Urs bin Amirah] dari bapaknya [Adi] ia berkata, \"Seorang laki-laki dari Kindah yang biasa dipanggil Umru`ul Qais bin Abis bersengketa dengan seorang laki-laki dari Hadhramut, mereka mengadukan kepada Rasulullah shallallahu 'alaihi wasallam prihal tanah. Maka beliau memberi putusan kepada Al Hadlrami agar ia menunjukkan bukti, namun ia tidak dapat menunjukkan bukti apapun. Kemudian Rasulullah shallallahu 'alaihi wasallam memberi putusan kepada Al Qais agar ia bersumpah. Al Hadlrami pun berkata, \"Jika tuan memberi keluasan baginya untuk bersumpah, niscaya tanah itu akan menjadi miliknya. Demi Allah, atau demi Rabb-nya Ka'bah, tanah itu adalah milikku.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan sumpah palsu untuk mengambil harta saudaranya, maka ia akan menemui Allah, sedang Allah dalam keadaan murka atasnya.\" Raja` berkata, \"Lalu Rasulullah shallallahu 'alaihi wasallam membacakan ayat: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit,..) ' (Qs. Ali Imran: 77). Maka Umru`ul Qais berkata, \"Wahai Rasulullah, lalu apa balasan bagi orang yang meninggalkannya?\" beliau menjawab: \"Baginya surga.\" Ia berkata, \"Saksikanlah, saya telah meninggalkannya (menyerahkan tanah itu) semua untuknya.\""},{"p":"Ahmad","n":1710,"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا سَيْفٌ قَالَ سَمِعْتُ عَدِيَّ بْنَ عَدِيٍّ الْكِنْدِيَّ يُحَدِّثُ عَنْ مُجَاهِدٍ قَالَ حَدَّثَنِي مَوْلًى لَنَا أَنَّهُ سَمِعَ عَدِيًّا يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يُعَذِّبُ الْعَامَّةَ بِعَمَلِ الْخَاصَّةِ حَتَّى يَرَوْا الْمُنْكَرَ بَيْنَ ظَهْرَانَيْهِمْ وَهُمْ قَادِرُونَ عَلَى أَنْ يُنْكِرُوهُ فَلَا يُنْكِرُوهُ فَإِذَا فَعَلُوا ذَلِكَ عَذَّبَ اللَّهُ الْخَاصَّةَ وَالْعَامَّةَحَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ جَرِيرُ بْنُ حَازِمٍ قَالَ حَدَّثَنِي عَدِيُّ بْنُ عَدِيٍّ عَنْ رَجَاءِ بْنِ حَيْوَةَ وَالْعُرْسِ ابْنِ عَمِيرَةَ عَنْ أَبِيهِ عَدِيٍّ فَذَكَرَ الْحَدِيثَ قَالَ جَرِيرٌ وَزَادَنِي أَيُّوبُ وَكُنَّا جَمِيعًا حِينَ سَمِعْنَا الْحَدِيثَ مِنْ عَدِيٍّ قَالَ قَالَ عَدِيٌّ وَحَدَّثَنَا الْعُرْسُ ابْنُ عَمِيرَةَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِهَا وَلَمْ أَحْفَظْهُ أَنَا يَوْمَئِذٍ مِنْ عَدِيٍّ","trj":"Telah menceritakan kepada kami [Ibnu Numair] Telah menceritakan kepada kami [Saif] ia berkata, saya mendengar [Adi bin Adi Al Kindi] menceritakan dari [Mujahid] ia berkata, telah menceritakan kepadaku [Budak milik kami] bahwa ia mendengar [Adi] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla tidak mengadzab manusia secara umum hanya karena perbuatan dosa segelintir orang, sehingga mereka melihat kemungkaran dan mereka pun mampu untuk mengingkarinya, namun mereka tidak mengingkarinya. Jika mereka telah melakukan hal itu, maka Allah akan menyiksa segelintir orang itu dan juga manusia secara menyeluruh.\" Telah menceritakan kepada kami [Yazid bin Harun] dari [Jarir bin Hazim] ia berkata, telah menceritakan kepadaku [Adi bin Adi] dari [Raja` bin Haiwah] dan [Al Urs bin Amirah] dari bapaknya [Adi] lalu ia menyebutkan hadits tersebut.\" [Jarir] berkata, \" [Ayyub] menambahkan kepadaku, \"Ketika kami semua mendengar hadits itu dari Adi, ia berkata, \"Dan telah menceritakan kepada kami Al Ursu bin Amirah; Maka turunlah ayat ini: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit..) ' (Qs. Ali Imran: 77) -hingga akhir ayat- Saat itu aku belum menghafalnya dari Adi.\""},{"p":"Ahmad","n":2950,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","trj":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""},{"p":"Ahmad","n":3303,"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ أَخْبَرَنِي مُحَمَّدُ بْنُ يُوسُفَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ عَنْ صَفْوَانَ بْنِ الْمُعَطَّلِ السُّلَمِيِّ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَرَمَقْتُ صَلَاتَهُ لَيْلَةً فَصَلَّى الْعِشَاءَ الْآخِرَةَ ثُمَّ نَامَ فَلَمَّا كَانَ نِصْفُ اللَّيْلِ اسْتَيْقَظَ فَتَلَا الْآيَاتِ الْعَشْرَ آخِرَ سُورَةِ آلِ عِمْرَانَ ثُمَّ تَسَوَّكَ ثُمَّ تَوَضَّأَ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ فَلَا أَدْرِي أَقِيَامُهُ أَمْ رُكُوعُهُ أَمْ سُجُودُهُ أَطْوَلُ ثُمَّ انْصَرَفَ فَنَامَ ثُمَّ اسْتَيْقَظَ فَتَلَا الْآيَاتِ ثُمَّ تَسَوَّكَ ثُمَّ تَوَضَّأَ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ لَا أَدْرِي أَقِيَامُهُ أَمْ رُكُوعُهُ أَمْ سُجُودُهُ أَطْوَلُ ثُمَّ انْصَرَفَ فَنَامَ ثُمَّ اسْتَيْقَظَ فَفَعَلَ ذَلِكَ ثُمَّ لَمْ يَزَلْ يَفْعَلُ كَمَا فَعَلَ أَوَّلَ مَرَّةٍ حَتَّى صَلَّى إِحْدَى عَشْرَةَ رَكْعَةً","trj":"Telah menceritakan kepada kami 'Abdullah telah bercerita kepadaku ['Ubaidullah bin 'Umar Al Qawariri] telah bercerita kepada kami ['Abdullah bin Ja'far] telah mengabarkan kepadaku [Muhammad bin Yusuf] dari ['Abdullah bin Al Fadhl] dari [Abu Bakar bin 'Abdur Rahman bin Al Harits] dari [Shafwan bin Al Muaththal As Sulami] berkata: Saya bersama Rasulullah Shallallahu'alaihiwasallam dalam sebuah perjalanan, maka pada suatu malam saya menyelidiki shalat beliau Shallallahu'alaihiwasallam, beliau Shallallahu'alaihiwasallam shalat isya' yang diakhirkan kemudian kemudian tidur, dan ketika tiba paruh malam beliau Shallallahu'alaihiwasallam bangun dan membaca sepuluh ayat terakhir dari surat Ali-Imran kemudian bersiwak, berwudhu lalu shalat dua rakaat, saya tidak tahu apakah berdirinya yang lebih lama atau ruku'nya atau sujudnya, kemudian beliau Shallallahu'alaihiwasallam selesai lalu tidur kemudian bangun dan membaca sepuluh ayat terakhir dari surat Aali-Imraan kemudian beliau Shallallahu'alaihiwasallam bersiwak kemudian berwudlu lalu shalat dua rakaat, saya tidak tahu apakah berdirinya yang lebih lama, ruku'nya atau sujudnya, kemudian beliau Shallallahu'alaihiwasallam selesai kemudian tidur lalu melakukan hal demikian, beliau Shallallahu'alaihiwasallam masih selalu melakukan hal itu sebagaimana yang beliau lakukan pertama kali hingga beliau Shallallahu'alaihiwasallam shalat sebelas rakaat."},{"p":"Bukhari","n":177,"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ لَيْلَةً عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ ابْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى أَتَاهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","trj":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] mantan budak Ibnu 'Abbas, bahwa ['Abdullah bin 'Abbas] mengabarkan kepadanya, bahwa ia pada suatu malam pernah bermalam di rumah Maimunah, isteri Nabi shallallahu 'alaihi wasallam, dan bibinya dari pihak ibu. Katanya, \"Aku berbaring di sisi bantal sementara Nabi shallallahu 'alaihi wasallam dan isterinya berbaring pada bagian panjang (tengahnya). Rasulullah shallallahu 'alaihi wasallam lalu tidur hingga pada tengah malam, atau kurang sedikit, atau lewat sedikit, beliau bangun dan duduk sambil mengusap sisa-sisa kantuk yang ada di wajahnya dengan tangan. Beliau kemudian membaca sepuluh ayat terakhir dari Surah Ali 'Imran. Kemudian berdiri menuju tempat wudlu, beliau lalu berwudlu dengan memperbagus wudlunya, lalu shalat.\" Ibnu 'Abbas berkata, \"Maka akupun ikut dan melakukan sebagaimana yang beliau lakukan, aku lalu berdiri di sampingnya. Beliau kemudian meletakkan tangan kanannya di kepalaku seraya memegang telingaku hingga menggeserku ke sebelah kanannya. Kemudian beliau shalat dua rakaat, kemudian dua rakaat, kemudian dua rakaat, kemudian dua rakaat, kemudian witir. Setelah itu beliau tidur berbaring hingga tukang adzan mendatanginya, beliau lalu berdiri dan shalat dua rakaat ringan, kemudian keluar untuk menunaikan shalat Subuh.\""},{"p":"Bukhari","n":937,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ وَهِيَ خَالَتُهُ فَاضْطَجَعْتُ فِي عَرْضِ وِسَادَةٍ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ حَتَّى انْتَصَفَ اللَّيْلُ أَوْ قَرِيبًا مِنْهُ فَاسْتَيْقَظَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ ثُمَّ قَرَأَ عَشْرَ آيَاتٍ مِنْ آلِ عِمْرَانَ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ قَامَ يُصَلِّي فَصَنَعْتُ مِثْلَهُ فَقُمْتُ إِلَى جَنْبهِ فَوَضَعَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي يَفْتِلُهَا ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","trj":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik bin Anas] dari [Makhramah bin Sulaiman] dari [Kuraib] bahwa [Ibnu 'Abbas] mengabarkan kepadanya, bahwa dia pernah bermalam di rumah Maimunah, bibinya dari pihak ibu. Ia mengatakan, \"Aku tidur pada sisi tikar sedangkan Rasulullah shallallahu 'alaihi wasallam dan isterinya berbaring pada bagian tengahnya. Beliau tidur hingga pertengahan malam atau kurang sedikit, kemudian beliau bangun dan mengusap sisa tidur pada wajahnya, membaca sepuluh ayat dari surah Ali 'Imran. Kemudian beliau berdiri mengambil geriba berisi air yang digantung, beliau berwudlu dengan wudlu yang sempurna lalu mendirikan shalat. Aku kemudian mengerjakan seperti apa yang beliau kerjakan, aku lantas berdiri disampingnya. Beliau kemudian meletakkan tangan kanannya di atas kepalaku, meraih telingaku dan menariknya (menggeser). Kemudian beliau shalat dua rakaat, lalu dua rakaat, lalu dua rakaat, lalu dua rakaat, lalu dua rakaat, lalu dua rakaat, lalu shalat witir. Kemudian Beliau berbaring hingga seorang mu'adzin mendatanginya, kemudian beliau melaksanakan shalat dua rakaat lalu keluar melaksanakan shalat subuh.\""},{"p":"Bukhari","n":1123,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّهُ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا وَهِيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ عَلَى عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ ثُمَّ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ فَمَسَحَ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ آيَاتٍ خَوَاتِيمَ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا بِيَدِهِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","trj":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] sahaya Ibnu 'Abbas radliallahu 'anhu bahwa dia mengabarkan dari ['Abdullah bin 'Abbas radliallahu 'anhuma] bahwa dia pada suatu malam bermalam di rumah Maimunah Ummul Mu'minin radliallahu 'anha, dia adalah bibinya, katanya: \"Maka aku berbaring di sisi bantal bagian lebar, sementara Nabi shallallahu 'alaihi wasallam dan keluarganya pada bagian panjang, lantas Rasulullah shallallahu 'alaihi wasallam tidur hingga pada tengah malam kurang sedikit atau lewat sedikit, Beliau shallallahu 'alaihi wasallam bangun lalu sambil duduk Beliau mengusap (sisa) tidur pada wajahnya dengan tangannya. Kemudian membaca sepuluh ayat terakhir dari Surah Ali 'Imran. Kemudian berdiri menuju tempat wudhu' lalu Beliau berwudhu' dengan sebaik-baiknya, kemudian shalat\". Berkata, Ibnu 'Abbas radliallahu 'anhu, \"Maka aku pun bangun dan aku lakukan seperti yang Beliau shallallahu 'alaihi wasallam lakukan. Lalu aku menuju kepadanya dan berdiri di sampingnya. Maka Beliau meletakkan tangan kanannya di kepalaku seraya memegang telingaku hingga menggeserku ke sebelah kanannya. Kemudian Beliau shalat dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian witir (ganjil) kemudian berbaring hingga datang kepadanya mu'adzin (mengumandangkan adzan). Maka Beliau shalat dua raka'at dengan ringan lalu keluar untuk menunaikan shalat Shubuh\"."},{"p":"Bukhari","n":1165,"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنِي مَعْمَرٌ وَيُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ قَالَتْأَقْبَلَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ عَلَى فَرَسِهِ مِنْ مَسْكَنِهِ بِالسُّنْحِ حَتَّى نَزَلَ فَدَخَلَ الْمَسْجِدَ فَلَمْ يُكَلِّمْ النَّاسَ حَتَّى دَخَلَ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَتَيَمَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُسَجًّى بِبُرْدِ حِبَرَةٍ فَكَشَفَ عَنْ وَجْهِهِ ثُمَّ أَكَبَّ عَلَيْهِ فَقَبَّلَهُ ثُمَّ بَكَى فَقَالَ بِأَبِي أَنْتَ يَا نَبِيَّ اللَّهِ لَا يَجْمَعُ اللَّهُ عَلَيْكَ مَوْتَتَيْنِ أَمَّا الْمَوْتَةُ الَّتِي كُتِبَتْ عَلَيْكَ فَقَدْ مُتَّهَاقَالَ أَبُو سَلَمَةَ فَأَخْبَرَنِي ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ خَرَجَ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُ يُكَلِّمُ النَّاسَ فَقَالَ اجْلِسْ فَأَبَى فَقَالَ اجْلِسْ فَأَبَى فَتَشَهَّدَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَمَالَ إِلَيْهِ النَّاسُ وَتَرَكُوا عُمَرَ فَقَالَ أَمَّا بَعْدُ فَمَنْ كَانَ مِنْكُمْ يَعْبُدُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ مَاتَ وَمَنْ كَانَ يَعْبُدُ اللَّهَ فَإِنَّ اللَّهَ حَيٌّ لَا يَمُوتُ قَالَ اللَّهُ تَعَالَى{ وَمَا مُحَمَّدٌ إِلَّا رَسُولٌ قَدْ خَلَتْ مِنْ قَبْلِهِ الرُّسُلُ إِلَى الشَّاكِرِينَ }وَاللَّهِ لَكَأَنَّ النَّاسَ لَمْ يَكُونُوا يَعْلَمُونَ أَنَّ اللَّهَ أَنْزَلَهَا حَتَّى تَلَاهَا أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَتَلَقَّاهَا مِنْهُ النَّاسُ فَمَا يُسْمَعُ بَشَرٌ إِلَّا يَتْلُوهَا","trj":"Telah menceritakan kepada kami [Bisyir bin Muhammad] telah mengabarkan kepada kami ['Abdullah] berkata, telah mengabarkan kepada saya [Ma'mar] dan [Yunus] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Abu Salamah] bahwa ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya, katanya; [Abu Bakar] radliallahu 'anhu menunggang kudanya dari suatu tempat bernama Sunih hingga sampai dan masuk ke dalam masjid dan dia tidak berbicara dengan orang-orang, lalu dia menemui 'Aisyah radliallahu 'anha dan langsung mendatangi Nabi shallallahu 'alaihi wasallam yang sudah ditutupi (jasadnya) dengan kain terbuat dari katun. Kemudian dia membuka tutup wajah Beliau lalu Abu Bakar bersimpuh didepan jasad Nabi, lalu menutupnya kembali. Kemudian Abu Bakar menangis dan berkata: \"Demi bapak dan ibuku, wahai Nabi Allah, Allah tidak akan menjadikan kematian dua kali kepadamu. Adapun kematian pertama yang telah ditetapkan buatmu itu sudah terjadi\". Berkata, [Abu Salamah]; telah mengabarkan kepada saya [Ibnu 'Abbas] radliallahu 'anhuma bahwa; Kemudian [Abu Bakar] radliallahu 'anhu keluar bertepatan 'Umar radliallahu 'anhu sedang berbicara dengan orang banyak. Maka (Abu Bakar radliallahu 'anhu) berkata, kepada (\"Umar radliallahu 'anhu): \"Duduklah!\". Namun 'Umar tidak mempedulikannya. Lalu Abu Bakar berkata, lagi: \"Duduklah!\". Namun 'Umar tetap tidak mempedulikannya. Akhirnya Abu Bakar bersaksi (tentang kewafatan Nabi shallallahu 'alaihi wasallam) sehingga orang-orang berkumpul kepadanya dan meninggalkan 'Umar, lalu Abu Bakar berkata: \"Kemudian, barangsiapa dari kalian yang menyembah Muhammad shallallahu 'alaihi wasallam, sungguh Muhammad shallallahu 'alaihi wasallam sekarang sudah wafat dan barangsiapa dari kalian yang menyembah Allah, sungguh Allah Maha Hidup yang tidak akan pernah mati. Allah Ta'ala telah berfirman: (yang artinya): \"Dan Muhammad itu tidak lain kecuali hanyalah seorang rasul sebagaimana telah berlalu (mati) rasul-rasul sebelum dia\"..seterusnya hingga akhir ayat … Allah akan memberi balasan pahala bagi orang-orang yang bersyukur\" (QS. Ali'Imran 165). Demi Allah, seakan-akan orang-orang belum pernah mengetahui bahwa Allah sudah menurunkan ayat tersebut sampai Abu Bakar radliallahu 'anhu membacakannya. Akhirnya orang-orang memahaminya dan tidak ada satupun orang yang mendengarnya (wafatnya Nabi) kecuali pasti membacakannya\"."},{"p":"Bukhari","n":1946,"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا الْعَوَّامُ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَقَامَ سِلْعَةً وَهُوَ فِي السُّوقِ فَحَلَفَ بِاللَّهِ لَقَدْ أَعْطَى بِهَا مَا لَمْ يُعْطِ لِيُوقِعَ فِيهَا رَجُلًا مِنْ الْمُسْلِمِينَ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }الْآيَةَ","trj":"Telah menceritakan kepada kami ['Amru bin Muhammad] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Al 'Awwam] dari [Ibrahim bin 'Abdurrahman] dari ['Abdullah bin Abi Aufa radliallahu 'anhu] bahwa ada seseorang menyiapkan barang dagangan dipasar, lalu ia bersumpah atas nama Allah, sesungguhnya ia telah memberikan barang tersebut dengan apa yang tidak ada padanya kepada seseorang dari kaum muslimin, lalu turunlah ayat: (\"Sesungguhnya orang-orang yang menukar janjinya dengan Allah dan sumpah-sumpah mereka dengan harga yang sedikit\"). (QS Al 'Imran: 77). "},{"p":"Bukhari","n":2472,"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ وَهُوَ فِيهَا فَاجِرٌ لِيَقْتَطِعَ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُقَالَ فَقَالَ الْأَشْعَثُ بْنُ قَيْسٍ فِيَّ وَاللَّهِ كَانَ ذَلِكَ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قَالَ قُلْتُ لَا قَالَ فَقَالَ لِلْيَهُودِيِّ احْلِفْ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفَ وَيَذْهَبَ بِمَالِي قَالَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","trj":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari ['Abdullah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah dengan sumpah curang, dan bermaksud mengambil harta seorang muslim maka nanti dia akan berjumpa dengan Allah, sedang Allah murka kepadanya\". Dia berkata,, maka [Al Ays'ats bin Qais] berkata: \"Demi Allah, hadits itu berkenaan dengan aku, yang antara aku dan seorang Yahudi ada sebidang lahan, lalu dia mempermasalahkannya sehingga aku adukan kepada Nabi shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Apakah kamu memiliki bukti?\" Aku katakan: \"Tidak\". Lalu Beliau berkata kepada si Yahudi: \"Bersumpahlah kamu\". 'Abdullah berkata; Aku katakan: \"Wahai Rasulullah, kalau dia bersumpah nanti dia musti membawa hartaku\". 'Abdullah berkata: \"Maka turunlah firman Allah yang artinya: (\"Sesungguhnya orang-orang yang menjualjanjinya dengan Allah dan sumpah mereka dengan harga yang murah …hingga akhir ayat\") (QS. Ali Imran 77)."},{"p":"Bukhari","n":2474,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِمَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالًا لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ ثُمَّ أَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ إِلَى عَذَابٌ أَلِيمٌ }ثُمَّ إِنَّ الْأَشْعَثَ بْنَ قَيْسٍ خَرَجَ إِلَيْنَا فَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ فَحَدَّثْنَاهُ بِمَا قَالَ فَقَالَ صَدَقَ لَفِيَّ أُنْزِلَتْ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ خُصُومَةٌ فِي شَيْءٍ فَاخْتَصَمْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ شَاهِدَاكَ أَوْ يَمِينُهُ فَقُلْتُ لَهُ إِنَّهُ إِذًا يَحْلِفُ وَلَا يُبَالِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالًا وَهُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ عَزَّ وَجَلَّ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ ثُمَّ اقْتَرَأَ هَذِهِ الْآيَةَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] berkata; ['Abdullah] berkata: \"Siapa yang bersumpah yang dengan sumpahnya bermaksud untuk menguasai harta maka dia akan berjumpa Allah dan Allah dalam keadaan murka kepadanya. Kemudian turunlah firman Allah sebagai pembenaran atas ini: (\"Sesungguhnya orang-orang yang menjual janjinya dengan Allah dan sumpah mereka dengan harga yang murah …hingga ayat berbunyi…. siksa yang pedih) (QS. Ali'Imran.77). Kemudian [Al Asy'ats bin Qais] menemui kami lalu berkata: \"Apa yang diceritakan kepada kalian oleh Abu 'Abdurrahman?\" Maka kami ceritakan kepadanya apa yang disampaikan oleh Abu 'Abdurrahman. Maka dia berkata: \"Dia benar, karena memang ayat itu turun berkenaan dengan aku, yang antara aku dan seseorang ada perselisihan tentang sesuatu sehingga kami bawa persoalan tersebut kepada Rasulullah shallallahu 'alaihi wasallam lalu Beliau bertanya: \"Siapa dua orang saksimu atau orang itu menyatakan sumpahnya\". Aku katakan kepada Beliau: \"Kalau sumpah, dia pasti mau bersumpah lalu dia tidak mempedulikan aku\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah dengan tujuan bermaksud mengambil harta seseorang padahal dia bersumpah dengan curang (dusta) maka nanti dia akan berjumpa Allah 'azza wajalla, dan Allah murka kepadanya\". Maka turunlah ayat sebagai pembenaran dari hal ini, lalu dia membacanya."},{"p":"Bukhari","n":2479,"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْعَوَّامُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ أَبُو إِسْمَاعِيلَ السَّكْسَكِيُّ سَمِعَ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَقَامَ رَجُلٌ سِلْعَتَهُ فَحَلَفَ بِاللَّهِ لَقَدْ أَعْطَى بِهَا مَا لَمْ يُعْطِهَا فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }وَقَالَ ابْنُ أَبِي أَوْفَى النَّاجِشُ آكِلُ رِبًا خَائِنٌ","trj":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al 'Awwam] berkata, telah menceritakan kepadaku [Ibrahim Abu Isma'il as-Saksakiy] dia mendengar ['Abdullah bin Abu Awfaa radliallahu 'anhuma] berkata; Ada seseorang yang menunggui barang dagangannya, lalu dia bersumpah atas nama Allah bahwa dia hanya memberikan dagangannya dengan harga sekian-sekian padahal bohong belaka, maka turunlah firman Allah yang artinya: (\"Sesungguhnya orang-orang yang menjual janjinya kepada Allah dan sumpah mereka dengan harga yang murah..) (QS. Ali'Imran 77). Dan berkata Ibnu Abi Awfaa: \"Orang yang menipu orang lain, sama artinya dengan pemakan riba dan pengkhianat\"."},{"p":"Bukhari","n":2480,"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبًا لِيَقْتَطِعَ مَالَ رَجُلٍ أَوْ قَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ تَصْدِيقَ ذَلِكَ فِي الْقُرْآنِ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا الْآيَةَ إِلَى قَوْلِهِ عَذَابٌ أَلِيمٌ }فَلَقِيَنِي الْأَشْعَثُ فَقَالَ مَا حَدَّثَكُمْ عَبْدُ اللَّهِ الْيَوْمَ قُلْتُ كَذَا وَكَذَا قَالَ فِيَّ أُنْزِلَتْ","trj":"Telah menceritakan kepada kami [Bisyir bin Khalid] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Abu Wa'il] dari ['Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang bersumpah palsu (berdusta) yang dengan sumpahnya itu dia bermaksud mengambil harta orang lain atau Beliau bersabda dengan redaksi 'saudaranya', maka dia berjumpa Allah sedang Allah murka kepadanya\". Lalu Allah menurunkan ayat Al Qur'an sebagai pembenaran atas sabda Beliau ini yang artinya: (\"Sesungguhnya orang-orang yang menjual janjinya kepada Allah dan sumpah mereka dengan harga yang murah.. hingga firman-Nya …siksa yang pedih) (QS. Ali'Imran 77). Kemudian [Al Asy'ats] menemuiku seraya berkata: \"Apa yang diceritakan 'Abdullah kepada kalian hari ini?\" Aku katakan: \"Begini-begini\". Maka dia berkata: \"Ayat itu turun berkenaan dengan aku\"."},{"p":"Bukhari","n":3120,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ قَالَ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ بَنِي آدَمَ مَوْلُودٌ إِلَّا يَمَسُّهُ الشَّيْطَانُ حِينَ يُولَدُ فَيَسْتَهِلُّ صَارِخًا مِنْ مَسِّ الشَّيْطَانِ غَيْرَ مَرْيَمَ وَابْنِهَا ثُمَّ يَقُولُ أَبُو هُرَيْرَةَ{ وَإِنِّي أُعِيذُهَا بِكَ وَذُرِّيَّتَهَا مِنْ الشَّيْطَانِ الرَّجِيمِ }","trj":"Telah bercerita kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata telah bercerita kepadaku [Sa'id bin Al Musayyab] berkata; [Abu Hurairah radliallahu 'anhu] berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pun dari anak keturunan Adam yang dilahirkan kecuali dia disentuh oleh setan saat dilahirkan, maka dia akan berteriak (menangis dengan keras) karena sentuhan setan tersebut kecuali Maryam dan anaknya\". Kemudian Abu Hurairah radliallahu 'anhu membaca firman Allah Ta'ala: (\"…dan aku memohon perlindungan kepada-Mu, ya Allah untuknya (Maryam) dan untuk anak keturunannya dari setan yang terketuk\"). (QS Ali 'Imran ayat 36)."},{"p":"Bukhari","n":3546,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَزَلَتْ هَذِهِ الْآيَةُ فِينَا{ إِذْ هَمَّتْ طَائِفَتَانِ مِنْكُمْ أَنْ تَفْشَلَا }بَنِي سَلِمَةَ وَبَنِي حَارِثَةَ وَمَا أُحِبُّ أَنَّهَا لَمْ تَنْزِلْ وَاللَّهُ يَقُولُ{ وَاللَّهُ وَلِيُّهُمَا }","trj":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Ibnu Uyainah] dari ['Amru] dari [Jabir] radliallahu 'anhu, dia berkata, \"Ayat ini turun kepada kami: '(Ketika dua golongan dari padamu ingin (mundur) Karena takut..) ' (Qs. Ali Imran: 122), yaitu bani Salimah dan Bani Haritsah, dan aku lebih suka jika ayat tersebut tidak turun, Allah berfirman: '(padahal Allah adalah penolong bagi kedua golongan itu) '."},{"p":"Bukhari","n":3559,"ar":"حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ السُّلَمِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي سَالِمٌ عَنْ أَبِيهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ مِنْ الرَّكْعَةِ الْآخِرَةِ مِنْ الْفَجْرِ يَقُولُ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا وَفُلَانًا بَعْدَ مَا يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ فَأَنْزَلَ اللَّهُ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ إِلَى قَوْلِهِ فَإِنَّهُمْ ظَالِمُونَ }وَعَنْ حَنْظَلَةَ بْنِ أَبِي سُفْيَانَ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو عَلَى صَفْوَانَ بْنِ أُمَيَّةَ وَسُهَيْلِ بْنِ عَمْرٍو وَالْحَارِثِ بْنِ هِشَامٍ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ إِلَى قَوْلِهِ فَإِنَّهُمْ ظَالِمُونَ }","trj":"Telah menceritakan kepada kami [Yahya bin Abdullah As Sulami] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah menceritakan kepadaku [Salim] dari [Ayahnya] bahwa dia mendengar saat Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya dari rukuk di rakaat terakhir shalat shubuh, beliau mengucapkan: \"Ya Allah, laknatlah fulan, fulan dan fulan, \" yaitu setelah beliau mengucapkan: \"Sami'allahu liman hamidah, rabbanaa walakalhamdu.\" Setelah itu Allah menurunkan ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu -hingga firmanNya- Sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128). Dan dari [Hanzhalah bin Abu Sufyan] aku mendengar [Salim bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mendo'akan (kejelekkan) kepada Shofwan bin Umayyah, Suhail bin 'Amru dan Harits bin Hisyam, lalu turunlah ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu -hingga firmanNya- Sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128)."},{"p":"Bukhari","n":3566,"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ الَّذِينَ اسْتَجَابُوا لِلَّهِ وَالرَّسُولِ مِنْ بَعْدِ مَا أَصَابَهُمْ الْقَرْحُ لِلَّذِينَ أَحْسَنُوا مِنْهُمْ وَاتَّقَوْا أَجْرٌ عَظِيمٌ }قَالَتْ لِعُرْوَةَ يَا ابْنَ أُخْتِي كَانَ أَبَوَاكَ مِنْهُمْ الزُّبَيْرُ وَأَبُو بَكْرٍ لَمَّا أَصَابَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَصَابَ يَوْمَ أُحُدٍ وَانْصَرَفَ عَنْهُ الْمُشْرِكُونَ خَافَ أَنْ يَرْجِعُوا قَالَ مَنْ يَذْهَبُ فِي إِثْرِهِمْ فَانْتَدَبَ مِنْهُمْ سَبْعُونَ رَجُلًا قَالَ كَانَ فِيهِمْ أَبُو بَكْرٍ وَالزُّبَيْرُ","trj":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam] dari [Ayahnya] dari ['Aisyah] radliallahu 'anha mengenai ayat: '((yaitu) orang-orang yang mentaati perintah Allah dan rasul-Nya sesudah mereka mendapat luka (dalam peperangan Uhud). bagi orang-orang yang berbuat kebaikan diantara mereka dan yang bertakwa ada pahala yang besar) ' (Qs. Ali Imran: 172). Aisyah berkata kepada 'Urwah, \"Wahai keponakanku, sesungguhnya ayahmu termasuk dari mereka (yang diterangkan dalam ayat), yaitu Az Zubair dan Abu Bakr. Ketika Rasulullah Shallallahu 'alahi wasallam terluka pada perang Uhud, disaat beliau khawatir kaum Musyrikin yang telah pergi akan kembali, beliau bersabda: \"Siapakah yang akan mengintai mereka?\", lalu beliau memilih tujuh puluh orang.\" Perawi berkata, \"Termasuk diantara mereka adalah Abu Bakr dan Az Zubair.\""},{"p":"Bukhari","n":3899,"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ فَقُلْتُ لَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطُرِحَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وِسَادَةٌ فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طُولِهَا فَجَعَلَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ ثُمَّ قَرَأَ الْآيَاتِ الْعَشْرَ الْأَوَاخِرَ مِنْ آلِ عِمْرَانَ حَتَّى خَتَمَ ثُمَّ أَتَى شَنًّا مُعَلَّقًا فَأَخَذَهُ فَتَوَضَّأَ ثُمَّ قَامَ يُصَلِّي فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ جِئْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ يَدَهُ عَلَى رَأْسِي ثُمَّ أَخَذَ بِأُذُنِي فَجَعَلَ يَفْتِلُهَا ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ أَوْتَرَ","trj":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami ['Abdur Rahman bin Mahdi] dari [Malik bin Anas] dari [Makhramah bin Sulaiman] dari [Kuraib] dari [Ibnu 'Abbas radliallahu 'anhuma] ia berkata; Suatu ketika aku menginap di rumah Maimunah, lalu aku berkata; Aku akan melihat shalat Rasulullah. Tiba-tiba Rasulullah shallallahu 'alaihi wasallam diberi bantal dan beliau tidur di bagian sisi panjang. Setelah itu bangun seraya mengusap kantuk dari wajahnya. Lalu beliau membaca sepuluh ayat terakhir surat Ali Imran hingga selesai. kemudian beliau menuju ke geriba yang tergantung, beliau berwudlu darinya dan beliau shalat. Ibnu 'Abbas berkata; Aku pun bangun dan melaksanakan seperti apa yang beliau kerjakan, kemudian aku berdiri di sampingnya, maka beliau meletakkan tangannya di kepalaku dan memegang telinga kananku lalu memilinnya. Beliau shalat dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at kemudian beliau melakukan witir."},{"p":"Bukhari","n":3900,"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنَا مَالِكٌ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهْيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ ثُمَّ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدَيْهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْن��ى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي بِيَدِهِ الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","trj":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Ma'an bin 'Isa] Telah menceritakan kepada kami [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] -budak yang dimerdekakan- 'Abdullah bin 'Abbas bahwa ['Abdullah bin 'Abbas] mengabarkan kepadanya bahwasannya dia pernah menginap di rumah Maimunah isteri Nabi shallallahu 'alaihi wasallam, yaitu bibinya. Ia berkata; Aku berbaring di bantal bagian sisi lebar, sedangkan Rasulullah shallallahu 'alaihi wasallam dan keluarganya tidur di bantal bagian sisi panjang. Rasulullah shallallahu 'alaihi wasallam tidur hingga pertengahan malam, mendekati atau melewati sedikit, kemudian bangun dan duduk seraya mengusap kantuk dari wajahnya dengan tangannya. Kemudian beliau membaca sepuluh ayat terakhir surat Ali Imran, lalu bangun menuju ke geriba yang tergantung, beliau berwudlu darinya dan menyempurnakan wudlunya kemudian beliau shalat. Ibnu 'Abbas berkata; Aku pun bangun dan melaksanakan seperti apa yang beliau kerjakan, kemudian aku berdiri di sampingnya, maka beliau meletakkan tangannya di kepalaku dan memegang telinga kananku lalu memilinnya. Beliau shalat dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at kemudian beliau melakukan witir, setelah selesai beliau tidur kembali hingga datang seruan mu`adzin. Kemudian beliau shalat dua raka'at ringan dan keluar untuk melakukan shalat Subuh.\""},{"p":"Bukhari","n":3901,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهْيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ ابْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] -budak yang dimerdekakan- Ibnu 'Abbas bahwa [Ibnu 'Abbas radliallahu 'anhu] telah mengabarkan kepadanya bahwasannya dia pernah menginap di rumah Maimunah isteri Nabi shallallahu 'alaihi wasallam, yaitu bibinya. Ia berkata; Aku berbaring di bantal bagian sisi lebar, sedangkan Rasulullah shallallahu 'alaihi wasallam dan keluarganya tidur di bantal bagian sisi panjang. Rasulullah shallallahu 'alaihi wasallam tidur hingga pertengahan malam, mendekati atau melewati sedikit, kemudian bangun dan duduk seraya mengusap kantuk dari wajahnya dengan tangannya. Kemudian beliau membaca sepuluh ayat terakhir dari surat Ali Imran, lalu bangun menuju ke geriba yang tergantung, beliau berwudlu darinya dan menyempurnakan wudlunya kemudian beliau shalat. Ibnu 'Abbas berkata; Aku pun bangun dan melaksanakan seperti apa yang beliau kerjakan, kemudian aku berdiri di sampingnya, maka beliau meletakkan tangannya di kepalaku dan memegang telinga kananku lalu memilinnya. Beliau shalat dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at, dua raka'at kemudian beliau melakukan witir, setelah selesai beliau tidur kembali hingga datang seruan mu`adzin. Kemudian beliau shalat dua raka'at ringan dan keluar untuk melakukan shalat Subuh.\""},{"p":"Bukhari","n":4875,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ مَالًا مِنْ نَخْلٍ وَكَانَ أَحَبُّ مَالِهِ إِلَيْهِ بَيْرُحَاءَ وَكَانَتْ مُسْتَقْبِلَ الْمَسْجِدِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَاءٍ فِيهَا طَيِّبٍ قَالَ أَنَسٌ فَلَمَّا نَزَلَتْ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَامَ أَبُو طَلْحَةَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ يَقُولُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }وَإِنَّ أَحَبَّ مَالِي إِلَيَّ بَيْرُحَاءَ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ أَرَاكَ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخٍ ذَلِكَ مَالٌ رَابِحٌ أَوْ رَايِحٌ شَكَّ عَبْدُ اللَّهِ وَقَدْ سَمِعْتُ مَا قُلْتَ وَإِنِّي أَرَى أَنْ تَجْعَلَهَا فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَمَهَا أَبُو طَلْحَةَ فِي أَقَارِبِهِ وَفِي بَنِي عَمِّهِوَقَالَ إِسْمَاعِيلُ وَيَحْيَى بْنُ يَحْيَى رَايِحٌ","trj":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ishaq bin Abdullah] bahwa dia mendengar [Anas bin Malik] berkata; Abu Thalhah adalah sahabat Anshar yang paling banyak hartanya di Madinah yaitu berupa kebun kurma, sementara harta yang paling dia cintai ialah (kebun kurma) yang berada di Bairuha' dan yang menghadap ke Masjid, Rasulullah Shallallahu'alaihi wasallam juga sering memasukinya dan minum airnya yang jernih, Anas berkata; ketika ayat ini turun Tidaklah engkau mendapatkan kebaikan hingga engkau menginfakkan apa yang paling engkau sukai QS Ali Imran; 92, Maka Abu Thalhah berdiri dan berkata; \"Ya Rasulullah, sesungguhnya Allah telah berfirman \"Tidaklah engkau mendapatkan kebaikan hingga engkau menginfakkan apa yang paling engkau sukai\" dan sungguh harta yang paling aku sukai adalah Bairuha' dan telah aku infakkan dijalan Allah, aku hanya berharap kebaikannya dan aku harapkan simpanannya disisi Allah, maka taruhlah ia dimanapun engkau kehendaki ya Rasulullah, selanjutnya Rasulullah Shallallahu'alaihi wasallam bersabda: \"Wah…! Itu adalah harta yang sangat berharga, harta yang sangat berharga, sungguh aku telah mendengar apa yang kamu katakan agar kamu menjadikannya sebagian untuk karib kerabatmu, \" lalu Abu Thalhah berkata; \"Akan aku lakukan ya Rasulullah, \" maka ia membaginya untuk keluarganya dan anak pamannya.\" Sementara [Isma'il] dan [Yahya bin Yahya] menyebutkan dengan redaksi \"raayihun (berharga).\""},{"p":"Bukhari","n":5434,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ ح حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ أُسَامَةَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ عَلَى حِمَارٍ عَلَيْهِ قَطِيفَةٌ فَدَكِيَّةٌ وَأُسَامَةُ وَرَاءَهُ يَعُودُ سَعْدَ بْنَ عُبَادَةَ فِي بَنِي حَارِثِ بْنِ الْخَزْرَجِ قَبْلَ وَقْعَةِ بَدْرٍ فَسَارَا حَتَّى مَرَّا بِمَجْلِسٍ فِيهِ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ وَذَلِكَ قَبْلَ أَنْ يُسْلِمَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ فَإِذَا فِي الْمَجْلِسِ أَخْلَاطٌ مِنْ الْمُسْلِمِينَ وَالْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ وَالْيَهُودِ وَفِي الْمُسْلِمِينَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَلَمَّا غَشِيَتْ الْمَجْلِسَ عَجَاجَةُ الدَّابَّةِ خَمَّرَ ابْنُ أُبَيٍّ أَنْفَهُ بِرِدَائِهِ وَقَالَ لَا تُغَبِّرُوا عَلَيْنَا فَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ ثُمَّ وَقَفَ فَنَزَلَ فَدَعَاهُمْ إِلَى اللَّهِ وَقَرَأَ عَلَيْهِمْ الْقُرْآنَ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ أَيُّهَا الْمَرْءُ لَا أَحْسَنَ مِمَّا تَقُولُ إِنْ كَانَ حَقًّا فَلَا تُؤْذِنَا بِهِ فِي مَجَالِسِنَا فَمَنْ جَاءَكَ فَاقْصُصْ عَلَيْهِ قَالَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ بَلَى يَا رَسُولَ اللَّهِ فَاغْشَنَا فِي مَجَالِسِنَا فَإِنَّا نُحِبُّ ذَلِكَ فَاسْتَبَّ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْيَهُودُ حَتَّى كَادُوا يَتَثَاوَرُونَ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ حَتَّى سَكَتُوا ثُمَّ رَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَابَّتَهُ فَسَارَ حَتَّى دَخَلَ عَلَى سَعْدِ بْنِ عُبَادَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ سَعْدُ أَلَمْ تَسْمَعْ مَا قَالَ أَبُو حُبَابٍ يُرِيدُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَالَ كَذَا وَكَذَا فَقَالَ سَعْدُ بْنُ عُبَادَةَ أَيْ رَسُولَ اللَّهِ بِأَبِي أَنْتَ اعْفُ عَنْهُ وَاصْفَحْ فَوَالَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ لَقَدْ جَاءَ اللَّهُ بِالْحَقِّ الَّذِي أَنْزَلَ عَلَيْكَ وَلَقَدْ اصْطَلَحَ أَهْلُ هَذِهِ الْبَحْرَةِ عَلَى أَنْ يُتَوِّجُوهُ وَيُعَصِّبُوهُ بِالْعِصَابَةِ فَلَمَّا رَدَّ اللَّهُ ذَلِكَ بِالْحَقِّ الَّذِي أَعْطَاكَ شَرِقَ بِذَلِكَ فَذَلِكَ فَعَلَ بِهِ مَا رَأَيْتَ فَعَفَا عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ يَعْفُونَ عَنْ الْمُشْرِكِينَ وَأَهْلِ الْكِتَابِ كَمَا أَمَرَهُمْ اللَّهُ وَيَصْبِرُونَ عَلَى الْأَذَى قَالَ اللَّهُ تَعَالَى{ وَلَتَسْمَعُنَّ مِنْ الَّذِينَ أُوتُوا الْكِتَابَ }الْآيَةَ وَقَالَ{ وَدَّ كَثِيرٌ مِنْ أَهْلِ الْكِتَابِ }فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَأَوَّلُ فِي الْعَفْوِ عَنْهُمْ مَا أَمَرَهُ اللَّهُ بِهِ حَتَّى أَذِنَ لَهُ فِيهِمْ فَلَمَّا غَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدْرًا فَقَتَلَ اللَّهُ بِهَا مَنْ قَتَلَ مِنْ صَنَادِيدِ الْكُفَّارِ وَسَادَةِ قُرَيْشٍ فَقَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ مَنْصُورِينَ غَانِمِينَ مَعَهُمْ أُسَارَى مِنْ صَنَادِيدِ الْكُفَّارِ وَسَادَةِ قُرَيْشٍ قَالَ ابْنُ أُبَيٍّ ابْنُ سَلُولَ وَمَنْ مَعَهُ مِنْ الْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ هَذَا أَمْرٌ قَدْ تَوَجَّهَ فَبَايِعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْإِسْلَامِ فَأَسْلَمُوا","trj":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] bahwa [Usamah bin Zaid] radliallahu 'anhuma telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengendarai seekor keledai, dilengkapi dengan pelana yang terbuat dari kain Fadak, sementara Usamah berada di belakang beliau. Beliau pergi untuk menjenguk Sa'ad bin 'Ubadah di Bani Al Harits bin Al Khazraj; kejadian ini berlangsung sebelum perang Badar. Kemudian beliau berangkat hingga melewati suatu majlis, yang di dalamnya terdapat 'Abdullah bin 'Ubay bin Salul. Itu terjadi sebelum 'Abdullah bin 'Ubay masuk Islam. Di dalam majlis itu berkumpul pula orang-orang dari kaum Muslimin, orang-orang Musyrik, para penyembah berhala, dan orang-orang Yahudi. Di kalangan kaum Muslimin terdapat 'Abdullah bin Rawahah. Ketika majlis tersebut di kepuli oleh debu yang ditimbulkan dari hewan tunggangan, 'Abdullah bin 'Ubay langsung menutup hidungnya sambil berkata; \"Hei, jangan kamu kepuli kami dengan debu.\" Rasulullah shallallahu 'alaihi wasallam mengucapkan salam kepada mereka, lalu beliau berhenti, turun dan mengajak mereka kepada Allah (memeluk agama Islam) dan membacakan kepada mereka Al Qur'an. Mendengar hal itu 'Abdullah bin 'Ubay berkata; 'Hei..! apa tak ada yang lebih baik dari yang engkau ucapkan! jika itu benar, jangan ganggu di pertemuan kami. Kembalilah! Dan bacakan saja kepada orang-orang yang datang kepadamu! ' Mendengar itu 'Abdullah bin Rawahah berkata; 'Ya Rasulullah! sampaikan saja kepada kami dalam pertemuan ini, karena kami menyukai hal itu.' Maka Kaum Muslimin, orang-orang kafir, dan Yahudi saling mencaci-maki satu sama lain hingga hampir saja mereka berkelahi. Nabi shallallahu 'alaihi wasallam tidak henti-hentinya menenangkan mereka hingga mereka semua kembali tenang. Setelah itu Rasulullah shallallahu 'alaihi wasallam menaiki kembali keledainya dan melanjutkan perjalanan hingga sampai di kediaman Sa'ad bin 'Ubadah. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepada Sa'ad: 'Wahai Sa'd, tidakkah engkau mendengar apa yang diucapkan Abu Hubab? ' -yang beliau maksudkan adalah 'Abdullah bin 'Ubay- 'Dia telah berkata ini dan itu.' Mendengar itu Sa'ad bin 'Ubadah berkata; Demi ayahku, maafkan dia wahai Rasulullah dan berlapang dadalah kepadanya. Demi dzat yang menurunkan kitab kepada anda, Allah telah datang dengan kebenaran yang diturunkan kepada anda. (dahulu) Penduduk telaga ini (penduduk Madinah -red) bersepakat untuk memilihnya dan mengangkatnya, namun karena kebenaran yang diberikan kepada anda itu muncul, sehingga menghalanginya (Abdullah bin Ubay) menjabat sebagai pemimpin, maka seperti itulah perbuatannya sebagaimana yang anda lihat.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam memaafkannya, karena itu Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya memaafkan orang-orang kafir dan para Ahli Kitab sebagaimana yang diperintahkan Allah, dan mereka bersabar terhadap gangguan mereka. Allah Ta'ala berfirman: (…kamu sungguh-sungguh akan mendengar dari orang-orang yang diberi Kitab…) QS Ali Imran; 186. dan firman Allah (…Sebahagian besar ahli Kitab menginginkan agar mereka dapat mengembalikan kamu…) QS Al Baqarah; 109. Dan Nabi shallallahu 'alaihi wasallam menafsirkan (ayat di atas) suatu prinsip memberikan ampunan kepada mereka selama Allah memerintahkannya demikian hingga Allah memberikan izin untuk memerangi mereka. Maka ketika Rasulullah shallallahu 'alaihi wasallam memerangi mereka dalam Perang Badar dan Allah membinasakan orang-orang terkemuka Quraisy, maka Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya pun kembali dengan membawa kemenangan, baik harta ghanimah maupun para tawanan dari pembesar-pembesar Qurasy, Abdullah bin Ubay bin Salul dan orang-orang kafir dari para penyembah berhala yang bersamanya berkata; 'Perkara ini (Islam) telah muncul.' Lalu mereka berbaiat atas Islam kepada Rasulullah shallallahu 'alaihi wasallam, akhirnya mereka masuk Islam."},{"p":"Bukhari","n":5442,"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي شَرِيكٌ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ فِي بَيْتِ مَيْمُونَةَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا فَلَمَّا كَانَ ثُلُثُ اللَّيْلِ الْآخِرُ أَوْ بَعْضُهُ قَعَدَ فَنَظَرَ إِلَى السَّمَاءِ فَقَرَأَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ لَآيَاتٍ لِأُولِي الْأَلْبَابِ }","trj":"Telah menceritakan kepada kami [Ibnu Abu Maryam] telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah mengabarkan kepadaku [Syarik] dari [Kuraib] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Aku pernah bermalam di rumah Maimunah, sedangkan Nabi shallallahu 'alaihi wasallam berada di sisinya, tatkala di sepertiga malam terakhir atau sebagian malam, beliau duduk dan memandang ke arah langit sambil membaca: \"Sesungguhnya dalam penciptaan langit dan bumi, dan silih bergantinya malam dan siang terdapat tanda-tanda bagi orang-orang yang berakal.\" QS Ali Imran; 190."},{"p":"Bukhari","n":5835,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ وَمَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبَةٍ يَقْتَطِعَ بِهَا مَالَ رَجُلٍ مُسْلِمٍ أَوْ قَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ }قَالَ سُلَيْمَانُ فِي حَدِيثِهِ فَمَرَّ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا يُحَدِّثُكُمْ عَبْدُ اللَّهِ قَالُوا لَهُ فَقَالَ الْأَشْعَثُ نَزَلَتْ فِيَّ وَفِي صَاحِبٍ لِي فِي بِئْرٍ كَانَتْ بَيْنَنَا","trj":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Syu'bah] dari [Sulaiman] dan [Manshur] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan sumpah dusta untuk menguasai harta seorang muslim -atau ia katakan dengan redaksi untuk menguasai harta saudaranya-- ia bertemu Allah sedang Allah dalam keadaan murka kepadanya.\" Kemudian Allah menurunkan ayat yang membenarkannya; 'Sesungguhnya orang-orang yang menukar janji Allah,,, dst (QS. Ali'Imran 77), [Sulaiman] berkata dalam haditsnya; kemudian Al Asy'ats bin Qais lewat dan berujar; 'Apa yang diceritakan Abdullah kepada kalian? ' Mereka pun menjawabnya dengan suatu jawaban sebagaimana diutarakan Abdullah. Lantas [Asy'ats] menerangkan; 'Sesungguhnya ayat diatas diturunkan tentang saya dan kawan saya karena suatu sumur yang ada diantara kami.'"},{"p":"Bukhari","n":5850,"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِفَدَخَلَ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا حَدَّثَكُمْ أَبُو عَبْدِ الرَّحْمَنِ فَقَالُوا كَذَا وَكَذَا قَالَ فِيَّ أُنْزِلَتْ كَانَتْ لِي بِئْرٌ فِي أَرْضِ ابْنِ عَمٍّ لِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَيِّنَتُكَ أَوْ يَمِينُهُ قُلْتُ إِذًا يَحْلِفُ عَلَيْهَا يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ وَهُوَ فِيهَا فَاجِرٌ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ يَوْمَ الْقِيَامَةِ وَهُوَ عَلَيْهِ غَضْبَانُ","trj":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu menuturkan; Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Barangsiapa bersumpah mengada-ada di depan hakim, dengan tujuan untuk memperoleh harta seorang muslim, maka ia berjumpa dengan Allah dan Allah murka kepadanya, \" kemudian Allah menurunkan ayat yang membenarkan hal ini dengan ayat; 'Sesungguhnya orang-orang yang menukar janji Allah dan sumpah mereka dengan harga yang sedikit' (QS. Ali'imran 77) hingga akhir ayat. Maka [Al Asy'ats bin Qais] masuk dan bertanya; 'Apa yang diceritakan Abu Abdurrahman kepada kalian? ' Mereka menjawab; 'begini dan begini'. Maka Al Asy'ats bin Qais berkata; 'ayat itu diturunkan kepada kami, yang ketika itu saya mempunyai sumur di pekarangan keponakanku, maka kudatangi Rasulullah Shallallahu'alaihi wa sallam dan beliau bersabda: \"Sekarang engkau harus menyertakan bukti kepemiikanmu atau dia melakukan sumpahnya!\" Aku menjawab; 'kalau begitu, dia pasti akan bersumpah Ya Rasulullah! ' Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Barangsiapa bersumpah dengan sumpah dusta (diada-adakan), ia melakukan kejahatan dengan sumpahnya itu dengan tujuan untuk merampas harta seorang muslim, ia akan menjumpai Allah sedang Allah dalam keadaan murka kepadanya.\""},{"p":"Bukhari","n":6313,"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ قَالَ عَبْدُ اللَّهِقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْلِفُ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ مَالًا وَهُوَ فِيهَا فَاجِرٌ إِلَّا لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }الْآيَةَفَجَاءَ الْأَشْعَثُ وَعَبْدُ اللَّهِ يُحَدِّثُهُمْ فَقَالَ فِيَّ نَزَلَتْ وَفِي رَجُلٍ خَاصَمْتُهُ فِي بِئْرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ فَلْيَحْلِفْ قُلْتُ إِذًا يَحْلِفُ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Abu Wa'il] mengatakan, [Abdullah] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda; \"Tidaklah seseorang bersumpah dusta dengan tujuan merampas harta orang lain dan dia bertindak zhalim dengan sumpahnya itu, kecuali ia akan bertemu Allah dan Allah dalam keadaan murka terhadapnya, \" kemudian Allah menurunkan ayat 'Sesungguhnya orang-orang yang membeli janji Allah dan sumpah mereka dengan harga yang sedikit' (QS. Ali'Imran.77), kemudian [Al Asy'ats] datang ketika [Abdullah] sedang menceritakan kepada mereka, dan mengatakan; sebenarnya ayat itu diturunkan kepada saya dan seseorang yang kuajak bersengketa tentang sebuah sumur, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"apa kamu punya bukti?\" \"TIDAK\" Jawabku. Nabi bersabda: \"kalau begitu, suruhlah lawan sengketamu bersumpah!\" maka Abdullah mengatakan; 'Kalau bukti sekedar sumpah, tentu dia akan bersumpah. Lantas turunlah ayat: 'Sesungguhnya orang-orang yang membeli janji Allah dan sumpah mereka dengan harga yang sedikit….sampai akhir ayat ' (QS. Ali'Imran.77) "},{"p":"Bukhari","n":6447,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي صَلَاةِ الْفَجْرِ وَرَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ فِي الْأَخِيرَةِ ثُمَّ قَالَ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }","trj":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibn Umar] ia mendengar nabi shallallahu 'alaihi wasallam berdoa ketika shalat fajar dan ketika mengangkat kepalanya dari rukuk: 'ALLAAHUMMA RABBANAA WALAKAL HAMDU (Ya Allah rabb kami, bagi-Mu segala puji) ', itu beliau ucapkan pada rukuk terakhir. Kemudian beliau berdoa: 'ALLAAHUMMA IL 'AN FULAANAN WAFULAANAN (Ya Allah, laknatlah si A dan si B) '. Lantas Allah menurunkan ayat: '(Sama sekali engkau tidak mempunyai wewenang terhadap urusan mereka itu, Allah mengampuni mereka atau menyiksa mereka, sebab mereka adalah orang-orang yang zhalim) ' (Qs. Ali'Imran: 128)."},{"p":"Bukhari","n":6543,"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنِي شَرِيكُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ فِي بَيْتِ مَيْمُونَةَ لَيْلَةً وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا لِأَنْظُرَ كَيْفَ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَتَحَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَهْلِهِ سَاعَةً ثُمَّ رَقَدَ فَلَمَّا كَانَ ثُلُثُ اللَّيْلِ الْآخِرُ أَوْ بَعْضُهُ قَعَدَ فَنَظَرَ إِلَى السَّمَاءِ فَقَرَأَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ إِلَى قَوْلِهِ لِأُولِي الْأَلْبَابِ }ثُمَّ قَامَ فَتَوَضَّأَ وَاسْتَنَّ ثُمَّ صَلَّى إِحْدَى عَشْرَةَ رَكْعَةً ثُمَّ أَذَّنَ بِلَالٌ بِالصَّلَاةِ فَصَلَّى رَكْعَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى لِلنَّاسِ الصُّبْحَ","trj":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] telah mengabarkan kepadaku [Syarik bin Abdullah bin Abu Namir] dari [Kuraib] dari [Ibn Abbas] mengatakan, \"Suatu malam aku bermalam di rumah maimunah sedang Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam di sisinya, itu kulakukan dengan niat agar aku bisa melihat Shalat Rasulullah Shallallahu'alaihiwasallam ketika malam. Rasulullah Shallallahu'alaihiwasallam berbincang-bincang bersama isterinya beberapa saat, kemudian tidur, ketika sepertiga malam terakhir tiba, atau sebagiannya, beliau duduk dan menatap langit lantas membaca ayat: '(Sesungguhnya dalam penciptaan langit dan bumi hingga ayat terdapat tanda-tanda bagi orang yang berakal) ' (QS. Ali'Imran: 190). Kemudian beliau berdiri dan berwudlu', beliau membersihkan gigi-giginya kemudian shalat sebelas rakaat. Kemudian setelah Bilal mengumandangkan adzan (subuh), beliau shalat dua rakaat, kemudian keluar untuk mengimami orang-orang shalat subuh.\""},{"p":"Bukhari","n":6618,"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ وَامْرَأَةٍ مِنْ الْيَهُودِ قَدْ زَنَيَا فَقَالَ لِلْيَهُودِ مَا تَصْنَعُونَ بِهِمَا قَالُوا نُسَخِّمُ وُجُوهَهُمَا وَنُخْزِيهِمَا قَالَ{ فَأْتُوا بِالتَّوْرَاةِ فَاتْلُوهَا إِنْ كُنْتُمْ صَادِقِينَ }فَجَاءُوا فَقَالُوا لِرَجُلٍ مِمَّنْ يَرْضَوْنَ يَا أَعْوَرُ اقْرَأْ فَقَرَأَ حَتَّى انْتَهَى إِلَى مَوْضِعٍ مِنْهَا فَوَضَعَ يَدَهُ عَلَيْهِ قَالَ ارْفَعْ يَدَكَ فَرَفَعَ يَدَهُ فَإِذَا فِيهِ آيَةُ الرَّجْمِ تَلُوحُ فَقَالَ يَا مُحَمَّدُ إِنَّ عَلَيْهِمَا الرَّجْمَ وَلَكِنَّا نُكَاتِمُهُ بَيْنَنَا فَأَمَرَ بِهِمَا فَرُجِمَا فَرَأَيْتُهُ يُجَانِئُ عَلَيْهَا الْحِجَارَةَ","trj":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Ismail] dari [Ayyub] dari [Nafi'] dari [Ibn Umar] radliyallahu'anhuma berkata, \"Seorang laki-laki dan wanita Yahudi yang berzina didatangkan kepada nabi shallallahu 'alaihi wasallam, Nabi lalu bertanya kepada si Yahudi: 'Hukuman apa biasa kalian lakukan terhadap keduanya? ' Mereka menjawab, 'Kami biasanya menghukum mereka dengan menghitami wajah keduanya dan menghinakannya.' Lantas nabi bersabda (dengan mengutip ayat): '(Maka datangkanlah Taurat dan bacalah, jika kalian orang-orang yang benar) ', (Qs. Ali 'Imran: 93), lantas mereka datang dan mereka katakan kepada seseorang yang mereka percayai, 'Hai A'war bacalah! Lantas A'war membaca hingga sampai ayat (yang berkenaan hukum perzinaan), dengan terburu-buru ia menutupi dengan tangannya, maka Nabi menegur: 'Hai, angkatlah tanganmu! ' Maka ia angkat tangannya. Dan ternyata yang ia tutupi adalah ayat rajam, lantas A'war berkata, 'Hai Muhammad, kedua orang itu wajib dirajam, hanya kami merahasiakannya di antara kami.' Maka Nabi perintahkan agar keduanya dirajam, dan kemudian keduanya pun dirajam. Sungguh, aku lihat yang laki-laki membungkukkan badannya ke arah wanita untuk mencegahnya agar tidak terkena batu.\""},{"p":"Darimi","n":239,"ar":" أَخْبَرَنَا هَارُونُ بْنُ مُعَاوِيَةَ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ أَبِي عَبْدِ اللَّهِ الْخُرَاسَانِيِّ عَنْ الضَّحَّاكِ وَلَكِنْ كُونُوا رَبَّانِيِّينَ بِمَا كُنْتُمْ تُعَلِّمُونَ الْكِتَابَ قَالَ حَقٌّ عَلَى كُلِّ مَنْ قَرَأَ الْقُرْآنَ أَنْ يَكُونَ فَقِيهًا","trj":"Telah mengabarkan kepada kami [Harun bin Mu'awiyah] dari [Hafsh bin Ghiyats] dari [Abi Abdullah Al Khurasani] dari [Ad Dlahaq] -Ia mengomentari ayat- 'Akan tetapi jadilah kalian semua Rabbaniyyun karena kamu selalu mengajarkan Al kitab' (Surat Ali-Imran; 79), dia berkata: \"adalah kewajiban setiap orang yang membaca Al Qur`an untuk menjadi faqih (mengetahui maksud atau isinya secara mendalam) \"."},{"p":"Darimi","n":1194,"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يَدْعُوَ عَلَى أَحَدٍ أَوْ يَدْعُوَ لِأَحَدٍ قَنَتَ بَعْدَ الرُّكُوعِ فَرُبَّمَا قَالَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا سِنِينَ كَسِنِي يُوسُفَ وَيَجْهَرُ بِذَلِكَ يَقُولُ فِي بَعْضِ صَلَاتِهِ فِي صَلَاةِ الْفَجْرِ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا لِحَيَّيْنِ مِنْ أَحْيَاءِ الْعَرَبِ فَأَنْزَلَ اللَّهُ تَعَالَى { لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }","trj":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Ibnu Al Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam jika ingin mendoakan keburukan atas seseorang atau mendoakan kebaikan untuk seseorang, maka beliau melakukan qunut setelah rukuk. Barangkali setelah mengucapkan SAMI'ALLAAHU LIMAN HAMIDAH, RABBANAA WA LAKAL HAMDU (Semoga Allah mendengar pujian orang yang memuji-Nya. Ya Rabb kami, kepada-Mu lah segala pujian), beliau berdoa: \"Ya Allah, selamatkan Al Walid bin Al Walid, Salamah bin Hisyam, 'Ayyasy bin Abu Rabi'ah dan orang-orang Mukmin yang lemah. Ya Allah, keraskan siksa-Mu atas Mudlar, timpakahlah kepada mereka masa paceklik sebagaimana paceklik pada masa Yusuf.\" Beliau mengeraskan doa tersebut. Dan beliau mengucapkan pada sebagian shalatnya; shalat subuh: \"Ya Allah, laknatlah Fulan dan Fulan.\" Beliau menyebutkan dua kampung dari kampung-kampung Arab. Kemudian Allah Ta'ala menurunkan ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka karena sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128)."},{"p":"Darimi","n":1243,"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَ كَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ مَالًا نَخْلًا وَكَانَتْ أَحَبَّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءُ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَائِهَا طَيِّبٌ فَقَالَ أَنَسٌ فَلَمَّا أُنْزِلَتْ هَذِهِ الْآيَةُ { لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ } قَالَ إِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءُ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ شِئْتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخٍ ذَلِكَ مَالٌ رَابِحٌ أَوْ رَائِحٌ وَقَدْ سَمِعْتُ مَا قُلْتَ فِيهِ وَإِنِّي أَرَى أَنْ تَجْعَلَهُ فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَّمَهُ أَبُو طَلْحَةَ فِي قَرَابَةِ بَنِي عَمِّهِ","trj":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas] ia berkata, \"Abu Thalhah adalah orang anshar yang paling banyak hartanya di kota Madinah, yaitu pohon kurma. Harta yang paling ia senangi adalah Bairuha` (kebun kurma) yang menghadap ke masjid. Ia biasa masuk untuk makan (buha) dan meminum airnya yang jernih.\" Anas berkata, \"Kemudian tatkala ayat: '(Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sehahagian harta yang kamu cintai) ' (Qs. Ali Imran: 92). Abu Thalhah berkata, \"Sungguh, hartaku yang paling aku senangi adalah Bairuha`, dan sesungguhnya kebun tersebut adalah sedekah untuk Allah, aku mengharapkan kebaikan dan simpanan pahalanya di sisi Allah. Maka pergunakan di mana engkau kehendaki wahai Rasul! \" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Bakh, itu adalah harta yang menguntungkan, sungguh aku telah mendengar apa yang engkau katakan. Namun menurutku, sebaiknya itu engkau berikan kepada para kerabat.\" Kemudian Abu Thalhah berkata, \"Aku akan melakukannya wahai Rasulullah! \" Abu Thalhah lalu membaginya di antara para kerabat anak pamannya.\""},{"p":"Darimi","n":1750,"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ أَبَا عُبَيْدَةَ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ قَالَ عَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ أَوْ إِنَّ الْحَمْدَ لِلَّهِ نَحْمَدُهُ وَنَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ { يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ } { يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا } { يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا يُصْلِحْ لَكُمْ أَعْمَالَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ وَمَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ فَازَ فَوْزًا عَظِيمًا } ثُمَّ يَتَكَلَّمُ بِحَاجَتِهِ","trj":"Telah menceritakan kepada kami [Abu Al Walid] dan [Hajjaj] keduanya berkata; telah menceritakan kepada kami [Syu'bah] ia berkata; telah memberitakan kepada kami [Abu Ishaq] ia berkata; Aku mendengar [Abu 'Ubaidah] menceritakan dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam mengajarkan kepada kami khutbah hajah, yaitu; \"Al HAMDULILLAAHI atau INNAL HAMDA LILLAAHI NAHMADUHU WA NASTA'IINUHU WA NASTAGHFIRUHU WA NA'UUDZU BILLAAHI MIN SYURUURI ANFUSINAA, MAN YAHDIHILLAAHU FALAA MUDHILLA LAHU WA MAN YUDHLIL FALAA HAADIYA LAHU. ASYHADU AN LAA ILAAHA ILLALLAAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUHU (segala puji bagi Allah, atau sesungguhnya segala puji bagi Allah, kita memujiNya, memohon pertolongan, serta ampunan kepadaNya, dan kita berlindung kepada Allah dari keburukan diri kita, barangsiapa yang Allah beri petunjuk maka tidak ada yang dapat menyesatkannya, dan barangsiapa yang Allah sesatkan maka tidak ada yang dapat memberinya petunjuk. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah, dan aku bersaksi bahwa Mummad adalah hamba dan utusanNya.. Kemudian membaca tiga ayat, yaitu; Hai orang-orang yang beriman, bertakwalah kepada Allah sebenar-benar takwa kepada-Nya; dan janganlah sekali-kali kamu mati melainkan dalam keadaan beragama Islam. QS Ali Imran; 102. Hai sekalian manusia, bertakwalah kepada Tuhan-mu yang telah menciptakan kamu dari seorang diri, dan dari padanya, Allah menciptakan isterinya.\" QS An Nisa`; 1. Hai orang-orang yang beriman, bertakwalah kamu kepada Allah dan katakanlah perkataan yang benar, niscaya Allah memperbaiki bagimu amalan-amalanmu dan mengampuni bagimu dosa-dosamu. Dan barangsiapa mentaati Allah dan Rasul-Nya, maka sesungguhnya ia telah mendapat kemenangan yang besar. QS Al Ahzab; 70-71. Kemudian mengatakan kebutuhannya."},{"p":"Darimi","n":2849,"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا بَشِيرٌ هُوَ ابْنُ الْمُهَاجِرِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ يَقُولُ تَعَلَّمُوا سُورَةَ الْبَقَرَةِ فَإِنَّ أَخْذَهَا بَرَكَةٌ وَتَرْكَهَا حَسْرَةٌ وَلَا يَسْتَطِيعُهَا الْبَطَلَةُ ثُمَّ سَكَتَ سَاعَةً ثُمَّ قَالَ تَعَلَّمُوا سُورَةَ الْبَقَرَةِ وَآلِ عِمْرَانَ فَإِنَّهُمَا الزَّهْرَاوَانِ وَإِنَّهُمَا تُظِلَّانِ صَاحِبَهُمَا يَوْمَ الْقِيَامَةِ كَأَنَّهُمَا غَمَامَتَانِ أَوْ غَيَايَتَانِ أَوْ فِرْقَانِ مِنْ طَيْرٍ صَوَافَّ وَإِنَّ الْقُرْآنَ يَلْقَى صَاحِبَهُ يَوْمَ الْقِيَامَةِ حِينَ يَنْشَقُّ عَنْهُ الْقَبْرُ كَالرَّجُلِ الشَّاحِبِ فَيَقُولُ لَهُ هَلْ تَعْرِفُنِي فَيَقُولُ مَا أَعْرِفُكَ فَيَقُولُ أَنَا صَاحِبُكَ الْقُرْآنُ الَّذِي أَظْمَأْتُكَ فِي الْهَوَاجِرِ وَأَسْهَرْتُ لَيْلَكَ وَإِنَّ كُلَّ تَاجِرٍ مِنْ وَرَاءِ تِجَارَتِهِ وَإِنَّكَ الْيَوْمَ مِنْ وَرَاءِ كُلِّ تِجَارَةٍ فَيُعْطَى الْمُلْكَ بِيَمِينِهِ وَالْخُلْدَ بِشِمَالِهِ وَيُوضَعُ عَلَى رَأْسِهِ تَاجُ الْوَقَارِ وَيُكْسَى وَالِدَاهُ حُلَّتَيْنِ لَا يُقَوَّمُ لَهُمَا الدُّنْيَا فَيَقُولَانِ بِمَ كُسِينَا هَذَا وَيُقَالُ لَهُمَا بِأَخْذِ وَلَدِكُمَا الْقُرْآنَ ثُمَّ يُقَالُ لَهُ اقْرَأْ وَاصْعَدْ فِي دَرَجِ الْجَنَّةِ وَغُرَفِهَا فَهُوَ فِي صُعُودٍ مَا دَامَ يَقْرَأُ هَذًّا كَانَ أَوْ تَرْتِيلًا","trj":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Basyir] ia adalah Ibnu Al Muhajir telah menceritakan kepadaku [Abdullah bin Buraidah] dari [ayahnya] ia berkata; Aku pernah duduk di sebelah Nabi shallallahu 'alaihi wasallam, aku mendengar beliau bersabda: \"Pelajarilah surat Al Baqarah sebab mempelajarinya adalah keberkahan dan meninggalkannya adalah kerugian. Para penyihir tidak mampu mengalahkannya.\" Kemudian beliau diam sesaat, lalu bersabda: \"Pelajarilah surah Al Baqarah dan surah Ali Imran, sesungguhnya kedua surat itu dinamakan 'az zahrawan' dan kedua surat itu juga akan menaungi pembacanya pada hari kiamat. Seakan-akan kedua surat itu seperti dua buah awan atau dua benda yang biasa menaungi manusia atau dua kelompok burung yang membentangkan sayapnya. Sesungguhnya Al Qur'an akan menemui pembacanya pada hari kiamat ketika kubur terbelah seperti seorang laki-laki pucat karena takut. Ia berkata kepada pembacanya; Apakah engkau mengenalku? Ia menjawab; Aku tidak mengenalmu. Ia berkata; Aku adalah temanmu, Al Qur'an, yang menghilangkan haus pada siang hari yang panas dan membuatmu begadang di malam hari. Sesungguhnya setiap pedagang akan mendapatkan laba dari perdagangannya. Sesungguhnya hari ini engkau mendapatkan pahala dari setiap perdagangan (yang telah engkau lakukan). Lalu kerajaan diberikan di tangan kanan pembaca Al Qur'an itu dan keabadian di tangan kirinya, serta diletakkan mahkota ketenangan di kepalanya. Sementara kedua orang tuanya diberi dua perhiasan yang tidak ternilai harganya di dunia. Kedua orang tuanya berkata; Karena apa kami diberi perhiasan ini? Dikatakan kepada keduanya; Karena anak kalian mempelajari Al Qur'an. Kemudian dikatakan kepadanya; Bacalah dan naiklah ke tangga-tangga surga dan kamar-kamarnya. Maka ia pun terus naik selama ia membaca, baik secara cepat maupun secara lambat.\" "},{"p":"Darimi","n":2850,"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي مُعَاوِيَةُ عَنْ أَبِي يَحْيَى سُلَيْمِ بْنِ عَامِرٍ أَنَّهُ سَمِعَ أَبَا أُمَامَةَ يَقُولُ إِنَّ أَخًا لَكُمْ أُرِيَ فِي الْمَنَامِ أَنَّ النَّاسَ يَسْلُكُونَ فِي صَدْعِ جَبَلٍ وَعْرٍ طَوِيلٍ وَعَلَى رَأْسِ الْجَبَلِ شَجَرَتَانِ خَضْرَاوَانِ تَهْتِفَانِ هَلْ فِيكُمْ مَنْ يَقْرَأُ سُورَةَ الْبَقَرَةِ هَلْ فِيكُمْ مَنْ يَقْرَأُ سُورَةَ آلِ عِمْرَانَ فَإِذَا قَالَ الرَّجُلُ نَعَمْ دَنَتَا بِأَعْذَاقِهِمَا ��َتَّى يَتَعَلَّقَ بِهِمَا فَتَخْطِرَانِ بِهِ الْجَبَلَ قَالَ أَبُو مُحَمَّد الْأَعْذَاقُ الْأَغْصَانُ","trj":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Mu'awiyah] dari [Abu Yahya Sulaim bin Amir] bahwa ia mendengar [Abu Umamah] berkata; Sesungguhnya ada seorang saudara kalian yang diperlihatkan dalam mimpi bahwa manusia berjalan di jalan setapak sebuah gunung yang tidak rata lagi panjang. Di puncak gunung itu ada dua batang pohon hijau yang bersuara; Apakah di antara kalian ada orang yang membaca surah Al Baqarah? Apakah di antara kalian ada orang yang membaca surah Ali Imran? Tiba-tiba ada seseorang menjawab; Ya, maka kedua pohon itu mendekatkan dahannya hingga orang itu dapat meraihnya. Lalu kedua pohon itu membawanya melewati gunung. Abu Muhammad berkata; Al A'dzaq berarti dahan pohon."},{"p":"Darimi","n":2851,"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ زَيْدٍ عَنْ جَابِرٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَ قَرَأَ رَجُلٌ عِنْدَ عَبْدِ اللَّهِ الْبَقَرَةَ وَآلَ عِمْرَانَ فَقَالَ قَرَأْتَ سُورَتَيْنِ فِيهِمَا اسْمُ اللَّهِ الْأَعْظَمُ الَّذِي إِذَا دُعِيَ بِهِ أَجَابَ وَإِذَا سُئِلَ بِهِ أَعْطَى","trj":"Telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi] dari [Ubaidullah bin Amr] dari [Zaid] dari [Jabir] dari [Abu Adl Dluha] dari [Masruq] dari [Abdullah] ia berkata; Ada seseorang membaca surat Al Baqarah dan surat Ali Imran di samping Abdullah, lalu ia pun berkata; Engkau telah membaca dua surat yang di dalamnya terdapat nama Allah yang paling agung, yang apabila digunakan ketika berdoa pasti diperkenankan dan apabila digunakan ketika meminta pasti dikabulkan."},{"p":"Darimi","n":2852,"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي عَطَّافٍ عَنْ كَعْبٍ قَالَ مَنْ قَرَأَ الْبَقَرَةَ وَآلَ عِمْرَانَ جَاءَتَا يَوْمَ الْقِيَامَةِ تَقُولَانِ رَبَّنَا لَا سَبِيلَ عَلَيْهِ","trj":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Al Jurairi] dari [Abu 'Aththaf] dari [Ka'b] ia berkata; Barangsiapa yang membaca surat Al Baqarah dan surat Ali Imran, maka kedua surat itu akan datang pada hari kiamat seraya berkata; Wahai Rabb kami, tidak ada alasan untuk mencelakainya."},{"p":"Darimi","n":2853,"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ سُلَيْمِ بْنِ حَنْظَلَةَ الْبَكْرِيِّ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ مَنْ قَرَأَ آلَ عِمْرَانَ فَهُوَ غَنِيٌّ وَالنِّسَاءُ مُحَبِّرَةٌ قَالَ أَبُو مُحَمَّد مُحَبِّرَةٌ مُزَيِّنَةٌ","trj":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Sulaim bin Hanzhalah Al Bakri] ia berkata; [Abdullah bin Mas'ud] berkata; Barangsiapa yang membaca surat Ali Imran maka ia adalah orang kaya, sedangkan jika ia seorang perempuan maka ia adalah orang yang berhias. [Abu Muhammad] berkata; Muhabbirah berarti perempuan yang berhias."},{"p":"Darimi","n":2854,"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى عَنْ ابْنِ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَ مَنْ قَرَأَ آخِرَ آلِ عِمْرَانَ فِي لَيْلَةٍ كُتِبَ لَهُ قِيَامُ لَيْلَةٍ","trj":"Telah menceritakan kepada kami [Ishaq bin Isa] dari [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Utsman bin 'Affan] ia berkata; Barangsiapa yang membaca akhir surat Ali Imran pada malam hari, maka ditulis baginya pahala shalat malam."},{"p":"Darimi","n":2855,"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ مَكْحُولٍ قَالَ مَنْ قَرَأَ سُورَةَ آلِ عِمْرَانَ يَوْمَ الْجُمُعَةِ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ إِلَى اللَّيْلِ","trj":"Telah menceritakan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Shadaqah bin Khalid] dari [Yahya bin Al Harits] dari [Makhul] ia berkata; Barangsiapa yang membaca surat Ali Imran pada hari Jum'at, maka para malaikat mendo'akan untuknya sampai tiba malam hari."},{"p":"Darimi","n":2856,"ar":" حَدَّثَنَا الْقَاسِمُ بْنُ سَلَّامٍ أَبُو عُبَيْدٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ حَدَّثَنِي مِسْعَرٌ حَدَّثَنِي جَابِرٌ قَبْلَ أَنْ يَقَعَ فِيمَا وَقَعَ فِيهِ عَنْ الشَّعْبِيِّ قَالَ قَالَ عَبْدُ اللَّهِ نِعْمَ كَنْزُ الصُّعْلُوكِ سُورَةُ آلِ عِمْرَانَ يَقُومُ بِهَا فِي آخِرِ اللَّيْلِ","trj":"Telah menceritakan kepada kami [Al Qasim bin Sallam Abu Ubaid] ia berkata; Telah menceritakan kepadaku [Ubaidullah Al Asyja'i] telah menceritakan kepadaku [Mis'ar] telah menceritakan kepadaku [Jabir] sebelum terjadi sesuatu padanya, dari [Asy Sya'bi] ia berkata; [Abdullah] berkata; Sebaik-baik perbendaharaan orang fakir adalah surat Ali Imran yang ia baca ketika melakukan shalat di akhir malam."},{"p":"Darimi","n":2857,"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ السَّلَامِ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي السَّلِيلِ قَالَ أَصَابَ رَجُلٌ دَمًا قَالَ فَأَوَى إِلَى وَادِي مَجَنَّةٍ وَادٍ لَا يُمْسِي فِيهِ أَحَدٌ إِلَّا أَصَابَتْهُ حَيَّةٌ وَعَلَى شَفِيرِ الْوَادِي رَاهِبَانِ فَلَمَّا أَمْسَى قَالَ أَحَدُهُمَا لِصَاحِبِهِ هَلَكَ وَاللَّهِ الرَّجُلُ قَالَ فَافْتَتَحَ سُورَةَ آلِ عِمْرَانَ قَالَا فَقَرَأَ سُورَةً طَيِّبَةً لَعَلَّهُ سَيَنْجُو قَالَ فَأَصْبَحَ سَلِيمًا قَالَ أَبُو مُحَمَّد أَبُو السَّلِيلِ ضُرَيْبُ بْنُ نُقَيْرٍ","trj":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abdus Salam] dari [Al Jurairi] dari [Abu As Salil] ia berkata; Ada seseorang terluka mengeluarkan darah. Ia melanjutkan; Lalu orang itu singgah di lembah Majannah, sebuah lembah yang tidak seorang pun berada di waktu sore kecuali menjadi gila, sementara di tepi lembah ada dua orang pendeta. Ketika orang itu berada di waktu sore, salah seorang pendeta berkata kepada temannya; Demi Allah, celakalah orang itu. Ia melanjutkan; Lalu orang itu membaca awal surat Ali Imran, maka kedua pendeta tersebut berkata; Ia telah membaca sebuah surat yang baik, semoga ia selamat. Ia berkata lagi; Maka selamatlah orang itu. [Abu Muhammad] berkata; Abu As Salil adalah Dluraib bin Nuqair. "},{"p":"Ibnu Majah","n":1320,"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ خَلَّادٍ الْبَاهِلِيُّ حَدَّثَنَا مَعْنُ بْنُ عِيسَى حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ أَخْبَرَهُأَنَّهُ نَامَ عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ آيَاتٍ مِنْ آخِرِ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ أُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ","trj":"Telah menceritakan kepada kami [Abu Bakr bin Khallad Al Bahili] berkata, telah menceritakan kepada kami [Ma'n bin Isa] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Makhramah bin Sulaiman] dari [Kuraib] -mantan budak Ibnu Abbas- dari [Ibnu Abbas] ia mengabarkan kepadanya, bahwa ia pernah tidur di rumah Maimunah, isteri Nabi shallallahu 'alaihi wasallam -Maimunah adalah bibinya- ia berkata, \"Aku berbaring di bantal bagian sisinya, sementara Nabi shallallahu 'alaihi wasallam dan isterinya di bagian tengahnya. Hingga pada pertengahan malam atau kurang sedikit, atau lewat tengah malam atau lebih sedikit, Nabi shallallahu 'alaihi wasallam bangun seraya mengusap mukanya dengan kedua tangan sambil membaca sepuluh ayat terakhir surat Ali Imran. Setelah itu beliau berdiri menuju girbah (bejana) kulit yang tergantung, beliau wudlu darinya dan membaguskan wudlunya kemudian melaksanakan shalat. \" Abdullah bin Abbas berkata, \"Kemudian aku bangun dan melakukan sebagaimana yang beliau lakukan, aku berjalan dan berdiri di sisinya. Rasulullah shallallahu 'alaihi wasallam kemudian meletakkan tangan kanannya di kepalaku meraih daun telinga, beliau menggeser posisiku. Setelah itu beliau shalat dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian witir. Lalu beliau berbaring hingga tukang adzannya mendatanginya, beliau lalu shalat dua raka'at ringan baru kemudian keluar untuk melaksanakan shalat (subuh). \""},{"p":"Ibnu Majah","n":3504,"ar":"حَدَّثَنَا هَارُونُ بْنُ حَيَّانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَنْبَأَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو جَنَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ أَبِي لَيْلَى قَالَكُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ أَعْرَابِيٌّ فَقَالَ إِنَّ لِي أَخًا وَجِعًا قَالَ مَا وَجَعُ أَخِيكَ قَالَ بِهِ لَمَمٌ قَالَ اذْهَبْ فَأْتِنِي بِهِ قَالَ فَذَهَبَ فَجَاءَ بِهِ فَأَجْلَسَهُ بَيْنَ يَدَيْهِ فَسَمِعْتُهُ عَوَّذَهُ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ الْبَقَرَةِ وَآيَتَيْنِ مِنْ وَسَطِهَا{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ خَاتِمَتِهَا وَآيَةٍ مِنْ آلِ عِمْرَانَ أَحْسِبُهُ قَالَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ }الْآيَةَ وَآيَةٍ مِنْ الْمُؤْمِنِينَ{ وَمَنْ يَدْعُ مَعَ اللَّهِ إِلَهًا آخَرَ لَا بُرْهَانَ لَهُ بِهِ }وَآيَةٍ مِنْ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا مَا اتَّخَذَ صَاحِبَةً وَلَا وَلَدًا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الْأَعْرَابِيُّ قَدْ بَرَأَ لَيْسَ بِهِ بَأْسٌ","trj":"Telah menceritakan kepada kami [Harun bin Hayyan] telah menceritakan kepada kami [Ibrahim bin Musa] telah memberitakan kepada kami ['Abdah bin Sulaiman] telah menceritakan kepada kami [Abu Janab] dari [Abdurrahman bin Abu Laila] dari ayahnya [Abu Laila] dia berkata, \"Ketika aku sedang duduk di samping Nabi shallallahu 'alaihi wasallam, tiba-tiba datang seorang Arab Badui seraya berkata, 'Sesungguhnya aku mempunyai saudara yang menderita sakit.\" Beliau bertanya: \"Apa sakit yang meninmpa saudaramu?\" Dia menjawab, \"Dia terserang ayan.\" Beliau bersabda: \"Pergi dan bawalah dia kesini.\" Maka dia pergi dan kembali (kepada beliau) bersama saudaranya dan mendudukkannya di depan beliau, maka aku mendengar beliau memberikan perlindungan kepadanya dengan Al Fatihah, empat ayat dari permulaan surat Al Baqarah, dua ayat dari tengahnya dan (ayat) WA ILAAHUKUM ILAAHUWWAAHID (dan tuhan kalian adalah tuhan yang satu), ayat kursi, tiga ayat dari penghujung surat Al Baqarah, dan satu ayat dari surat Ali 'Imran. Aku yakin beliau mengucapkan: \"SYAHIDALLAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah bersaksi bahwa tidak ada ilah yang berhak disembah kecuali Dia) '. Beliau juga membaca satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAHULLADZI KHALAQ (sesungguhnya Rabb kalian adalah yang menciptakan) ', satu ayat dari surat Al MuKminun: WA MAN YADA'U MA'ALLAHI ILAAHNA AAKHAR LAA BURHAANA LAHU BIHI '(Dan barang siapa yang menyeru bersama dengan Allah yaitu ilah yang lain, maka tidak ada petunjuk baginya), satu ayat dari surat Al Jin: WA ANNAHU TA'ALA JADDU RABBINAA MATTAKHADZA SHAAHIBATAN WA LAA WALADA (Dan bahwasannya Maha Tinggi kebesaran Rabb kami, Dia tidak beristeri dan tidak (pula) beranak) '. Sepuluh ayat dari surat Ash Shaffaat, tiga ayat dari akhir surat Al Hasyr, dan QULHUWALLAHU AHAD, dan dua mu'awidzatain. Kemudian orang Arab Badui itu bangun dan sembuh seakan-akan tidak menderita sakit.\""},{"p":"Ibnu Majah","n":3809,"ar":"حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ سُورَةِ آلِ عِمْرَانَ","trj":"Telah menceritakan kepada kami [Abu Bakar] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidillah bin Abu Ziyad] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Nama Allah yang Agung terdapat di dalam dua ayat ini; Dan Rabbmu adalah Rabb yang Maha Esa, tidak ada ilah (yang berhak di sembah) selain Dia, yang Maha pemurah lagi Maha penyayang.\" Qs Al Baqarah; 163, dan pembukaan surat Ali Imran.\""},{"p":"Malik","n":158,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ أَبِي عُبَيْدٍ مَوْلَى سُلَيْمَانَ بْنِ عَبْدِ الْمَلِكِ عَنْ عُبَادَةَ بْنِ نُسَيٍّ عَنْ قَيْسِ بْنِ الْحَارِثِ عَنْ أَبِي عَبْدِ اللَّهِ الصُّنَابِحِيِّ قَالَقَدِمْتُ الْمَدِينَةَ فِي خِلَافَةِ أَبِي بَكْرٍ الصِّدِّيقِ فَصَلَّيْتُ وَرَاءَهُ الْمَغْرِبَ فَقَرَأَ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ بِأُمِّ الْقُرْآنِ وَسُورَةٍ سُورَةٍ مِنْ قِصَارِ الْمُفَصَّلِ ثُمَّ قَامَ فِي الثَّالِثَةِ فَدَنَوْتُ مِنْهُ حَتَّى إِنَّ ثِيَابِي لَتَكَادُ أَنْ تَمَسَّ ثِيَابَهُ فَسَمِعْتُهُ قَرَأَ بِأُمِّ الْقُرْآنِ وَبِهَذِهِ الْآيَةِ{ رَبَّنَا لَا تُزِغْ قُلُوبَنَا بَعْدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِنْ لَدُنْكَ رَحْمَةً إِنَّكَ أَنْتَ الْوَهَّابُ }","trj":"Telah menceritakan kepadaku dari Malik dari [Abu 'Ubaid] mantan budak Sulaiman bin Abdul Malik, dari [Ubadah bin Nusai] dari [Qais bin Al Harits] dari [Abu Abdullah Ash Shunabihi] ia berkata; \"Aku datang ke Madinah pada masa kekhilafahan [Abu Bakar As Shiddiq] . Lalu aku shalat maghrib di belakangnya, dia membaca Ummul Qur'an pada dua rakaat pertama dan surat-surat Al Mufashshal yang pendek. Kemudian dia berdiri menuju rakaat yang ketiga, lalu aku mendekat kepadanya hingga kainku hampir menempel pakaiannya. Aku mendengar ia membaca Ummul Qur'an dan ayat ini; '(Ya Tuhan kami, janganlah Engkau jadikan hati kami condong kepada kesesatan sesudah Engkau beri petunjuk kepada kami, dan karuniakanlah kepada kami Rahmat dari sisi Engkau; Karena Engkau-lah Maha pemberi (karunia) '.\" (Qs. Ali Imran: 8) . "},{"p":"Malik","n":244,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ لَيْلَةً عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقٍ فَتَوَضَّأَ مِنْهُ فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ ابْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى أَتَاهُ الْمُؤَذِّنُ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَ","trj":"Telah menceritakan kepadaku dari Malik dari [Mahramah bin Sulaiman] dari [Kuraib] budak Ibnu 'Abbas, bahwa [Abdullah bin Abbas] mengabarkan kepadanya, bahwa ia pernah bermalam di tempat Maimunah, isteri Nabi shallallahu 'alaihi wasallam, yaitu bibi dari pihak ibunya. Abdullah bin Abbas berkata; \"Saya berbaring di atas bantal pada bagian sisinya, sedangkan Rasulullah shallallahu 'alaihi wasallam dan isterinya berbaring pada bagian sisi panjangnya. Rasulullah shallallahu 'alaihi wasallam tidur hingga ketika sampai pertengahan malam, atau kurang sedikit, atau lewat sedikit, beliau bangun. Beliau kemudian duduk sambil mengusap rasa kantuk dari wajah dengan tangan. Dan beliau membaca sepuluh ayat terakhir dari surat Ali Imran, lalu berdiri menuju geriba yang tergantung. Beliau berwudlu dengan menyempurnakan wudlunya, setelahitu berdiri shalat. Ibnu Abbas berkata, \"Kemudian aku bangun dan melakukan sebagaimana yang dilakukan oleh beliau, lalu aku pergi dan shalat di sisinya. Rasulullah shallallahu 'alaihi wasallam lalu meletakkan tangan kanannya di atas kepalaku seraya memegang telinga kananku dan menariknya (memalingkan) . Beliau lalu shalat dua rakaat, dua rakaat, dua rakaat, dua rakaat, dua rakaat, dan dua rakaat. Kemudian beliau shalat witir. Setelah itu beliau berbaring hingga muaddzin datang kepadanya. Beliau shalat ringan dua rakaat kemudian keluar shalat subuh.\""},{"p":"Malik","n":849,"ar":"و حَدَّثَنِي عَنْ مَالِك عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَ كَتَبَ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ إِلَى عُمَرَ بْنِ الْخَطَّابِيَذْكُرُ لَهُ جُمُوعًا مِنْ الرُّومِ وَمَا يَتَخَوَّفُ مِنْهُمْ فَكَتَبَ إِلَيْهِ عُمَرُ بْنُ الْخَطَّابِ أَمَّا بَعْدُ فَإِنَّهُ مَهْمَا يَنْزِلْ بِعَبْدٍ مُؤْمِنٍ مِنْ مُنْزَلِ شِدَّةٍ يَجْعَلْ اللَّهُ بَعْدَهُ فَرَجًا وَإِنَّهُ لَنْ يَغْلِبَ عُسْرٌ يُسْرَيْنِ وَأَنَّ اللَّهَ تَعَالَى يَقُولُ فِي كِتَابِهِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اصْبِرُوا وَصَابِرُوا وَرَابِطُوا وَاتَّقُوا اللَّهَ لَعَلَّكُمْ تُفْلِحُونَ }","trj":"Telah menceritakan kepadaku dari Malik dari [Zaid bin Aslam] berkata; \"Abu Ubaidah bin Al Jarrah menulis surat kepada Umar bin Al Khattab tentang jumlah pasukan Ramawi dan ketakutan (kaum muslimin) terhadap mereka. Lalu [Umar bin Khattab] membalas kepadanya; \"Amma ba'du: Sekiranya turun penderitaan kepada seorang hamba yang beriman, niscaya Allah akan menjadikan kemudahan setelah itu. Sesungguhnya satu kesulitan tidak akan bisa mengalahkan dua kemudahan, Allah berfirman dalam kitab-Nya: '(Hai orang-orang yang beriman, Bersabarlah kamu dan kuatkanlah kesabaranmu dan tetaplah bersiap siaga (di perbatasan negerimu) dan bertakwalah kepada Allah, supaya kamu beruntung) ' (Qs. Ali Imran: 200)"},{"p":"Malik","n":1575,"ar":"و حَدَّثَنِي مَالِك عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ مَالًا مِنْ نَخْلٍ وَكَانَ أَحَبَّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءَ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَاءٍ فِيهَا طَيِّبٍ قَالَ أَنَسٌ فَلَمَّا أُنْزِلَتْ هَذِهِ الْآيَةُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَامَ أَبُو طَلْحَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }وَإِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءَ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ شِئْتَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخْ ذَلِكَ مَالٌ رَابِحٌ ذَلِكَ مَالٌ رَابِحٌ وَقَدْ سَمِعْتُ مَا قُلْتَ فِيهِ وَإِنِّي أَرَى أَنْ تَجْعَلَهَا فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَمَهَا أَبُو طَلْحَةَ فِي أَقَارِبِهِ وَبَنِي عَمِّهِ","trj":"Telah menceritakan kepadaku Malik dari [Ishaq bin Abdullah bin Abu Thalhah] Bahwasanya ia mendengar [Anas bin Malik] berkata, \"Abu Thalhah adalah orang Anshar yang paling banyak hartanya di Madinah yang berupa kurma. Adapun harta yang paling dia sukai ialah Bairuha yang berada di depan masjid. Rasulullah shallallahu 'alaihi wasallam biasa memasukinya dan minum dari airnya yang jernih.\" Anas berkata; \"Ketika ayat ini diturunkan: '(Kalian sekali-kali tidak akan mendapatkan kebaikan (yang sempurna) sehingga kalian menginfakkan sebagian harta yang kalian sukai) .' (Qs. Ali Imran: 92) Abu Thalhah berdiri menghadap Rasulullah shallallahu 'alaihi wasallam kemudian berkata; 'Wahai Rasulullah, Allah Tabaraka Wa Ta'ala berfirman: '(Kalian sekali-kali tidak akan mendapatkan kebaikan (yang sempurna) sehingga kalian menginfakkan sebagian harta yang kalian sukai) ', sungguh harta yang paling aku sukai adalah Bairuha, kebun itu saya infakkan karena Allah, aku harap kebaikannya dan penyimpanannya di sisi Allah. Wahai Rasulullah, pergunakanlah harta tersebut sebagaimana anda kehendaki.\" Anas berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hebat…! Itu adalah harta yang menguntungkan, itu adalah harta yang menguntungkan. Aku telah mendengar apa yang engkau katakan. Menurutku sebaiknya kamu memberikannya kepada karib kerabat.' Maka Abu Thalhah berkata, \"Wahai Rasulullah, akan aku lakukan.\" Kemudian dia membaginya untuk keluarga dan anak pamannya.\""},{"p":"Muslim","n":196,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَاللَّفْظُ لَهُ أَخْبَرَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ هُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُقَالَ فَدَخَلَ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا يُحَدِّثُكُمْ أَبُو عَبْدِ الرَّحْمَنِ قَالُوا كَذَا وَكَذَا قَالَ صَدَقَ أَبُو عَبْدِ الرَّحْمَنِ فِيَّ نَزَلَتْ كَانَ بَيْنِي وَبَيْنَ رَجُلٍ أَرْضٌ بِالْيَمَنِ فَخَاصَمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ لَكَ بَيِّنَةٌ فَقُلْتُ لَا قَالَ فَيَمِينُهُ قُلْتُ إِذَنْ يَحْلِفُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ هُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ يَسْتَحِقُّ بِهَا مَالًا هُوَ فِيهَا فَاجِرٌ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِ الْأَعْمَشِ غَيْرَ أَنَّهُ قَالَ كَانَتْ بَيْنِي وَبَيْنَ رَجُلٍ خُصُومَةٌ فِي بِئْرٍ فَاخْتَصَمْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ شَاهِدَاكَ أَوْ يَمِينُهُ","trj":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki']. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abu Muawiyah] dan [Waki']. (dalam riwayat lain disebutkan) Dan telah menceritakan kepada kami [Ishaq bin Ibrahim al-Hanzhali] dan lafazh tersebut miliknya, telah mengabarkan kepada kami [Waki'] telah menceritakan kepada kami [al-A'masy] dari [Abu Wail] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa bersumpah atas untuk mengambil harta seorang muslim, maka karena itu ia menjadi seorang yang durhaka, dia akan bertemu Allah sementara Allah murka kepadanya.\" Perawi berkata, \"Lalu [al-Ats'asy bin Qais] masuk seraya bertanya, \"Apa yang diceritakan Abu Abdurrahman kepada kalian?\" Mereka menjawab, \"Demikian dan demikian.\" Asy'ats berkata, \"Abu Abdurrahman benar, hadits tersebut turun berkenaan denganku. Ada perselisihan antara aku dengan seorang laki-laki tentang tanah di Yaman, lalu aku mengajukan hal itu ke hadapan Nabi shallallahu 'alaihi wasallam, maka beliau bertanya: 'Apakah kamu mempunyai bukti'. Aku menjawab, 'Tidak.' Beliau bersabda: \"Maka sumpahnya (dijadikan sebagai alat hukum).' Aku berkata, 'Jadi dia bersumpah? ' Saat itu juga beliau langsung bersabda: \"Barangsiapa bersumpah untuk mengambil harta seorang Muslim, maka karena itu ia menjadi seorang yang durhaka, dia akan bertemu Allah sementara Allah murka kepadanya.\" Lalu turunlah ayat: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit, mereka itu tidak mendapat bahagian (pahala) di akhirat, dan Allah tidak akan berkata-kata dengan mereka dan tidak akan melihat kepada mereka pada hari kiamat dan tidak (pula) akan mensucikan mereka. Bagi mereka azab yang pedih) ' (Qs. Ali Imran: 77). Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Abu Wail] dari [Abdullah] dia berkata, 'Barangsiapa bersumpah untuk mendapatkan harta (orang lain), maka karena itu ia menjadi seorang yang durhaka, dan ia akan berjumpa dengan Allah sementara Allah dalam kondisi murka kepadanya.\" Kemudian dia menyebutkan semisal hadits al-A'masy, hanya saja dia menyebutkan, \"Pernah terjadi perselisihan antara aku dengan seorang laki-laki dalam masalah sumur. Maka kami mengadukannya kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lalu bersabda: \"Hendaklah kamu menghadirkan dua saksi, atau dia bersumpah'.\""},{"p":"Muslim","n":197,"ar":"و حَدَّثَنَا ابْنُ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ عَنْ جَامِعِ بْنِ أَبِي رَاشِدٍ وَعَبْدِ الْمَلِكِ بْنِ أَعْيَنَ سَمِعَا شَقِيقَ بْنَ سَلَمَةَ يَقُولُ سَمِعْتُ ابْنَ مَسْعُودٍ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَلَفَ عَلَى مَالِ امْرِئٍ مُسْلِمٍ بِغَيْرِ حَقِّهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ قَالَ عَبْدُ اللَّهِ ثُمَّ قَرَأَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِصْدَاقَهُ مِنْ كِتَابِ اللَّهِ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","trj":"Dan telah menceritakan kepada kami [Ibnu Abu Umar al-Makki] telah menceritakan kepada kami [Sufyan] dari [Jami' bin Abu Rasyid] dan [Abdul Malik bin A'yan] keduanya mendengar [Syaqiq bin Salamah] berkata, saya mendengar [Ibnu Mas'ud] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah atas harta seorang muslim tanpa haknya, niscaya dia menemui Allah, sedangkan Dia dalam keadaan marah kepadanya.\" Abdullah berkata, \"Kemudian Rasulullah membacakan untuk kami dalilnya dari Kitabullah: '(Sesungguhnya orang-orang yang menjual janji Allah dan sumpah mereka dengan harga yang murah…) ' (Qs. Ali Imran: 77), hingga akhir ayat.\""},{"p":"Muslim","n":277,"ar":"و حَدَّثَنَا حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا أَبُو عَاصِمٍ يَعْنِي مُحَمَّدَ بْنَ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي يَزِيدُ الْفَقِيرُ قَالَكُنْتُ قَدْ شَغَفَنِي رَأْيٌ مِنْ رَأْيِ الْخَوَارِجِ فَخَرَجْنَا فِي عِصَابَةٍ ذَوِي عَدَدٍ نُرِيدُ أَنْ نَحُجَّ ثُمَّ نَخْرُجَ عَلَى النَّاسِ قَالَ فَمَرَرْنَا عَلَى الْمَدِينَةِ فَإِذَا جَابِرُ بْنُ عَبْدِ اللَّهِ يُحَدِّثُ الْقَوْمَ جَالِسٌ إِلَى سَارِيَةٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِذَا هُوَ قَدْ ذَكَرَ الْجَهَنَّمِيِّينَ قَالَ فَقُلْتُ لَهُ يَا صَاحِبَ رَسُولِ اللَّهِ مَا هَذَا الَّذِي تُحَدِّثُونَ وَاللَّهُ يَقُولُ{ إِنَّكَ مَنْ تُدْخِلْ النَّارَ فَقَدْ أَخْزَيْتَهُ }وَ{ كُلَّمَا أَرَادُوا أَنْ يَخْرُجُوا مِنْهَا أُعِيدُوا فِيهَا }فَمَا هَذَا الَّذِي تَقُولُونَ قَالَ فَقَالَ أَتَقْرَأُ الْقُرْآنَ قُلْتُ نَعَمْ قَالَ فَهَلْ سَمِعْتَ بِمَقَامِ مُحَمَّدٍ عَلَيْهِ السَّلَام يَعْنِي الَّذِي يَبْعَثُهُ اللَّهُ فِيهِ قُلْتُ نَعَمْ قَالَ فَإِنَّهُ مَقَامُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَحْمُودُ الَّذِي يُخْرِجُ اللَّهُ بِهِ مَنْ يُخْرِجُ قَالَ ثُمَّ نَعَتَ وَضْعَ الصِّرَاطِ وَمَرَّ النَّاسِ عَلَيْهِ قَالَ وَأَخَافُ أَنْ لَا أَكُونَ أَحْفَظُ ذَاكَ قَالَ غَيْرَ أَنَّهُ قَدْ زَعَمَ أَنَّ قَوْمًا يَخْرُجُونَ مِنْ النَّارِ بَعْدَ أَنْ يَكُونُوا فِيهَا قَالَ يَعْنِي فَيَخْرُجُونَ كَأَنَّهُمْ عِيدَانُ السَّمَاسِمِ قَالَ فَيَدْخُلُونَ نَهَرًا مِنْ أَنْهَارِ الْجَنَّةِ فَيَغْتَسِلُونَ فِيهِ فَيَخْرُجُونَ كَأَنَّهُمْ الْقَرَاطِيسُفَرَجَعْنَا قُلْنَا وَيْحَكُمْ أَتُرَوْنَ الشَّيْخَ يَكْذِبُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَجَعْنَا فَلَا وَاللَّهِ مَا خَرَجَ مِنَّا غَيْرُ رَجُلٍ وَاحِدٍ أَوْ كَمَا قَالَ أَبُو نُعَيْمٍ","trj":"Dan telah menceritakan kepada kami [Hajjaj bin asy-Syair] telah menceritakan kepada kami [al-Fadll bin Dukain] telah menceritakan kepada kami [Abu 'Ashim] -yaitu Muhammad bin Abu Ayyub- dia berkata, telah menceritakan kepadaku [Yazid al-Faqir] dia berkata, \"Dahulu aku telah terpengaruh dengan pemikiran Khawarij, kemudian kami keluar dalam sebuah rombongan besar untuk melaksanakan haji. Ketika kami keluar dan melewati madinah, ternyata [Jabir bin Abdullah] sedang menceritakan hadits Rasulullah shallallahu 'alaihi wasallam kepada suatu kaum sambil bersandar pada sebuah tiang.\" Yazil al Faqir berkata lagi, \"Tiba-tiba dia menyebutkan al-Jahannamiyyin.\" Maka aku pun berkata kepadanya, 'Wahai sahabat Rasulullah, apa-apaan yang kau ceritakan! Padahal Allah berfirman: '(Sesungguhnya barangsiapa yang Kamu masukkan ke dalam neraka, maka sungguh kamu telah menghinakannya) ' (Qs. Ali Imran: 192), dan ayat: '(Setiap kali mereka berkeinginan untuk keluar darinya, niscaya mereka dikembalikan ke dalamnya) ' (Qs. As-Sajadah: 20). Apa yang kalian katakan ini? ' Jabir menjawab, 'Apakah kalian membaca al-Qur'an? ' Kami menjawab, 'Ya.' Jabir bertanya lagi, 'Apakah kamu mendengar kedudukan Muhammad shallallahu 'alaihi wasallam, yaitu memberikan syafa'at yang mana Allah mengutusnya di dalamnya? ' Aku menjawab, 'Ya.' Jbir lalu berkata, 'Maka itulah kedudukan Muhammad shallallahu 'alaihi wasallam yang terpuji, dengannya Allah mengeluarkan orang yang dia keluarkan (dari neraka).' Yazid berkata, 'Kemudian Jabir memperagakan peletakan shirath, dan manusia lewat di atasnya.' Kata Yazid, 'Dan aku sangat khawatir tidak selamat dari hal tersebut. Hanya saja Jabir tetap berkeyakinan bahwa sekelompok kaum pasti akan keluar dari neraka, setelah mereka tinggal beberapa lama.' Kata Jabir, 'Maksudnya mereka keluar seakan-akan tongkat arang yang hitam kelam.' Kata Jabir meneruskan, 'Lalu mereka masuki salah satu sungai surga, mereka mandi di dalamnya, mereka keluar dari sungai seakan-akan kertas (putih), dan kami pun pulang.' Kami berkata, 'Celaka kalian, apakah kalian taksir bahwa syaikh ini berdusta atas nama Rasulullah shallallahu 'alaihi wasallam!.' Kami pun kembali, demi Allah, tidak ada yang keluar dari kami melainkan hanya satu orang atau sebagaimana yang diucapkan Abu Na'im.\""},{"p":"Muslim","n":369,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ حَدَّثَنَا أَبُو الْمُتَوَكِّلِ أَنَّ ابْنَ عَبَّاسٍ حَدَّثَهُأَنَّهُ بَاتَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَقَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ آخِرِ اللَّيْلِ فَخَرَجَ فَنَظَرَ فِي السَّمَاءِ ثُمَّ تَلَا هَذِهِ الْآيَةَ فِي آلِ عِمْرَانَ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ حَتَّى بَلَغَ فَقِنَا عَذَابَ النَّارِ }ثُمَّ رَجَعَ إِلَى الْبَيْتِ فَتَسَوَّكَ وَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى ثُمَّ اضْطَجَعَ ثُمَّ قَامَ فَخَرَجَ فَنَظَرَ إِلَى السَّمَاءِ فَتَلَا هَذِهِ الْآيَةَ ثُمَّ رَجَعَ فَتَسَوَّكَ فَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى","trj":"Telah menceritakan kepada kami [Abd bin Humaid] telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ismail bin Muslim] telah menceritakan kepada kami [Abu al-Mutawakkil] bahwa [Ibnu Abbas] telah menceritakan kepadanya, bahwa dia bermalam di sisi Nabi shallallahu 'alaihi wasallam pada suatu malam, maka Rasulullah bangun di akhir malam dan keluar, lalu beliau melihat di langit seraya membaca ayat ini pada surat Ali Imran: '(Sesungguhnya dalam penciptaan langit langit dan bumi, dan silih bergantinya malam dan siang terdapat tanda-tanda bagi orang-orang yang berakal, (yaitu) orang-orang yang mengingat Allah sambil berdiri atau duduk atau dalam keadaan berbaring dan mereka memikirkan tentang penciptaan langit dan bumi (seraya berkata), 'Ya Rabb kami, tiadalah Engkau menciptakan ini dengan sia-sia Maha Suci Engkau, maka peliharalah kami dari siksa neraka) ' (Qs. Ali Imran: 191-192). Kemudian beliau kembali pulang ke rumah, beliau lalu bersiwak, berwudlu, lalu berdiri shalat. Setelah itu beliau berbaring, kemudian berdiri keluar melihat langit lalu membaca ayat ini lagi. Kemudian beliau kembali bersiwak dan wudlu, lalu berdiri melaksanakan shalat.\""},{"p":"Muslim","n":1049,"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ بْنُ يَحْيَى قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُمَا سَمِعَا أَبَا هُرَيْرَةَ يَقُولُاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حِينَ يَفْرُغُ مِنْ صَلَاةِ الْفَجْرِ مِنْ الْقِرَاءَةِ وَيُكَبِّرُ وَيَرْفَعُ رَأْسَهُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ يَقُولُ وَهُوَ قَائِمٌ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا عَلَيْهِمْ كَسِنِي يُوسُفَ اللَّهُمَّ الْعَنْ لِحْيَانَ وَرِعْلًا وَذَكْوَانَ وَعُصَيَّةَ عَصَتْ اللَّهَ وَرَسُولَهُ ثُمَّ بَلَغَنَا أَنَّهُ تَرَكَ ذَلِكَ لَمَّا أُنْزِلَ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ قَالَا حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ إِلَى قَوْلِهِ وَاجْعَلْهَا عَلَيْهِمْ كَسِنِي يُوسُفَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ","trj":"Telah menceritakan kepadaku [Abu At Thahir] dan [Harmalah bin Yahya], keduanya berkata; telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] katanya; telah mengabarkan kepadaku [Said bin Musayyab] dan [Abu Salamah bin Abdurrahman bin 'Auf], keduanya mendengar [Abu Hurairah] berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam shalat fajar (subuh), yaitu setelah membaca, bertakbir dan mengangkat kepalanya, beliau membaca \"Sami'allahu liman hamidah. Rabbanaa walakal hamdu.\" Kemudian beliau membaca lagi dan beliau masih berdiri, yaitu; ALLAAHUMMA ANJI ALWALID BIN WALID WA SALAMAH BIN HISYAM, WA AYYASY BIN ABU RABIAH, WAL MUSTADH'AFIINA MINAL MUL'MINIINA, ALLAAHUMMASY DUD WATH'ATHAKA 'ALAA MUDHARR WAJ'ALHAA 'ALIHIM KASINII YUUSUFA, ALLAAHUMMAL'AN LIHYAANA WARI'LAN WADZAKWAAANA WA'USHAYYAH ASHATALLAAHA WARASUULAHU (Ya Allah, selamatkanlah Walid bin walid, Salamah bin Hisyam, Ayyasy bin Abu Rabiah dan orang-orang mukmin yang lemah, Ya Allah, perkuatlah hukumanmu kepada Mudharr dan jadikanlah untuk mereka masa-masa paceklik sebagaimana paceklik Yusuf, Ya Allah, laknatilah Lihyan, Ri'l, dan Dzakwan, mereka yang telah membangkang Allah dan Rasul-Nya.\" Kemudian sampai berita kepada kami, bahwa beliau meninggakan doa (qunut) tersebut, tepatnya ketika turun ayat \"Tidak ada urusanmu entah Allah mengampuni mereka atau menyiksa mereka, sesungguhnya mereka orang-orang yang zhalim (QS. Ali Imran 128), Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan ['Amru An Naqid], keduanya berkata; telah menceritakan kepada kami [Ibn 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam hingga sabdanya: \"Ya Allah, jadikanlah untuk mereka tahun-tahun paceklik sebagaimana tahun-tahun paceklik Yusuf.\" Dan ia tidak menyebutkan kalimat sesudahnya."},{"p":"Muslim","n":1141,"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْفَزَارِيُّ يَعْنِي مَرْوَانَ بْنَ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ حَكِيمٍ الْأَنْصَارِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }الْآيَةَ الَّتِي فِي الْبَقَرَةِ وَفِي الْآخِرَةِ مِنْهُمَا{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","trj":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Fazari yaitu Marwan bin Muawiyah] dari [Utsman bin Hakim Al Anshari], katanya; telah menceritakan kepadaku [Said bin Yasar] bahwa [Ibnu Abbas] mengabarinya; bahwa dalam dua raka'at fajar, tepatnya di raka'at pertama, Rasulullah shallallahu 'alaihi wasallam membaca \"Katakanlah, kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" QS. Albaqarah 136, dan pada rakaat kedua membaca \"Kami beriman kepada Allah, dan saksikanlah bahwa kami orang muslim.\" QS. Ali Imran 52."},{"p":"Muslim","n":1200,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ لَيْلَةً عِنْدَ مَيْمُونَةَ أُمِّ الْمُؤْمِنِينَ وَهِيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ فَصَلَّى قَالَ ابْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَو حَدَّثَنِي مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ الْفِهْرِيِّ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ بِهَذَا الْإِسْنَادِ وَزَادَ ثُمَّ عَمَدَ إِلَى شَجْبٍ مِنْ مَاءٍ فَتَسَوَّكَ وَتَوَضَّأَ وَأَسْبَغَ الْوُضُوءَ وَلَمْ يُهْرِقْ مِنْ الْمَاءِ إِلَّا قَلِيلًا ثُمَّ حَرَّكَنِي فَقُمْتُ وَسَائِرُ الْحَدِيثِ نَحْوُ حَدِيثِ مَالِكٍ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata: Aku telah membacakan kepada [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] Maula Ibnu Abbas, bahwa [Ibnu Abbas] telah mengabarkan kepadanya bahwasanya; Pada suatu malam dia tidur di rumah bibinya, Maimunah, Ummul Mukminin. Dia tidur melintang kasur, sedangkan Rasulullah shallallahu 'alaihi wasallam dan isterinya memanjang kasur. Beliau tidur hingga lebih kurang sampai pertengan malam. Setelah itu, beliau bangun sambil menyapu kantuk dari mukanya. Kemudian beliau membaca sepuluh ayat penghabisan dari surat Ali Imran. Sesudah itu, beliau pergi ke tempat air, lalu beliau berwudlu dengan menyempurnakan wudlunya, dan sesudah itu beliau shalat. Ibnu Abbas berkata, \"Aku pun bangun kemudian melakukan sebagaimana yang dilakukan oleh Nabi shallallahu 'alaihi wasallam. Kemudian aku berdiri di samping kiri beliau. Tetapi beliau memegang kepalaku dengan tangannya dan memindahkanku ke sebelah kanannya. Mula-mula beliau shalat dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at dan kemudian witir satu raka'at. Sesudah itu, beliau berbaring hingga terdengar muadzin mengumandangkan adzan Shubuh. Rasulullah shallallahu 'alaihi wasallam bangun, lalu shalat ringkas dua raka'at, sesudah itu beliau pergi ke (masjid) untuk mengerjakan shalat Shubuh.\" Dan telah menceritakan kepadaku [Muhammad bin Salamah Al Muradi] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Iyadl bin Abdullah Al Fihri] dari [Makhramah bin Sulaiman] dengan isnad ini. dan ia menambahkan; \"Kemudian beliau pergi ke tempat air, bersiwak dan berwudlu dengan menyempurnakan wudlunya. Dan beliau tidaklah menggunakan air kecuali hanya sedikit. Sesudah itu, beliau menggerakkanku, hingga aku pun bangun.\" Semua hadits (tentang ini) menyerupai haditsnya Malik."},{"p":"Muslim","n":1210,"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ جَرِيرٍ كُلُّهُمْ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَافْتَتَحَ الْبَقَرَةَ فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَةِ ثُمَّ مَضَى فَقُلْتُ يُصَلِّي بِهَا فِي رَكْعَةٍ فَمَضَى فَقُلْتُ يَرْكَعُ بِهَا ثُمَّ افْتَتَحَ النِّسَاءَ فَقَرَأَهَا ثُمَّ افْتَتَحَ آلَ عِمْرَانَ فَقَرَأَهَا يَقْرَأُ مُتَرَسِّلًا إِذَا مَرَّ بِآيَةٍ فِيهَا تَسْبِيحٌ سَبَّحَ وَإِذَا مَرَّ بِسُؤَالٍ سَأَلَ وَإِذَا مَرَّ بِتَعَوُّذٍ تَعَوَّذَ ثُمَّ رَكَعَ فَجَعَلَ يَقُولُ سُبْحَانَ رَبِّيَ الْعَظِيمِ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَامَ طَوِيلًا قَرِيبًا مِمَّا رَكَعَ ثُمَّ سَجَدَ فَقَالَ سُبْحَانَ رَبِّيَ الْأَعْلَى فَكَانَ سُجُودُهُ قَرِيبًا مِنْ قِيَامِهِقَالَ وَفِي حَدِيثِ جَرِيرٍ مِنْ الزِّيَادَةِ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ","trj":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Mu'awiyah] -dalam jalur lain- Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] semuanya dari [Jarir] mereka semua dari [Al A'masy] -dalam jalur lain- telah menceritakan kepada kami [Ibnu Numair] -dan lafazh ini adalah darinya- telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Sa'id bin Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] ia berkata; Pada suatu malam, saya shalat (Qiyamul Lail) bersama Rasulullah shallallahu 'alaihi wasallam, lalu beliau mulai membaca surat Al Baqarah. Kemudian saya pun berkata (dalam hati bahwa beliau) akan ruku' pada ayat yang ke seratus. Kemudian (seratus ayat pun) berlalu, lalu saya berkata (dalam hati bahwa) beliau akan shalat dengan (surat itu) dalam satu raka'at. Namun (surat Al Baqarah pun) berlalu, maka saya berkata (dalam hati bahwa) beliau akan segera sujud. Ternyata beliau melanjutkan dengan mulai membaca surat An Nisa` hingga selesai membacanya. Kemudian beliau melanjutkan ke surat Ali Imran hingga selesai hingga beliau selesai membacanya. Bila beliau membaca ayat tasbih, beliau bertasbih dan bila beliau membaca ayat yang memerintahkan untuk memohon, beliau memohon, dan bila beliau membaca ayat ta'awwudz (ayat yang memerintahkan untuk memohon perlindungan) beliau memohon perlindungan. Kemudian beliau ruku'. Dalam ruku', beliau membaca: \"SUBHAANA RABBIYAL 'AZHIIM (Maha Suci Tuhanku yang Maha Agung).\" Dan lama beliau ruku' hampir sama dengan berdirinya. Kemudian beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH (Maha Mendengar Allah akan orang yang memuji-Nya).\" Kemudian beliau berdiri dan lamanya berdiri lebih kurang sama dengan lamanya ruku'. Sesudah itu beliau sujud, dan dalam sujud beliau membaca: \"SUBHAANA RABBIYAL A'LAA (Maha Suci Tuhanku Yang Maha Tinggi).\" Lama beliau sujud hampir sama dengan lamanya berdiri. Sementara di dalam hadits Jarir terdapat tambahan; Beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH RABBANAA LAKAL HAMDU (Allah Maha Mendengar akan orang yang memuji-Nya, Ya Tuhan kami bagi-Mu segala puji).\""},{"p":"Muslim","n":3089,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَابْنُ أَبِي عُمَرَ وَمُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ وَاللَّفْظُ لِابْنِ رَافِعٍ قَالَ ابْنُ رَافِعٍ وَابْنُ أَبِي عُمَرَ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ أَبَا سُفْيَانَ أَخْبَرَهُ مِنْ فِيهِ إِلَى فِيهِ قَالَانْطَلَقْتُ فِي الْمُدَّةِ الَّتِي كَانَتْ بَيْنِي وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَبَيْنَا أَنَا بِالشَّأْمِ إِذْ جِيءَ بِكِتَابٍ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هِرَقْلَ يَعْنِي عَظِيمَ الرُّومِ قَالَ وَكَانَ دَحْيَةُ الْكَلْبِيُّ جَاءَ بِهِ فَدَفَعَهُ إِلَى عَظِيمِ بُصْرَى فَدَفَعَهُ عَظِيمُ بُصْرَى إِلَى هِرَقْلَ فَقَالَ هِرَقْلُ هَلْ هَاهُنَا أَحَدٌ مِنْ قَوْمِ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ قَالُوا نَعَمْ قَالَ فَدُعِيتُ فِي نَفَرٍ مِنْ قُرَيْشٍ فَدَخَلْنَا عَلَى هِرَقْلَ فَأَجْلَسَنَا بَيْنَ يَدَيْهِ فَقَالَ أَيُّكُمْ أَقْرَبُ نَسَبًا مِنْ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَقَالَ أَبُو سُفْيَانَ فَقُلْتُ أَنَا فَأَجْلَسُونِي بَيْنَ يَدَيْهِ وَأَجْلَسُوا أَصْحَابِي خَلْفِي ثُمَّ دَعَا بِتَرْجُمَانِهِ فَقَالَ لَهُ قُلْ لَهُمْ إِنِّي سَائِلٌ هَذَا عَنْ الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ فَإِنْ كَذَبَنِي فَكَذِّبُوهُ قَالَ فَقَالَ أَبُو سُفْيَانَ وَايْمُ اللَّهِ لَوْلَا مَخَافَةُ أَنْ يُؤْثَرَ عَلَيَّ الْكَذِبُ لَكَذَبْتُ ثُمَّ قَالَ لِتَرْجُمَانِهِ سَلْهُ كَيْفَ حَسَبُهُ فِيكُمْ قَالَ قُلْتُ هُوَ فِينَا ذُو حَسَبٍ قَالَ فَهَلْ كَانَ مِنْ آبَائِهِ مَلِكٌ قُلْتُ لَا قَالَ فَهَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ قُلْتُ لَا قَالَ وَمَنْ يَتَّبِعُهُ أَشْرَافُ النَّاسِ أَمْ ضُعَفَاؤُهُمْ قَالَ قُلْتُ بَلْ ضُعَفَاؤُهُمْ قَالَ أَيَزِيدُونَ أَمْ يَنْقُصُونَ قَالَ قُلْتُ لَا بَلْ يَزِيدُونَ قَالَ هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ سَخْطَةً لَهُ قَالَ قُلْتُ لَا قَالَ فَهَلْ قَاتَلْتُمُوهُ قُلْتُ نَعَمْ قَالَ فَكَيْفَ كَانَ قِتَالُكُمْ إِيَّاهُ قَالَ قُلْتُ تَكُونُ الْحَرْبُ بَيْنَنَا وَبَيْنَهُ سِجَالًا يُصِيبُ مِنَّا وَنُصِيبُ مِنْهُ قَالَ فَهَلْ يَغْدِرُ قُلْتُ لَا وَنَحْنُ مِنْهُ فِي مُدَّةٍ لَا نَدْرِي مَا هُوَ صَانِعٌ فِيهَا قَالَ فَوَاللَّهِ مَا أَمْكَنَنِي مِنْ كَلِمَةٍ أُدْخِلُ فِيهَا شَيْئًا غَيْرَ هَذِهِ قَالَ فَهَلْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ قَالَ قُلْتُ لَا قَالَ لِتَرْجُمَانِهِ قُلْ لَهُ إِنِّي سَأَلْتُكَ عَنْ حَسَبِهِ فَزَعَمْتَ أَنَّهُ فِيكُمْ ذُو حَسَبٍ وَكَذَلِكَ الرُّسُلُ تُبْعَثُ فِي أَحْسَابِ قَوْمِهَا وَسَأَلْتُكَ هَلْ كَانَ فِي آبَائِهِ مَلِكٌ فَزَعَمْتَ أَنْ لَا فَقُلْتُ لَوْ كَانَ مِنْ آبَائِهِ مَلِكٌ قُلْتُ رَجُلٌ يَطْلُبُ مُلْكَ آبَائِهِ وَسَأَلْتُكَ عَنْ أَتْبَاعِهِ أَضُعَفَاؤُهُمْ أَمْ أَشْرَافُهُمْ فَقُلْتَ بَلْ ضُعَفَاؤُهُمْ وَهُمْ أَتْبَاعُ الرُّسُلِ وَسَأَلْتُكَ هَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالْكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ فَزَعَمْتَ أَنْ لَا فَقَدْ عَرَفْتُ أَنَّهُ لَمْ يَكُنْ لِيَدَعَ الْكَذِبَ عَلَى النَّاسِ ثُمَّ يَذْهَبَ فَيَكْذِبَ عَلَى اللَّهِ وَسَأَلْتُكَ هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَهُ سَخْطَةً لَهُ فَزَعَمْتَ أَنْ لَا وَكَذَلِكَ الْإِيمَانُ إِذَا خَالَطَ بَشَاشَةَ الْقُلُوبِ وَسَأَلْتُكَ هَلْ يَزِيدُونَ أَوْ يَنْقُصُونَ فَزَعَمْتَ أَنَّهُمْ يَزِيدُونَ وَكَذَلِكَ الْإِيمَانُ حَتَّى يَتِمَّ وَسَأَلْتُكَ هَلْ قَاتَلْتُمُوهُ فَزَعَمْتَ أَنَّكُمْ قَدْ قَاتَلْتُمُوهُ فَتَكُونُ الْحَرْبُ بَيْنَكُمْ وَبَيْنَهُ سِجَالًا يَنَالُ مِنْكُمْ وَتَنَالُونَ مِنْهُ وَكَذَلِكَ الرُّسُلُ تُبْتَلَى ثُمَّ تَكُونُ لَهُمْ الْعَاقِبَةُ وَسَأَلْتُكَ هَلْ يَغْدِرُ فَزَعَمْتَ أَنَّهُ لَا يَغْدِرُ وَكَذَلِكَ الرُّسُلُ لَا تَغْدِرُ وَسَأَلْتُكَ هَلْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ فَزَعَمْتَ أَنْ لَا فَقُلْتُ لَوْ قَالَ هَذَا الْقَوْلَ أَحَدٌ قَبْلَهُ قُلْتُ رَجُلٌ ائْتَمَّ بِقَوْلٍ قِيلَ قَبْلَهُ قَالَ ثُمَّ قَالَ بِمَ يَأْمُرُكُمْ قُلْتُ يَأْمُرُنَا بِالصَّلَاةِ وَالزَّكَاةِ وَالصِّلَةِ وَالْعَفَافِ قَالَ إِنْ يَكُنْ مَا تَقُولُ فِيهِ حَقًّا فَإِنَّهُ نَبِيٌّ وَقَدْ كُنْتُ أَعْلَمُ أَنَّهُ خَارِجٌ وَلَمْ أَكُنْ أَظُنُّهُ مِنْكُمْ وَلَوْ أَنِّي أَعْلَمُ أَنِّي أَخْلُصُ إِلَيْهِ لَأَحْبَبْتُ لِقَاءَهُ وَلَوْ كُنْتُ عِنْدَهُ لَغَسَلْتُ عَنْ قَدَمَيْهِ وَلَيَبْلُغَنَّ مُلْكُهُ مَا تَحْتَ قَدَمَيَّ قَالَ ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ سَلَامٌ عَلَى مَنْ اتَّبَعَ الْهُدَى أَمَّا بَعْدُ فَإِنِّي أَدْعُوكَ بِدِعَايَةِ الْإِسْلَامِ أَسْلِمْ تَسْلَمْ وَأَسْلِمْ يُؤْتِكَ اللَّهُ أَجْرَكَ مَرَّتَيْنِ وَإِنْ تَوَلَّيْتَ فَإِنَّ عَلَيْكَ إِثْمَ الْأَرِيسِيِّينَ وَ{ يَا أَهْلَ الْكِتَابِ تَعَالَوْا إِلَى كَلِمَةٍ سَوَاءٍ بَيْنَنَا وَبَيْنَكُمْ أَنْ لَا نَعْبُدَ إِلَّا اللَّهَ وَلَا نُشْرِكَ بِهِ شَيْئًا وَلَا يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًا مِنْ دُونِ اللَّهِ فَإِنْ تَوَلَّوْا فَقُولُوا اشْهَدُوا بِأَنَّا مُسْلِمُونَ }فَلَمَّا فَرَغَ مِنْ قِرَاءَةِ الْكِتَابِ ارْتَفَعَتْ الْأَصْوَاتُ عِنْدَهُ وَكَثُرَ اللَّغْطُ وَأَمَرَ بِنَا فَأُخْرِجْنَا قَالَ فَقُلْتُ لِأَصْحَابِي حِينَ خَرَجْنَا لَقَدْ أَمِرَ أَمْرُ ابْنِ أَبِي كَبْشَةَ إِنَّهُ لَيَخَافُهُ مَلِكُ بَنِي الْأَصْفَرِ قَالَ فَمَا زِلْتُ مُوقِنًا بِأَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَيَظْهَرُ حَتَّى أَدْخَلَ اللَّهُ عَلَيَّ الْإِسْلَامَو حَدَّثَنَاه حَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ بِهَذَا الْإِسْنَادِ وَزَادَ فِي الْحَدِيثِ وَكَانَ قَيْصَرُ لَمَّا كَشَفَ اللَّهُ عَنْهُ جُنُودَ فَارِسَ مَشَى مِنْ حِمْصَ إِلَى إِيلِيَاءَ شُكْرًا لِمَا أَبْلَاهُ اللَّهُ وَقَالَ فِي الْحَدِيثِ مِنْ مُحَمَّدٍ عَبْدِ اللَّهِ وَرَسُولِهِ وَقَالَ إِثْمَ الْيَرِيسِيِّينَ وَقَالَ بِدَاعِيَةِ الْإِسْلَامِ","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dan [Ibnu Abu Umar] serta [Muhammad bin Rafi'] dan [Abd bin Humaid] sedangkan lafadznya dari Ibnu Rafi', Ibnu Rafi' dan Ibnu Abu Umar mengatakan; telah menceritakan kepada kami, sedangkan yang dua mengatakan; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] bahwa [Abu Sufyan] mengisahkan dari mulutnya sendiri sebagai berikut, \"Pada saat berlangsungnya perjanjian damai antara aku dengan Rasulullah shallallahu 'alaihi wasallam, aku pergi berniaga ke negeri Syam. Ketika aku berada di sana, ada seseorang yang mengirim sepucuk surat dari Rasulullah shallallahu 'alaihi wasallam kepada kaisar Heraclius, penguasa agung Rumawi, yang membawa surat itu adalah Dihyah Al Kalbi kepada pembesar Bushra, kemudian pembesar Bushra menyampaikannya kepada Heraclius. Lantas Heraclius bertanya, \"Adakah di sini orang yang berasal dari kaumnya laki-laki yang mengaku sebagai Nabi ini (Rasulullah)? ' mereka menjawab, \"Ya.\" Lalu aku dipanggil untuk menghadap Heraclius bersama beberapa kawanku dari suku Quraisy, kami masuk dan duduk menghadap Hiraclius. Heraclius lantas bertanya, \"Siapakah di antara kalian, yang dekat pertalian darahnya dengan orang yang mendakwakan dirinya menjadi Nabi itu?\" Abu Sufyan berkata, \"Lalu aku menjawab, \"Aku.\" Lalu aku duduk di depan, sedangkan kawan-kawanku duduk di belakangku. Kemudian dia memanggil penerjemahnya, lalu dia berkata kepada penerjemahnya, \"Katakanlah kepada mereka, bahwa aku menanyakan kepada mereka perihal laki-laki yang mendakwakan dirinya sebagai Nabi, jika dia berdusta, katakan dia telah berdusta.\" Abu Sufyan berkata, \"Demi Allah, kalaulah aku tidak takut dicap sebagai pendusta, sungguh telah ku dustai mereka.\" Kemudian Heraclius berkata kepada penerjemahnya, \"Tanyakan kepadanya, bagaimana kebangsaan orang itu di kalanganmu.\" Abu Sufyan berkata, \"Jawabku, \"Dia seorang bangsawan di kalangan kami.\" Dia bertanya, \"Apakah dia keturunan raja?\" aku menjawab, \"Tidak.\" Dia bertanya, \"Pernahkah kalian mengatakannya sebagai pembohong sebelum ia menjadi seorang Nabi?\" Jaawabku, \"Tidak.\" Dia bertanya, \"Apakah orang-orang yang mengikutinya dari kalangan pembesar ataukah hanya rakyat kecil?\" jawabku, \"Hanya rakyat kecil.\" Dia bertanya, \"Apakah pengikutnya selalu bertambah?\" Jawabku, \"Mereka selalu bertambah.\" Dia bertanya, \"Adakah di antara pengikutnya itu murtad karena benci terhadap agama yang dikembangkannya?\" Jawabku, \"Tidak.\" Dia bertanya, \"Apakah kamu berperang melawannya?\" Jawabku, \"Ya, pernah.\" Dia bertanya, \"Bagaimana perjalanan peperanganmu melawannya?\" Jawabku, \"Peperangan kami berjalan silih berganti antara menang dan kalah. Kadang-kadang kamilah yang menang dan dia yang kalah, dan terkadang pula kami yang kalah dan dia yang menang.\" Dia bertanya, \"Apakah dia pernah ingkat janji?\" Jawabku, \"Tidak, bahkan kami sedang dalam masa perjanjian damai, yaitu tidak akan serang menyerang dengannya. Aku tidak tahu apa yang akan dibuatnya terhadap perjanjian tersebut.\" Kata Abu Sufyan selanjutnya, \"Demi Allah, tidak ada kalimat lain yang dapat kami ucapkan selain dari pada itu semua.\" Dia bertanya, \"Apakah ada orang lain sebelum dia, yang mendakwakan dirinya sebagai Nabi seperti dia?\" Jawabku, \"Tidak.\" Kemudian dia berkata kepada penerjemahnya, \"Katakan kepadanya, \"Kutanyakan kepadamu tentang bangsanya (status sosialnya), maka kalian katakan dia termasuk dari bangsawan. Memang demikianlah halnya semua para rasul, mereka dibangkitkan dari kalangan bangsawan kaumnya. Kutanyakan pula kepadamu, apakah dia dari keturunan para raja? Jawabmu 'tidak', kalau sekiranya bapak dan kakeknya yang menjadi raja, tentunya ada sangkaan bahwa dia ingin mengembalikan kekusaan nenek moyangnya. Kutanyakan pula tentang pengikutnya, apakah terdiri dari rakyat kecil atau dari orang-orang besar? Kamu menjawab 'hanya terdiri dari rakyat kecil', memang merekalah pengikut para rasul. Kutanyakan pula, pernahkah kamu menuduhnya sebagai pembohong sebelumnya? Kamu menjawab 'tidak', aku tahu, bahwa dia tidak akan pernah berdusta kepada manusia, apalagi bedusta kepada Allah. Aku tanyakan kepadamu; adakah pengikutnya yang murtad atau mereka membenci agama baru setelah memeluknya? Jawabmu 'tidak', memang begitulah halnya, apabila iman telah tertanam dalam hati seseorang. Aku bertanya kepadamu, apakah pengikutnya berkurang? Jawabmu 'bahkan mereka selalu bertambah', memang seperti itulah iman hingga ia tumbuh sempurna. Kutanya pula, pernahkah kamu memeranginya? Jawabmu 'ya kami memerangi, dan peperangan silih berganti, terkadang menang dan terkadang kalah'. Memang demikianlah halnya, para rasul itu selalu diuji. Namun demikian, kemengangan terakhir selalu dipihak mereka. Kutanyakan pula, pernahkah dia ingkar janji? Jawabmu 'tidak pernah', memang demikian para rasul tidak mungkin ingkar janji. Kutanyakan pula kepadamu, adakah orang lain sebelum dia yang mengaku menjadi Nabi seperti dia? Jawabmu 'tidak', begitulah, kalau ada orang sebelumnya yang mendakwakan dirinya sebagai Nabi seperti dia, mungkin dia hanya ikut-ikutan dengan orang yang sebelumnya.\" Kemudian dia bertanya, \"Apa saja yang diperintahkanya kepadamu?\" Jawabku, \"Dia menyuruh kami shalat, membayar zakat, menjalin tali silaturrahmi dan menjaga kehormatan diri.\" dia berkata, \"Jika yang kamu katakan itu benar semuanya, maka tak salah lagi bahwa lelaki tersebut adalah seorang Nabi, aku tahu bahwa dia akan muncul, akan tetapi aku tidak menduga bahwa dia akan muncul dari kalangan kalian, sekiranya aku dapat bertemu dengannya, saat di sampingnya maka sungguh aku akan membasuh kedua kakinya. Dan daerah kekuasaannya kelak, akan sampai ke daerah kekuasanku ini.\" Abu Sufyan berkata, \"Kemudian dia meminta surat dari Rasulullah shallallahu 'alaihi wasallam dan membacanya, di dalamnya tertulis: \"Dengan nama Allah yang Maha pengasih lagi Maha penyayang, dari Muhammad Rasulullah kepada Heraclius pembesar Rumawi. Keselamatan bagi orang yang mengikuti petunjuk, sesungguhnya aku mengajak anda untuk masuk Islam, masuk Islamlah anda niscaya anda akan selamat. Masuk Islamlah anda, niscaya Allah akan memberi pahala kepada anda dengan berlipat ganda. Jika anda menolak, maka anda akan memikul dosa kaum 'arisyiyun. '(Hai ahli kitab, marilah (berpegang) kepada suatu kalimat (ketetapan) yang tidak ada perselisihan antara kami dan kamu, bahwa kita tidak akan menyembah kecuali Allah dan tidak kita persekutukan dia dengan sesuatupun dan tidak (pula) sebagian kita menjadikan sebagian yang lain sebagai Tuhan selain Allah. jika mereka menolak, maka Katakanlah kepada mereka: \"Saksikanlah, bahwa kami adalah orang-orang yang berserah diri (kepada Allah) ' (Qs. Ali Imran: 64) Setelah dia selesai membaca surat tersebut, tiba-tiba terdengar suara heboh di sekitarnya. Dia memerintahkan kami supaya keluar. Sesampainya di luar, aku berkata kepada kawan-kawanku, \"Sungguh luar biasa urusan Ibnu Abu Kabsyah (maksudnya Rasulullah), hingga dia diikuti oleh raja bani Ashfar (bangsa berkulit kuning), karena itu aku senantiasa yakin bahwa agama Rasulullah shallallahu 'alaihi wasallam ini pasti menang, dan akhirnya Allah memasukkan hidayah Islam ke dalam hati sanubariku.\" Dan telah menceritakan kepada kami [Hasan Al Khulwani] dan [Abd bin Humaid] keduanya berkata; telah menceritakan kepada kami [Ya'qub] -yaitu Ibnu Ibrahim bin Sa'd- telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] dengan isnad ini, dan ia menambahkan dalam haditsnya, \"Setelah Allah memenangkan tentara Persi atasnya, maka Kaisar berjalan kaki dari daerah Himsha hingga Iliya` sebagai bentuk syukur akan ujian Allah.\" Dan dalam hadits itu pula disebutkan, \"Dari Muhammad, seorang hamba Allah dan Rasul-Nya.\" Dan dia juga menyebutkan, \"Dosa kaum Yarisiyin.\" Dan dia menyebutkan, \"Dengan seruan Islam.\""},{"p":"Muslim","n":3113,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُسِرَتْ رَبَاعِيَتُهُ يَوْمَ أُحُدٍ وَشُجَّ فِي رَأْسِهِ فَجَعَلَ يَسْلُتُ الدَّمَ عَنْهُ وَيَقُولُ كَيْفَ يُفْلِحُ قَوْمٌ شَجُّوا نَبِيَّهُمْ وَكَسَرُوا رَبَاعِيَتَهُ وَهُوَ يَدْعُوهُمْ إِلَى اللَّهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ }","trj":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas], bahwa gigi geraham Rasulullah shallallahu 'alaihi wasallam pecah ketika perang Uhud, dan kepala beliau juga terluka hingga mengalirkan darah, beliau lalu bersabda: \"Bagaimana mungkin suatu kaum akan beruntung, sedangkan mereka melukai nabinya dan mematahkan gigi gerahamnya.\" Oleh karena itu beliau memohon kepada Allah untuk mengutuk mereka, lalu Allah Azza wa jalla menurunkan ayat: '(Kamu tidak memiliki wewenang apa-apa terhadap urusan mereka…) ' (Qs. Ali Imran: 128)."},{"p":"Muslim","n":3260,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ أَبِي مُعَاوِيَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ وَعِيسَى بْنُ يُونُسَ جَمِيعًا عَنْ الْأَعْمَشِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَسْبَاطٌ وَأَبُو مُعَاوِيَةَ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ قَالَسَأَلْنَا عَبْدَ اللَّهِ عَنْ هَذِهِ الْآيَةِ{ وَلَا تَحْسَبَنَّ الَّذِينَ قُتِلُوا فِي سَبِيلِ اللَّهِ أَمْوَاتًا بَلْ أَحْيَاءٌ عِنْدَ رَبِّهِمْ يُرْزَقُونَ }قَالَ أَمَا إِنَّا قَدْ سَأَلْنَا عَنْ ذَلِكَ فَقَالَ أَرْوَاحُهُمْ فِي جَوْفِ طَيْرٍ خُضْرٍ لَهَا قَنَادِيلُ مُعَلَّقَةٌ بِالْعَرْشِ تَسْرَحُ مِنْ الْجَنَّةِ حَيْثُ شَاءَتْ ثُمَّ تَأْوِي إِلَى تِلْكَ الْقَنَادِيلِ فَاطَّلَعَ إِلَيْهِمْ رَبُّهُمْ اطِّلَاعَةً فَقَالَ هَلْ تَشْتَهُونَ شَيْئًا قَالُوا أَيَّ شَيْءٍ نَشْتَهِي وَنَحْنُ نَسْرَحُ مِنْ الْجَنَّةِ حَيْثُ شِئْنَا فَفَعَلَ ذَلِكَ بِهِمْ ثَلَاثَ مَرَّاتٍ فَلَمَّا رَأَوْا أَنَّهُمْ لَنْ يُتْرَكُوا مِنْ أَنْ يُسْأَلُوا قَالُوا يَا رَبِّ نُرِيدُ أَنْ تَرُدَّ أَرْوَاحَنَا فِي أَجْسَادِنَا حَتَّى نُقْتَلَ فِي سَبِيلِكَ مَرَّةً أُخْرَى فَلَمَّا رَأَى أَنْ لَيْسَ لَهُمْ حَاجَةٌ تُرِكُوا","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] keduanya dari [Abu Mu'awiyah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dan [Isa bin Yunus] semuanya dari [Al A'masy]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] sedangkan lafadznya dari dia, telah menceritakan kepada kami [Asbath] dan [Abu Mu'awiyah] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dia berkata, \"Kami pernah bertanya kepada [Abdullah] perihal ayat ini: '(Dan janganlah kalian mengira bahwa orang-orang yang terbunuh di jalan Allah itu (memang) mati, akan tetapi sebenarnya mereka itu hidup di sisi Rabb mereka dan diberi rezeki (yang melimpah) ' (Qs. Ali Imran: 169) Dia berkata, \"Kami dulu pernah menanyakan hal itu, dan beliau menjawab: \"Ruh mereka berada di dalam rongga burung hijau yang mempunyai banyak pelita yang bergantungan di 'Arsy, ia dapat keluar masuk surga sesuka hati kemudian beristirahat lagi di pelita-pelita itu, kemudian Rabb mereka menengok mereka seraya berkata: 'Apakah kalian menginginkan sesuatu? ' Mereka menjawab, 'Apa lagi yang kami inginkan kalau kami sudah dapat keluar masuk ke surga sesuka hati kami? ' Lalu Allah terus mengulangi pertanyaan itu hingga tiga kali. Ketika mereka melihat kalau mereka tidak akan ditinggalkan sebelum menjawab pertanyaan itu, maka merekapun menjawab, 'Duhai Rabb, kami menginginkan ruh kami dikembalikan lagi ke jasad kami hingga kami dapat berperang lagi di jalan-Mu untuk kesekian kalinya.' Ketika Allah melihat kalau mereka tidak lagi membutuhkan sesuatu, akhirnya mereka ditinggal pergi.\""},{"p":"Muslim","n":4221,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَأَحْمَدُ بْنُ عَبْدَةَ وَاللَّفْظُ لِإِسْحَقَ قَالَا أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَفِينَا نَزَلَتْ{ إِذْ هَمَّتْ طَائِفَتَانِ مِنْكُمْ أَنْ تَفْشَلَا وَاللَّهُ وَلِيُّهُمَا }بَنُو سَلِمَةَ وَبَنُو حَارِثَةَ وَمَا نُحِبُّ أَنَّهَا لَمْ تَنْزِلْ لِقَوْلِ اللَّهِ عَزَّ وَجَلَّ{ وَاللَّهُ وَلِيُّهُمَا }","trj":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dan [Ahmad bin 'Abdah], lafazh ini milik Ishaq keduanya berkata; Telah mengabarkan kepada kami [Sufyan] dari ['Amru] dari [Jabir bin 'Abdullah] dia berkata; \"Ada ayat Al Qur'an yang turun berkenaan dengan kami yaitu: 'Ingatlah ketika dua golongan ingin mundur karena takut, padahal Allah penolong kedua golongan tersebut. '(Qs. Ali 'lmraan (2): 122) Keduanya adalah Bani Salimah dan Bani Haritsah. Kami tidak senang jika ayat ini tidak turun, karena firman Allah yang berbunyi: \"Padahal Allah penolong kedua golongan itu (QS. Ali-Imran 122)."},{"p":"Muslim","n":4627,"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ وَاللَّفْظُ لِزُهَيْرٍ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَخْبَرَهُأَنَّ مَرْوَانَ قَالَ اذْهَبْ يَا رَافِعُ لِبَوَّابِهِ إِلَى ابْنِ عَبَّاسٍ فَقُلْ لَئِنْ كَانَ كُلُّ امْرِئٍ مِنَّا فَرِحَ بِمَا أَتَى وَأَحَبَّ أَنْ يُحْمَدَ بِمَا لَمْ يَفْعَلْ مُعَذَّبًا لَنُعَذَّبَنَّ أَجْمَعُونَ فَقَالَ ابْنُ عَبَّاسٍ مَا لَكُمْ وَلِهَذِهِ الْآيَةِ إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي أَهْلِ الْكِتَابِ ثُمَّ تَلَا ابْنُ عَبَّاسٍ{ وَإِذْ أَخَذَ اللَّهُ مِيثَاقَ الَّذِينَ أُوتُوا الْكِتَابَ لَتُبَيِّنُنَّهُ لِلنَّاسِ وَلَا تَكْتُمُونَهُ }هَذِهِ الْآيَةَ وَتَلَا ابْنُ عَبَّاسٍ{ لَا تَحْسَبَنَّ الَّذِينَ يَفْرَحُونَ بِمَا أَتَوْا وَيُحِبُّونَ أَنْ يُحْمَدُوا بِمَا لَمْ يَفْعَلُوا }وَقَالَ ابْنُ عَبَّاسٍ سَأَلَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَيْءٍ فَكَتَمُوهُ إِيَّاهُ وَأَخْبَرُوهُ بِغَيْرِهِ فَخَرَجُوا قَدْ أَرَوْهُ أَنْ قَدْ أَخْبَرُوهُ بِمَا سَأَلَهُمْ عَنْهُ وَاسْتَحْمَدُوا بِذَلِكَ إِلَيْهِ وَفَرِحُوا بِمَا أَتَوْا مِنْ كِتْمَانِهِمْ إِيَّاهُ مَا سَأَلَهُمْ عَنْهُ","trj":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Harun bin 'Abdullah] -dan lafadh ini milik Zuhair- mereka berdua berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij]; telah mengabarkan kepadaku [Ibnu Abu Malikah] bahwasanya [Humaid bin 'Abdurrahman bin 'Auf] mengabarkan kepadanya bahwasanya Marwan berkata; \"Wahai Abu Rafi', katakan kepada kepada penjaga pintu agar dia pergi menemui Ibnu Abbas, tanyakan kepadanya; 'Apabila setiap orang dari kita yang merasa senang dengan apa yang dia kerjakan dan yang menyukai untuk dipuji terhadap apa yang belum dia kerjakan akan di adzab, dengan demikian berarti kita semua akan di adzab? [Ibnu Abbas] berkata; 'Apa hubungannya kalian dengan ayat ini? ' Ayat ini hanya di turunkan mengenai Ahlu kitab. Lalu Ibnu Abbas membaca ayat; \"Dan (ingatlah), ketika Allah mengambil janji dari orang-orang yang telah diberi (yaitu), \"Hendaklah kamu benar-benar menerangkannya (isi kitab itu) kepada manusia dan janganlah kamu menyembunyikannya. (QS. Ali Imran 187) \" Dan Ibnu Abbas membaca ayat; \"Dan janganlah sekali-kali kamu mengira bahwa orang yang gembira dengan apa yang telah mereka kerjakan dan mereka suka dipuji atas perbuatan yang tidak mereka lakukan. (QS. Ali'Imran 188) \" Ibnu Abbas berkata; Yaitu ketika nabi shallallahu 'alaihi wasallam menanyakan kepada mereka tentang sesuatu, namun mereka menyembunyikannya dan mengabarkan hal yang lain. Lalu mereka keluar. Sungguh aku melihat beliau diberitahu tentang yang beliau tanyakan kepada mereka hingga mereka ingin dipuji dengan apa yang telah mereka kabarkan itu dan mereka senang dengan apa yang telah mereka kerjakan dari menyembunyikan sesuatu yang beliau tanyakan.'"},{"p":"Muslim","n":4631,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا سُلَيْمَانُ وَهُوَ ابْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ مِنَّا رَجُلٌ مِنْ بَنِي النَّجَّارِ قَدْ قَرَأَ الْبَقَرَةَ وَآلَ عِمْرَانَ وَكَانَ يَكْتُبُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ هَارِبًا حَتَّى لَحِقَ بِأَهْلِ الْكِتَابِ قَالَ فَرَفَعُوهُ قَالُوا هَذَا قَدْ كَانَ يَكْتُبُ لِمُحَمَّدٍ فَأُعْجِبُوا بِهِ فَمَا لَبِثَ أَنْ قَصَمَ اللَّهُ عُنُقَهُ فِيهِمْ فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا ثُمَّ عَادُوا فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا ثُمَّ عَادُوا فَحَفَرُوا لَهُ فَوَارَوْهُ فَأَصْبَحَتْ الْأَرْضُ قَدْ نَبَذَتْهُ عَلَى وَجْهِهَا فَتَرَكُوهُ مَنْبُوذًا","trj":"Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu An Nadhr] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas bin Malik] dia berkata; \"Dulu ada seorang sahabat laki-laki dari Bani Najjar. Sahabat tersebut telah menghafal surah Al Baqarah dan surah Ali Imran. Selain itu, ia juga pernah menjadi juru tulis Rasulullah shallallahu 'alaihi wasallam. Hingga pada suatu hari ia melarikan diri dan bergabung dengan Ahli Kitab.\" Anas berkata; 'Ternyata orang-orang Ahli Kitab memuliakan dan menghormatinya. Mereka berkata; 'Sesungguhnya orang laki-laki ini pernah menjadi juru tulis Muhammad.' Maka semakin tambah hormatnya mereka kepada orang laki-laki itu. Tak lama kemudian, orang itu meninggal dunia di tengah-tengah orang-orang Ahli Kitab. Lalu mereka menggali tanah untuk menguburkannya. Tetapi kemudian, bumi malah memuntahkan mayatnya ke atas. Mereka menggali tanah lagi untuk menguburkannya. Tetapi kemudian bumi malah memuntahkan mayatnya ke atas. Mereka menggali tanah lagi untuk menguburkannya. Tetapi kemudian bumi malah memuntahkan mayatnya ke atas, hingga mereka membiarkannya tergeletak."},{"p":"Nasa'i","n":1115,"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ سَوَّارٍ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَمْرِو بْنِ قَيْسٍ الْكِنْدِيِّ أَنَّهُ سَمِعَ عَاصِمَ بْنَ حُمَيْدٍ يَقُولُ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ يَقُولُقُمْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَدَأَ فَاسْتَاكَ وَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى فَبَدَأَ فَاسْتَفْتَحَ مِنْ الْبَقَرَةِ لَا يَمُرُّ بِآيَةِ رَحْمَةٍ إِلَّا وَقَفَ وَسَأَلَ وَلَا يَمُرُّ بِآيَةِ عَذَابٍ إِلَّا وَقَفَ يَتَعَوَّذُ ثُمَّ رَكَعَ فَمَكَثَ رَاكِعًا بِقَدْرِ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ سَجَدَ بِقَدْرِ رُكُوعِهِ يَقُولُ فِي سُجُودِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ قَرَأَ آلَ عِمْرَانَ ثُمَّ سُورَةً ثُمَّ سُورَةً فَعَلَ مِثْلَ ذَلِكَ","trj":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Al Hasan bin Sawwar] dia berkata; telah menceritakan kepada kami [Laits bin Sa'ad] dari [Mu'awiyah bin Shalih] dari ['Amr bin Qais Al Kindi] bahwasanya dia mendengan ['Ashim bin Humaid] berkata; aku mendengar ['Auf bin Malik] berkata; \"Aku pernah bangun bersama Nabi Shallallahu'alaihi wasallam, lalu beliau mulai bersiwak dan berwudhu. Kemudian beliau berdiri dan shalat. Beliau mengawali shalatnya dengan membaca surat Al Baqarah. Beliau tidak melewati ayat tentang rahmat kecuali beliau berhenti dan memohon (rahmat). Beliau juga tidak melewati ayat tentang adzab kecuali beliau berhenti dan berlindung darinya. Kemudian beliau ruku' hingga ia tenang dalam keadaan ruku' seukuran berdirinya, sambil membaca: 'Subhana dzil jabaruuti wal malakuuti wal kibriyaai wal 'adzamati (Maha Suci Dzat yang mempunyai hak memaksa dan kekuasaan, serta yang memiliki kesombongan dan keagungan) ' saat ruku'. Lantas beliau Shallallahu'alaihiwasallam sujud seukuran ruku'nya tadi dengan membaca: 'Subhana dzil jabaruuti wal malakuuti wal kibriyaai wal 'adzamati'. Kemudian beliau membaca surat Ali 'Imran, kemudian surat lainnya, dan beliau juga melakukan hal yang sama - di rakaat berikutnya -.\" "},{"p":"Nasa'i","n":1378,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","trj":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "},{"p":"Nasa'i","n":1570,"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي مَخْرَمَةُ بْنُ سُلَيْمَانَ عَنْ كُرَيْبٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ عِنْدَ مَيْمُونَةَ أُمِّ الْمُؤْمِنِينَ وَهِيَ خَالَتُهُ فَاضْطَجَعَ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ قَلِيلًا أَوْ بَعْدَهُ قَلِيلًا اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِيمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ يُصَلِّي قَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَهُ الْمُؤَذِّنُ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ","trj":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnul Qasim] dari [Malik] dia berkata; telah menceritakan kepadaku [Makhramah bin Sulaiman] dari [Kuraib] bahwasanya ['Abdullah bin 'Abbas] mengabarkan kepadanya, bahwa dia pernah bermalam di rumah bibinya Maimunah (istri Nabi shallallahu 'alaihi wasallam), lalu dia berbaring di atas bantal, sementara Rasulullah shallallahu 'alaihi wasallam dan keluarganya berbaring di (tikar) yang panjang. Nabi shallallahu 'alaihi wasallam tidur hingga tengah malam -sebelum atau sesudahnya sedikit-, Rasulullah shallallahu 'alaihi wasallam bangun, terus duduk dan mengusap mukanya dengan tangan, lalu membaca sepuluh ayat terakhir surah Ali Imran. Setelah itu beliau pergi ke bejana air yang tergantung, lalu berwudlu dengan air itu. Beliau memperbagus wudlunya, kemudian mengerjakan shalat. Abdullah bin Abbas berkata; 'Aku berdiri, lalu aku mengerjakan seperti apa yang dikerjakan beliau. Kemudian aku pergi ke samping beliau, beliau memegang kepalaku dengan tangan kanannya seraya menyentil telingaku. Setelah itu beliau shalat dua raka'at, lalu dua raka'at, dua raka'at, dua raka'at, lalu dua raka'at, dan dua raka'at lagi. Kemudian mengerjakan shalat witir. Setelah itu beliau berbaring, sampai datang muadzin, lalu berdiri mengerjakan shalat dua raka'at yang ringan."},{"p":"Nasa'i","n":3445,"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَالَ أَبُو طَلْحَةَ إِنَّ رَبَّنَا لَيَسْأَلُنَا عَنْ أَمْوَالِنَا فَأُشْهِدُكَ يَا رَسُولَ اللَّهِ أَنِّي قَدْ جَعَلْتُ أَرْضِي لِلَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلْهَا فِي قَرَابَتِكَ فِي حَسَّانَ بْنِ ثَابِتٍ وَأُبَيِّ بْنِ كَعْبٍ","trj":"Telah mengabarkan kepada kami [Abu Bakr bin Nafi'] berkata; telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami [Hammad] berkata; telah menceritakan kepada kami [Tsabit] dari [Anas] berkata, \"Tatkala turun ayat ini: '(Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebagian harta yang kamu cintai) ' (Qs. Ali Imran: 92), maka Abu Thalhah berkata, \"Sungguh, tuhan kita akan bertanya kepada kita mengenai harta-harta kita. Maka aku meminta persaksianmu wahai Rasulullah, bahwa aku telah menjadikan lahanku untuk Allah.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jadikanlah lahan tersebut untuk para kerabatmu, yaitu Hasan bin Tsabit dan Ubay bin Ka'b.\""},{"p":"Nasa'i","n":5069,"ar":"أَخْبَرَنَا عَلِيُّ بْنُ سَعِيدِ بْنِ مَسْرُوقٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ نَافِعِ بْنِ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَكَانَتْ جَارِيَتَانِ تَخْرُزَانِ بِالطَّائِفِ فَخَرَجَتْ إِحْدَاهُمَا وَيَدُهَا تَدْمَى فَزَعَمَتْ أَنَّ صَاحِبَتَهَا أَصَابَتْهَا وَأَنْكَرَتْ الْأُخْرَى فَكَتَبْتُ إِلَى ابْنِ عَبَّاسٍ فِي ذَلِكَ فَكَتَبَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى أَنَّ الْيَمِينَ عَلَى الْمُدَّعَى عَلَيْهِ وَلَوْ أَنَّ النَّاسَ أُعْطُوا بِدَعْوَاهُمْ لَادَّعَى نَاسٌ أَمْوَالَ نَاسٍ وَدِمَاءَهُمْ فَادْعُهَا وَاتْلُ عَلَيْهَا هَذِهِ الْآيَةَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا أُولَئِكَ لَا خَلَاقَ لَهُمْ فِي الْآخِرَةِ }حَتَّى خَتَمَ الْآيَةَ فَدَعَوْتُهَا فَتَلَوْتُ عَلَيْهَا فَاعْتَرَفَتْ بِذَلِكَ فَسَرَّهُ","trj":"Telah mengabarkan kepada kami [Ali bin Sa'id bin Masruq] ia berkata; telah menceritakan kepada kami [Yahya bin Abu Zaidah] dari [Nafi' bin Umar] dari [Ibnu Abu Mulaikah] ia berkata, \"Dua orang wanita masuk ke dalam gua di wilayah Tha'if. Lalu salah seorang dari keduanya keluar dengan tangan terluka. Maka ia menyangka bahwa temannya yang telah melukainya, namun temannya mengingkari. Aku lalu menulis surat kepada Ibnu Abbas berkenaan dengan masalah tersebut, [Ibnu Abbas] membalas; Rasulullah shallallahu 'alaihi wasallam pernah memberi putusan, bahwa sumpah itu bagi orang yang dituduh (terdakwa). Sebab jika manusia dibiarkan memberikan dakwaan, maka mereka akan mendakwa harta dan nyawa orang banyak. Oleh karena itu panggillah wanita itu dan bacakanlah ayat ini kepadanya: ' Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit, mereka itu tidak mendapat bahagian (pahala) di akhirat' QS Ali Imran; 77 hingga akhir ayat. Kemudian aku memanggil wanita tersebut dan aku bacakan ayat itu kepadanya, akhirnya ia mengakuinya.\""},{"p":"Tirmidzi","n":514,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ فَأَطَالَ الْقِرَاءَةَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِرَاءَةَ هِيَ دُونَ الْأُولَى ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَسَجَدَ ثُمَّ فَعَلَ مِثْلَ ذَلِكَ فِي الرَّكْعَةِ الثَّانِيَةِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَبِهَذَا الْحَدِيثِ يَقُولُ الشَّافِعِيُّ وَأَحْمَدُ وَإِسْحَقُ يَرَوْنَ صَلَاةَ الْكُسُوفِ أَرْبَعَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ قَالَ الشَّافِعِيُّ يَقْرَأُ فِي الرَّكْعَةِ الْأُولَى بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ سُورَةِ الْبَقَرَةِ سِرًّا إِنْ كَانَ بِالنَّهَارِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ بِتَكْبِيرٍ وَثَبَتَ قَائِمًا كَمَا هُوَ وَقَرَأَ أَيْضًا بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ آلِ عِمْرَانَ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ سَجَدَ سَجْدَتَيْنِ تَامَّتَيْنِ وَيُقِيمُ فِي كُلِّ سَجْدَةٍ نَحْوًا مِمَّا أَقَامَ فِي رُكُوعِهِ ثُمَّ قَامَ فَقَرَأَ بِأُمِّ الْقُرْآنِ وَنَحْوًا مِنْ سُورَةِ النِّسَاءِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ رَأْسَهُ بِتَكْبِيرٍ وَثَبَتَ قَائِمًا ثُمَّ قَرَأَ نَحْوًا مِنْ سُورَةِ الْمَائِدَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا نَحْوًا مِنْ قِرَاءَتِهِ ثُمَّ رَفَعَ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ تَشَهَّدَ وَسَلَّمَ","trj":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu As Syawarib] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] bahwa dia berkata, telah terjadi gerhana pada masa Rasulullah shallallahu 'alaihi wasallam, kemudian Rasulullah shallallahu 'alaihi wasallam shalat bersama manusia dengan memanjangkan bacaan shalat, beliau kemudian ruku' dan memanjangkan ruku'nya, lalu beliau mengangkat kepala dan memanjangkan bacaan shalat, namun tidak seperti (lebih singkat) dari yang pertama. Kemudian beliau ruku' dan memanjangkan ruku'nya namun tidak seperti yang pertama. Kemudian beliau mengangkat kepala lalu sujud, kemudian beliau melakukan seperti itu diraka'at kedua. Abu Isa berkata, ini adalah hadits hasan shahih, dengan hadits ini pula Syafi'i, Ahamad dan Ishaq berpendapat bahwa shalat gerhana itu empat kali ruku' dan empat kali sujud. Syafi'i berkata, pada raka'at pertama membaca surat Al Fatehah dan surat yang sepadan dengan surat Al Baqarah. Beliau membaca dengan suara pelan jika di siang hari (gerhana matahari), kemudian ruku' yang panjang seperti membaca bacaan, kemudian mengangkat kepala dengan mengucapkan takbir dan berdiri sebagaimana mestinya, kemudian membaca surat Al Fatihah lagi dan membaca surat yang sepadan dengan surat Ali Imran, lalu memanjangkan ruku'nya seperti ketika membaca bacaan. Kemudian mengangat kepala, lantas membaca sami'allahu liman hamidah, kemudian sujud dua kali dengan sempurna. Setiap sujud beliau berhenti sebagaimana berhenti ketika ruku', kemudian berdiri sambil membaca Al Fatehah dan surat yang sepadan dengan surat An Nisaa', kemudian memanjangan ruku' seperti membaca bacaan. Kemudian mengangkat kepala dengan mengucapkan takbir, lantas berdiri dengan membaca bacaan yang sepadan dengan surat Al Maidah, kemudian memanjangkan ruku'nya seperti ketika membaca bacaan. Kemudian mengangkat kepala dan membaca sami'allahu liman hamidah, kemudian sujud dua kali lalu membaca tahiyyat dan salam."},{"p":"Tirmidzi","n":2822,"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةَ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }أَوْ{ مَنْ ذَا الَّذِي يُقْرِضُ اللَّهَ قَرْضًا حَسَنًا }قَالَ أَبُو طَلْحَةَ وَكَانَ لَهُ حَائِطٌ فَقَالَ يَا رَسُولَ اللَّهِ حَائِطِي لِلَّهِ وَلَوْ اسْتَطَعْتُ أَنْ أُسِرَّهُ لَمْ أُعْلِنْهُ فَقَالَ اجْعَلْهُ فِي قَرَابَتِكَ أَوْ أَقْرَبِيكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكِ","trj":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abdullah bin Bakr As Sahmani] telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata; \"Ketika turun ayat Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebahagian harta yang kamu cintai.\" QS Ali 'Imran: 92 atau Siapakah yang mau memberi pinjaman kepada Allah, pinjaman yang baik (menafkahkan hartanya di jalan Allah). QS Al-Baqarah: 245, kemudian Abu Thalhah, yang memiliki kebun berkata; \"Wahai Rasulullah, saya (infakkan) kebun saya ini di jalan Allah. Dan sekiranya saya mampu untuk menyembunyikannya tentu saya tidak menyatakannya. lalu beliau mengatakan \"Berikanlah kepada kerabat atau orang yang terdekat denganmu!\" Abu Isa mengatakan bahwa hadits ini hasan shahih. Dan [Malik bin Anas] telah meriwayatkan dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] "},{"p":"Tirmidzi","n":2825,"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي قَوْلِهِ تَعَالَى{ كُنْتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ }قَالَ إِنَّكُمْ تَتِمُّونَ سَبْعِينَ أُمَّةً أَنْتُمْ خَيْرُهَا وَأَكْرَمُهَا عَلَى اللَّهِهَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ بَهْزِ بْنِ حَكِيمٍ نَحْوَ هَذَا وَلَمْ يَذْكُرُوا فِيهِ{ كُنْتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ }","trj":"Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda tentang firman Allah Ta'ala; Kamu adalah umat yang terbaik yang dilahirkan untuk manusia. QS Ali Imran: 110, beliau bersabda: \"Sesungguhnya kalian terbagi menjadi tujuh puluh umat, dan kalianlah yang terbaik (diantara mereka) serta paling mulia di sisi Allah.\" Hadits ini hasan. Beberapa perawi meriwayatkan hadits ini dari Bahz bin Hakim seperti ini, namun mereka tidak menyebut: Kamu adalah umat yang terbaik yang dilahirkan untuk manusia QS Ali Imran: 110."},{"p":"Tirmidzi","n":2826,"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُسِرَتْ رَبَاعِيَتُهُ يَوْمَ أُحُدٍ وَشُجَّ وَجْهُهُ شَجَّةً فِي جَبْهَتِهِ حَتَّى سَالَ الدَّمُ عَلَى وَجْهِهِ فَقَالَ كَيْفَ يُفْلِحُ قَوْمٌ فَعَلُوا هَذَا بِنَبِيِّهِمْ وَهُوَ يَدْعُوهُمْ إِلَى اللَّهِ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ }إِلَى آخِرِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid] dari [Anas] bahwa pada perang Uhud, rahang Rasulullah shallallahu 'alaihi wasallam retak dan pelipisnya terluka hingga wajahnya mengalirkan darah. Beliau bersabda: \"Bagaimana mungkin suatu kaum akan beruntung sedang mereka memperlakukan nabinya seperti ini, padahal ia menyeru mereka ke jalan Allah.\" lalu turunlah ayat: Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka. QS Ali Imran: 128, Abu Isa mengatakan bahwa hadits ini hasan shahih."},{"p":"Tirmidzi","n":2827,"ar":"حَدَّثَنَا أَبُو السَّائِبِ سَلْمُ بْنُ جُنَادَةَ بْنِ سَلْمٍ الْكُوفِيُّ حَدَّثَنَا أَحْمَدُ بْنُ بَشِيرٍ عَنْ عُمَرَ بْنِ حَمْزَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ اللَّهُمَّ الْعَنْ أَبَا سُفْيَانَ اللَّهُمَّ الْعَنْ الْحَارِثَ بْنَ هِشَامٍ اللَّهُمَّ الْعَنْ صَفْوَانَ بْنَ أُمَيَّةَ قَالَ فَنَزَلَتْ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ }فَتَابَ اللَّهُ عَلَيْهِمْ فَأَسْلَمُوا فَحَسُنَ إِسْلَامُهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ يُسْتَغْرَبُ مِنْ حَدِيثِ عُمَرَ بْنِ حَمْزَةَ عَنْ سَالِمٍ عَنْ أَبِيهِ وَقَدْ رَوَاهُ الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِ لَمْ يَعْرِفْهُ مُحَمَّدُ بْنُ إِسْمَعِيلَ مِنْ حَدِيثِ عُمَرَ بْنِ حَمْزَةَ وَعَرَفَهُ مِنْ حَدِيثِ الزُّهْرِيِّ","trj":"Telah menceritakan kepada kami [Abu As Sa`ib Salm bin Junadah bin Salm Al Kufi] telah menceritakan kepada kami [Ahmad bin Basyir] dari [Umar bin Hamzah] dari [Salim bin Abdullah bin Umar] dari [Ayahnya] ia mengatakan; Rasulullah shallallahu 'alaihi wasallam pernah berdoa pada perang Uhud: \"Ya Allah, laknatlah Abu Sufyan, laknatlah Al Harits bin Hisyam, ya Allah, laknatlah Shafwan bin 'Umayyah.\" lalu turunlah ayat Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka. QS Ali Imran: 128, akan tetapi Allah mengampuni mereka, akhirnya mereka pun masuk Islam, dengan keIslaman yang baik.\" Abu Isa mengatakan bahwa hadits ini hasan gharib, dinilai asing dari hadits Umar bin Hamzah dari Salim dari Ayahnya, [Az Zuhri] telah meriwayatkan dari [Salim] dari [Ayahnya], namun Muhammad bin Isma'il tidak mengetahui dari Umar bin Hamzah, dan dia hanya mengetahui dari hadits Az Zuhri."},{"p":"Tirmidzi","n":2828,"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ الْبَصْرِيُّ حَدَّثَنَا خَالِدُ ابْنُ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو عَلَى أَرْبَعَةِ نَفَرٍ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }فَهَدَاهُمْ اللَّهُ لِلْإِسْلَامِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ يُسْتَغْرَبُ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ نَافِعٍ عَنْ ابْنِ عُمَرَ وَرَوَاهُ يَحْيَى بْنُ أَيُّوبَ عَنْ ابْنِ عَجْلَانَ","trj":"Telah menceritakan kepada kami [Yahya bin Habib bin 'Arabi Al Bashri] telah menceritakan kepada kami [Khalid bin Al Harits] dari [Muhammad bin 'Ajlan] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam mendakwahi empat orang, kemudian Allah menurunkan ayat; Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka karena sesungguhnya mereka itu orang-orang yang zhalim. QS Ali Imran: 128, lalu Allah memberi petunjuk mereka kepada Islam.\" Abu Isa berkata; Hadits in hasan gharib shahih dan dinilai gharib melalui sanad ini dari hadits Nafi' dari Ibnu Umar. [Yahya bin Ayub] juga meriwayatkannya dari [Ibnu 'Ajlan]."},{"p":"Tirmidzi","n":2829,"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَا��َةَ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ عَنْ عَلِيِّ بْنِ رَبِيعَةَ عَنْ أَسْمَاءَ بْنِ الْحَكَمِ الْفَزَارِيِّ قَال سَمِعْتُ عَلِيًّا يَقُولُإِنِّي كُنْتُ رَجُلًا إِذَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا نَفَعَنِي اللَّهُ مِنْهُ بِمَا شَاءَ أَنْ يَنْفَعَنِي وَإِذَا حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِهِ اسْتَحْلَفْتُهُ فَإِذَا حَلَفَ لِي صَدَّقْتُهُ وَإِنَّهُ حَدَّثَنِي أَبُو بَكْرٍ وَصَدَقَ أَبُو بَكْرٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ رَجُلٍ يُذْنِبُ ذَنْبًا ثُمَّ يَقُومُ فَيَتَطَهَّرُ ثُمَّ يُصَلِّي ثُمَّ يَسْتَغْفِرُ اللَّهَ إِلَّا غَفَرَ لَهُ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ{ وَالَّذِينَ إِذَا فَعَلُوا فَاحِشَةً أَوْ ظَلَمُوا أَنْفُسَهُمْ ذَكَرُوا اللَّهَ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ قَدْ رَوَاهُ شُعْبَةُ وَغَيْرُ وَاحِدٍ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَرَفَعُوهُ وَرَوَاهُ مِسْعَرٌ وَسُفْيَانُ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَلَمْ يَرْفَعَاهُ وَقَدْ رَوَاهُ بَعْضُهُمْ عَنْ مِسْعَرٍ فَأَوْقَفَهُ وَرَفَعَهُ بَعْضُهُمْ وَرَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ فَأَوْقَفَهُ وَلَا نَعْرِفُ لِأَسْمَاءَ بْنِ الْحَكَمِ حَدِيثًا إِلَّا هَذَا","trj":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Utsman bin Al Mughirah] dari [Ali bin Rabi'ah] dari [Asma` bin Al Hakam Al Fazari] ia berkata; Aku mendengar [Ali] berkata; Aku adalah seseorang yang bila mendengar suatu hadits dari Rasulullah shallallahu 'alaihi wasallam, Allah memanfaatkanku darinya seperti yang Ia kehendaki dan bila seseorang sahabatku menceritakan kepadaku, aku memintanya bersumpah, bila ia bersumpah, aku membenarkannya. [Abu Bakar] pernah menceritakan kepadaku, sementara Abu Bakar adalah orang yang jujur, ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang melakukan suatu dosa, kemudian berdiri, wudhu lalu shalat, setelah itu ia meminta ampun kepada Allah melainkan pasti diampuni.\" Setelah itu Abu Bakar membaca ayat ini: Dan (juga) orang-orang yang apabila mengerjakan perbuatan keji atau menganiaya diri sendiri, mereka ingat akan Allah, lalu memohon ampun terhadap dosa-dosa mereka. QS Ali Imran: 135, hingga akhir ayat. Abu Isa berkata; Hadits ini diriwayatkan oleh [Syu'bah] dan beberapa orang dari [Utsman bin Al Mughirah] dan mereka memarfu'kannya. Diriwayatkan juga oleh [Mis'ar] dan [Sufyan] dari [Utsman bin Al Mughirah], tapi keduanya tidak memarfu'kannya. Sebagian lainnya meriwayatkannya dari Mis'ar dan memauqufkannya, sementara sebagian lainnya memarfu'kannya. Sufyan Ats Tsauri meriwayatkannya dari Utsman bin Al Mughirah lalu memauqufkannya. Kami tidak mengetahui hadits Amsa` bin Al Hakam selain hadits ini."},{"p":"Tirmidzi","n":2836,"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ رَجُلٍ مِنْ وَلَدِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْيَا رَسُولَ اللَّهِ لَا أَسْمَعُ اللَّهَ ذَكَرَ النِّسَاءَ فِي الْهِجْرَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ أَنِّي لَا أُضِيعُ عَمَلَ عَامِلٍ مِنْكُمْ مِنْ ذَكَرٍ أَوْ أُنْثَى بَعْضُكُمْ مِنْ بَعْضٍ }","trj":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [seseorang] anak Ummu Salamah, dari [Ummu Salamah] ia berkata; \"Wahai Rasulullah, aku tidak mendengar Allah menyebut kaum wanita dalam hijrah.\" Lalu Allah Ta'ala menurunkan Maka Rabb mereka memperkenankan permohonannya (dengan berfirman): 'Sesungguhnya Aku tidak menyia-nyiakan amal orang-orang yang beramal di antara kamu, baik laki-laki atau perempuan, (karena) sebagian kamu adalah turunan dari sebagian yang lain. QS Ali Imran: 195."},{"p":"Tirmidzi","n":2849,"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا مُنْصُورُ بْنُ وَرْدَانَ عَنْ عَلِيِّ بْنِ عَبْدِ الْأَعْلَى عَنْ أَبِيهِ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ عَلِيٍّ قَالَلَمَّا نَزَلَتْ{ وَلِلَّهِ عَلَى النَّاسِ حِجُّ الْبَيْتِ مَنْ اسْتَطَاعَ إِلَيْهِ سَبِيلًا }قَالُوا يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ فَسَكَتَ قَالُوا يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ قَالَ لَا وَلَوْ قُلْتُ نَعَمْ لَوَجَبَتْ فَأَنْزَلَ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ عَلِيٍّ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ","trj":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] telah menceritakan kepada kami [Manshur bin Wardan] dari [Ali bin Abdul A'la] dari [Ayahnya] dari [Abu al Bakhtari] dari [Ali] ia berkata; Tatkala turun ayat Mengerjakan haji adalah kewajiban manusia terhadap Allah, yaitu (bagi) orang yang sanggup mengadakan perjalanan ke Baitullah QS Ali Imran: 97, para sahabat bertanya; \"Wahai Rasulullah, apakah (dilakukan) setiap tahun?\" Beliau terdiam, mereka bertanya lagi; \"Wahai Rasulullah, apakah (dilakukan) setiap tahun?\" beliau menjawab: \"Tidak, seandainya tadi kujawab ya, pasti akan menjadi wajib (hukumnya).\" Lalu Allah menurunkan Hai orang-orang yang beriman, janganlah kamu menanyakan (kepada Nabimu) hal-hal yang jika diterangkan kepadamu akan menyusahkan Kamu. QS Al Mai`idah: 101. Abu Isa mengatakan bahwa hadits ini hasan gharib."},{"p":"Tirmidzi","n":3043,"ar":"بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَعَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ أَعْدَدْتُ لِعِبَادِيَ الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ وَاقْرَءُوا إِنْ شِئْتُمْ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }وَفِي الْجَنَّةِ شَجَرَةٌ يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ وَظِلٍّ مَمْدُودٍ }وَمَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ فَمَنْ زُحْزِحَ عَنْ النَّارِ وَأُدْخِلَ الْجَنَّةَ فَقَدْ فَازَ وَمَا الْحَيَاةُ الدُّنْيَا إِلَّا مَتَاعُ الْغُرُورِ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Bismillahirrahmanirrahim. Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami ['Abdah bin Sulaiman] serta [Abdur Rahim bin Sulaiman] dari [Muhammad bin 'Amr], ia berkata; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah berfirman: \"Aku telah mempersiapkan bagi para hambaku yang shalih, apa yang belum pernah dilihat mata, belum pernah didengar telinga, dan tidak terlintas dalam hati manusia.\" Apabila kalian kehendaki maka bacalah: \"Tak seorangpun mengetahui berbagai nikmat yang dirahasiakan bagi mereka, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan.\" (QS. Assajdah 17), Di Surga terdapat pohon yang mana seorang pengendara berjalan di bawah naungannya selama seratus tahun tidak mampu menyeberanginya. Apabila kalian menghendaki maka bacalah: \"Dan naungan yang terbentang luas\" (QS. Alwaqi'ah 30), Dan tempat cemeti di Surga lebih baik daripada dunia dan seisinya. Apabila kalian menghendaki maka bacalah: \"Barangsiapa dijauhkan dari neraka dan dimasukkan ke dalam syurga, maka sungguh ia telah beruntung. Kehidupan dunia itu tidak lain hanyalah kesenangan yang memperdayakan.\" (QS. Ali'Imran 185), Abu Isa berkata: hadits ini adalah hadits hasan shahih."},{"p":"Tirmidzi","n":3224,"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ الْقَدَّاحِ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْمُ اللَّهِ الْأَعْظَمُ فِي هَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ لَا إِلَهَ إِلَّا هُوَ الرَّحْمَنُ الرَّحِيمُ }وَفَاتِحَةِ آلِ عِمْرَانَ{ الم اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","trj":"Telah menceritakan kepada kami [Ali bin Khasyram] telah menceritakan kepada kami [Isa bin Yunus] dari ['Ubaidullah bin Abu Ziyad Al Qaddah] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Nama Allah Allah yang paling agung ada dalam kedua ayat ini, yaitu: \"Dan Tuhanmu adalah Tuhan Yang Maha Esa; tidak ada Tuhan melainkan Dia Yang Maha Pemurah lagi Maha Penyayang\", (QS. Albaqarah 163) dan permulaan Surat Ali Imran; \"Alif laam miim. Allah, tidak ada Tuhan (yang berhak disembah) melainkan Dia. Yang hidup kekal lagi terus menerus mengurus makhluk-Nya.\" (QS.Ali Imran 1-2), Abu Isa berkata; hadits ini adalah hadits hasan shahih."}]};
